INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('snack_bag', '과자 봉지', 'vinyl', '은박 코팅된 과자/라면 봉지', '["부스러기 털어내기", "비닐류로 배출"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=97', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 과일, 과자 등을 포장하기 위해 사용하는 대부분의 합성수지 비닐은 생산자책임재활용제도 (EPR)대상 품목에 해당되어 재활용이 가능합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '·이물질을 제거한 후 배출', NULL, 0, '["재활용폐기물", "합성수지 비닐류"]');
