INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('milk_carton', '우유팩', 'paper_pack', '일반 종이와 별도 수거 (종이팩 전용 함)', '["내용물 비우기", "물로 헹구기", "펼쳐서 말리기", "종이팩 전용함 또는 종이류 별도 묶음"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=16', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 종이팩은 일반 종이와 달리 고품질의 펄프로 제작되어 미용 티슈, 화장지 등 고급 제품으로 재활용이 가능합니다. · 종이팩은 우유, 음료, 두유 등 액체류를 포장하는데 사용되는 용기로 일반팩과 멸균팩이 있습니다. · 일반팩은 주로 우유팩으로 사용되며, 외부와 내부에 PE 코팅이 되어있습니다. · 멸균팩은 산소와 자외선을 막아 장기간 보관할 수 있도록 만들어진 제품으로 내부에 알루미늄 호일이...', '· 내용물을 비우고 물로 헹군 후 배출 · 종이팩은 일반 종이와 구분하여 배출', NULL, 1, '["재활용폐기물", "종이팩", "일반팩"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('juice_carton', '주스팩 (멸균팩)', 'paper', '알루미늄 코팅된 멸균팩 - 일반 우유팩과 별도', '["내용물 비우기", "헹구기", "펼쳐서 말리기", "멸균팩 별도 분리 권장"]', 'medium', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 1, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('paper_cup', '종이컵 (일반)', 'paper', '음료 자국 등 가볍게 씻은 후 배출', '["내용물 비우기", "헹구기", "종이팩류로 배출"]', 'medium', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=36', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 종이는 수거하여 종류별로 분류한 후 각각의 제지공장으로 운반되어 해리, 정선, 농축, 고해 과정을 거친 후 펄프와 혼합하여 종이로 재활용하고 있습니다. · 쇼핑백의 종이재질이 아닌 손잡이는 제거해서 종량제봉투로 배출합니다. · 비닐 코팅된 쇼핑백은 종량제봉투로 배출합니다.', '·양면이 코팅되어 찢어지지 않는 경우 일반종량제폐기물로 배출', '2026-05-18', 1, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('paper_cup_coated', '코팅 종이컵/종이용기', 'general', 'PE/PLA 코팅된 일회용 종이용기 - 재활용 공정 달라 종량제봉투 권장', '["내용물 비우기", "종량제봉투에 배출"]', 'medium', NULL, NULL, NULL, NULL, NULL, NULL, 1, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('receipt', '영수증', 'general', '감열지는 BPA 코팅으로 재활용 불가', '["종량제봉투에 배출"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=143', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 수은함유폐기물이란 수은과 그 화합물을 함유한 폐기물을 말하며, 혈압계, 온도계, 체온계 등이 있습니다. · 혈압계, 온도계 등에 포함된 수은은 인체에 혼입될 시 발열, 오한, 구토 등의 급성 증상과 구강염증, 기억력 소실, 지적능력 저하 등 만성 증상이 발생할 수 있으며, 환경에 유출될 시 생물 농축, 잔류 등 악영향을 일으킬 수 있습니다. · 수은이 함유된 폐기물을 배출할때에는 분해·해...', '· 수은이 외부로 유출될 시 환경 및 인체에 유해하므로 주의하여 배출', '2026-05-18', 0, '["생활계 유해폐기물", "수은함유 폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('book', '책', 'paper', '표지(비닐 코팅) 제거 후 묶음 배출', '["하드커버/비닐 코팅 표지 제거", "끈으로 묶어서 배출"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=20', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 종이의 종류로는 골판지, 백판지, 백상지, 종이팩이 있습니다. · 종이를 배출할 때에는 골판지와 골판지 외 종이류(백판지, 백상지 등)으로 구분하여 배출합니다. · 공책,수첩,노트는 색상과 관계없이 신문지, 백상지 등 기타 종이류와 함께 배출하며, 이때, 비닐 코팅된 종이, 공책의 스프링, 비닐포장지 등은 제거 후 배출합니다.', '· 코팅종이, 금박지, 은박지, 검은색 먹지 등은 제거하여 배출', '2026-05-18', 0, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('note', '노트', 'paper', '스프링은 분리하여 캔/금속류로 배출', '["스프링/철핀 분리", "종이류로 배출"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('can', '캔 (일반)', 'can', '철/알루미늄 캔', '["내용물 비우기", "헹구기", "압착하여 배출"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=84', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 참치캔은 뚜껑은 알루미늄, 몸체는 스틸(철)인 금속재질로 금속캔으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 내용물을 비우고 물로 헹군 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "금속캔"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('beverage_can', '음료수 캔', 'can', '알루미늄 캔', '["내용물 비우기", "물로 헹구기", "압착", "캔/금속류로 배출"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=616', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 맥주캔은 몸체, 뚜껑이 금속(알루미늄) 재질로 금속캔으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 내용물을 비우고 물로 헹군 후 배출', NULL, 0, '["재활용폐기물", "금속류", "금속캔"]');
