INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('glass_bottle', '유리병', 'glass', '주류병/음료병 등 (빈용기 보증금 환불 가능 품목은 별도)', '["뚜껑 제거", "내용물 비우기", "헹구기", "병류 전용함 배출"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=510', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 유리병은 3색(무색, 녹색, 갈색)으로 분류한 후 파쇄∙분쇄, 용융과정을 거쳐 재활용하고 있습니다. · 이 과정에서 와인병과 같은 이색(파란색, 검정색, 자주색 등) 유리병은 혼색 유리병으로 분류 및 분쇄 후 건설자재 등으로 재활용되고 있으므로 유리병으로 배출합니다.', '·깨진 유리병은 불연성종량제봉투로 배출하거나 신문지 등에 싸서 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "유리병"]');
