INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('aluminum_foil', '알루미늄 호일', 'general', '오염된 알루미늄 호일은 일반쓰레기', '["종량제봉투에 배출"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=409', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 재활용 선별장에서는 알루미늄 캔, 용기, 제품을 선별하나 알루미늄 호일은 선별이 용이하지 않기 때문에 종량제봉투로 배출합니다.', '· 금속캔, 고철류로 배출 불가', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('battery', '폐건전지', 'battery', '건전지/리튬이온/충전지 - 생활계 유해폐기물', '["물기 제거", "분해 금지", "동주민센터/아파트 전용수거함 배출"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=124', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· AA 건전지는 생산자책임재활용제도(EPR) 대상에 해당되는 제품으로 재활용이 가능합니다. · EPR 대상에 해당되는 전지류는 망간/알칼리 건전지(가정에서 주로 사용하는 전지로 AA, AAA 건전지 등이 포함), 산화은 건전지(손목시계 등), 리튬1차 전지(자동차키 등) 등이 있습니다. · 전지에 내부에는 전해질, 아연 등이 포함되어 있어 외부로 유출될 시 환경 오염에 우려가될 뿐만 아니라...', '· 반드시 재활용품과 분리하여 배출', '2026-05-18', 0, '["재활용폐기물", "전지류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('lithium_battery', '리튬이온 배터리 (보조배터리 등)', 'battery', '부풀어 오른 경우 화재/폭발 위험', '["부풀음 시 비닐랩으로 감싸기", "동주민센터/구청 담당자에게 직접 전달"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('lamp', '폐형광등', 'lamp', '수은 함유로 별도 수거 필수', '["포장 제거", "깨지지 않게 운반", "전용수거함 배출"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=136', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 직관형, 환형, 안정기내장형, 콤팩트형 형광등은 형광등 수거함으로 배출합니다. · 조명이 깨진 경우에는 배출자, 수거원 등이 다칠 우려가 있으므로 신문지, 테이프 등을 활용하여 충분히 감싼 후 불연성 종량제봉투(마대)로 배출합니다.', '· 깨지지 않도록 주의', '2026-05-18', 0, '["재활용폐기물", "조명제품"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('clothes', '헌 옷/의류', 'clothes', '재사용 가능한 의류, 가방, 신발, 담요 등', '["세탁/건조", "의류수거함 배출"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=347', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 교복, 군복, 경찰복 등 타인이 사용하기 부적합한 의류는 가위로 절단하여 종량제봉투로 배출합니다.', '의류수거함 배출 품목은 지자체에 따라 상이할 수 있음', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('electronics', '소형가전', 'electronics', '1m 미만 소형가전은 무상 방문수거 신청 가능 (E-순환거버넌스 15990903)', '["E-순환거버넌스(15990903) 또는 주민센터 신청", "무상 방문수거"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=231', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 공기청정기는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도 대상품목으로는 냉장고, 세탁기,...', '· 폐가전제품 무상방문서비스 문의 후 배출', NULL, 1, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('furniture', '대형폐기물 (가구)', 'furniture', '주민센터/구청에 신고 후 스티커 부착하여 배출', '["구청/주민센터 또는 온라인 신고", "수수료 결제 및 스티커 발급", "지정 장소에 배출"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=183', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 매트리스와 같은 침구류는 재활용이 어려워 대형폐기물로 수거한 후 소각됩니다.', '· 매트리스는 부피, 크기가 커 배출하실 때에는 보행자에게 불편을 주지 않도록 주의하여 배출', NULL, 1, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('medicine', '폐의약품', 'general', '약국/보건소에 비치된 폐의약품 수거함에 배출 (절대 변기/하수구 금지)', '["포장재(종이박스, 설명서) 제거", "약국/보건소 수거함에 배출"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=146', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 포장재 겉면에 의약품으로 표기된 연고는 가까운 약국이나 보건소, 주민센터 등에 비치된 폐의약품전용수거함으로 배출합니다. · 의약품의 경우(물약 제외) 일부 지자체에 한하여 우정산업본부와 사전협의를 통해 우체통으로 배출하는 경우도 있습니다. · 의약외품인 연고 경우 종량제봉투로 배출하여 주시면 됩니다.', '· 제품 포장재 의약품/의약외품 확인후 배출', NULL, 0, '["생활계 유해폐기물", "폐의약품"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('종이팩', '종이팩', 'paper', '· 종이팩은 일반 종이와 달리 고품질의 펄프로 제작되어 미용 티슈, 화장지 등 고급 제품으로 재활용이 가능합니다. · 종이팩은 우유, 음료, 두유 등 액체류를 포장하는데 사용되는 용기로 일반팩과 멸균팩이 있습니다. · 일반팩은 주로 우유팩으로 사용되며, 외부와 내부에 PE 코팅이 되어있습니다. · 멸균팩은 산소와 자외선을 막아 장기간 보관할 수 있도록 만들', '["종이팩을 배출할 때에는 일반팩과 멸균팩으로 구분하지 않고 종이팩수거함으로 배출합니다.", "인근에 종이팩수거함이 없는 경우에는 일반 종이류와 구분하여 종이류수거함으로 배출합니다."]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 내용물을 비우고 물로 헹군 후 배출 · 종이팩은 일반 종이와 구분하여 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('메모지', '메모지', 'paper', '· 크기가 작은 종이는 이물질이 묻어 있지 않은 경우에는 종이류로 배출합니다. · 메모지와 같이 크기가 작은 종이는 묶음 그대로 배출하거나 낱개로 배출할 때에는 흩날리지 않도록 종이봉투 등에 담거나 신문지 등에 끼워서 종이로 배출할 수 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에', '["메모지는 종이류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=21', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 크기가 작은 종이는 이물질이 묻어 있지 않은 경우에는 종이류로 배출합니다. · 메모지와 같이 크기가 작은 종이는 묶음 그대로 배출하거나 낱개로 배출할 때에는 흩날리지 않도록 종이봉투 등에 담거나 신문지 등에 끼워서 종이로 배출할 수 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분...', '', '2026-05-18', 0, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('합성수지 필름', '합성수지 필름', 'general', '· 종이의 종류로는 골판지, 백판지, 백상지, 종이팩이 있습니다. · 종이는 수거하여 종류별로 분류한 후 각각의 제지공장으로 운반되어 해리, 정선, 농축, 고해 과정을 거친 후 펄프와 혼합하여 종이로 재활용하고 있습니다. · 종이에 합성수지를 분사했거나 합성수지필름을 붙여 코팅한 전단지와 카탈로그는 재활용이 어려워 일반쓰레기로 배출해야 합니다.', '["합성수지 필름이 코팅되지 않는 종이는 종이류수거함으로 배출합니다.", "합성수지 필름이 코팅된 종이는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=22', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 종이의 종류로는 골판지, 백판지, 백상지, 종이팩이 있습니다. · 종이는 수거하여 종류별로 분류한 후 각각의 제지공장으로 운반되어 해리, 정선, 농축, 고해 과정을 거친 후 펄프와 혼합하여 종이로 재활용하고 있습니다. · 종이에 합성수지를 분사했거나 합성수지필름을 붙여 코팅한 전단지와 카탈로그는 재활용이 어려워 일반쓰레기로 배출해야 합니다.', '· 양면이 코팅된 종이는 재활용이 어려우므로 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "종이", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('염색된 정도에 따라 색종이', '염색된 정도에 따라 색종이', 'general', '· 일반 종이에 색을 들인 색종이는 종이류로 배출하면 재활용이 가능합니다. · 다만, 검은색 먹지와 같이 종이의 겉면과 내면이 모두 염색된 종이는 재활용 시 제품 품질에 영향을 미치므로 일반폐기물로 배출하여 주시는 것이 좋습니다. · 이때, 염색 여부를 판단하는 기준은 색종이를 찢었을 때 내면이 색이 입혀진 경우에는 염색된 종이이며, 내면이 하얀 종이인 경', '["염색된 정도에 따라 색종이는 종이류 수거함 또는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=23', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 일반 종이에 색을 들인 색종이는 종이류로 배출하면 재활용이 가능합니다. · 다만, 검은색 먹지와 같이 종이의 겉면과 내면이 모두 염색된 종이는 재활용 시 제품 품질에 영향을 미치므로 일반폐기물로 배출하여 주시는 것이 좋습니다. · 이때, 염색 여부를 판단하는 기준은 색종이를 찢었을 때 내면이 색이 입혀진 경우에는 염색된 종이이며, 내면이 하얀 종이인 경우에는 염색되지 않은 종이입니다. ·...', '· 겉면과 내면이 모두 염색된 종이는 재활용이 어려우므로 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "종이", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('지관통', '지관통', 'paper', '· 지관통은 포스터나 그림 등을 휴대하기 위해 만들어진 제품으로 강도가 높은 크라프트지를 활용하여 제작하고 있습니다. · 크라프트지는 일반 종이보다 해리시간이 길어 골판지와 함께 배출합니다.', '["지관통은 종이류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=25', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 지관통은 포스터나 그림 등을 휴대하기 위해 만들어진 제품으로 강도가 높은 크라프트지를 활용하여 제작하고 있습니다. · 크라프트지는 일반 종이보다 해리시간이 길어 골판지와 함께 배출합니다.', '· 지관통의 금속을 제거한 후 자르거나 압착하여 평평하게 하여 배출', '2026-05-18', 0, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('탁상 달력', '탁상 달력', 'paper', '· 탁상 달력은 종이로 배출하면 재활용이 가능합니다. · 달력의 금속 또는 플라스틱 링은 제거한 후 배출합니다.', '["탁상 달력은 종이류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=26', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 탁상 달력은 종이로 배출하면 재활용이 가능합니다. · 달력의 금속 또는 플라스틱 링은 제거한 후 배출합니다.', '· 스프링은 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('정부화일', '정부화일', 'paper', '· 정부화일은 종이(백판지)로 제작되며 비닐이 코팅되어 있지 않아 재활용이 가능합니다. · 정부화일에 문서를 보관할 수 있도록 하는 철제는 제거 후 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배', '["정부화일은 종이류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=27', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 정부화일은 종이(백판지)로 제작되며 비닐이 코팅되어 있지 않아 재활용이 가능합니다. · 정부화일에 문서를 보관할 수 있도록 하는 철제는 제거 후 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역...', '', '2026-05-18', 0, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('휴지심', '휴지심', 'paper', '· 휴지심은 화장지를 고정하기 위하여 만들어진 제품으로 강도가 높은 크라프트지를 사용하고 있으며, 종이로 재활용이 가능합니다. · 다만, 동그랗고 부피가 크기 때문에 종이로 배출할 때에는 자르거나 압착하여 평평하게 하여 골판지로 배출합니다. · 종이의 종류로는 골판지, 백판지, 백상지, 종이팩이 있습니다. · 종이는 수거하여 종류별로 분류한 후 각각의 제지', '["휴지심은 종이류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=29', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 휴지심은 화장지를 고정하기 위하여 만들어진 제품으로 강도가 높은 크라프트지를 사용하고 있으며, 종이로 재활용이 가능합니다. · 다만, 동그랗고 부피가 크기 때문에 종이로 배출할 때에는 자르거나 압착하여 평평하게 하여 골판지로 배출합니다. · 종이의 종류로는 골판지, 백판지, 백상지, 종이팩이 있습니다. · 종이는 수거하여 종류별로 분류한 후 각각의 제지공장으로 운반되어 해리, 정선, 농축...', '· 평평하게 하여 배출', '2026-05-18', 0, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('골판지 상자', '골판지 상자', 'paper', '· 종이의 종류로는 골판지, 백판지, 백상지, 종이팩이 있습니다. · 종이를 배출할 때에는 골판지와 골판지 외 종이류(백판지, 백상지 등)으로 구분하여 배출합니다. · 골판지 상자는 별도의 분리배출함(또는 마대)에 배출하거나 끈 등으로 묶어서 배출합니다. · 택배용 보냉 상자류 등 내부에 알루미늄박, 비닐 등이 부착되어 종이와 분리되지 않는 상자류는 일반쓰', '["골판지 상자는 일반 종이와 구분하여 종이류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=30', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 종이의 종류로는 골판지, 백판지, 백상지, 종이팩이 있습니다. · 종이를 배출할 때에는 골판지와 골판지 외 종이류(백판지, 백상지 등)으로 구분하여 배출합니다. · 골판지 상자는 별도의 분리배출함(또는 마대)에 배출하거나 끈 등으로 묶어서 배출합니다. · 택배용 보냉 상자류 등 내부에 알루미늄박, 비닐 등이 부착되어 종이와 분리되지 않는 상자류는 일반쓰레기로 배출합니다. · 골판지 상자...', '· 상자에 부착된 송장은 제거한 후 배출 · 상자에 부착된 테이프는 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('그림', '그림', 'paper', '· 물감, 사인펜, 색연필 등으로 색칠한 종이는 종이류로 배출하면 재활용이 가능합니다. · 종이는 수거하여 종류별로 분류한 후 각각의 제지공장으로 운반되어 해리, 정선, 농축, 고해 과정을 거친 후 펄프와 혼합하여 종이로 재활용하고 있습니다. · 물감, 사인펜 등으로 염색된 종이는 재활용 표백과정에서 제거가 됩니다. ※ 배출방법은 지역별로 차이가 있을 수', '["그림은 종이류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=31', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 물감, 사인펜, 색연필 등으로 색칠한 종이는 종이류로 배출하면 재활용이 가능합니다. · 종이는 수거하여 종류별로 분류한 후 각각의 제지공장으로 운반되어 해리, 정선, 농축, 고해 과정을 거친 후 펄프와 혼합하여 종이로 재활용하고 있습니다. · 물감, 사인펜 등으로 염색된 종이는 재활용 표백과정에서 제거가 됩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는...', '', '2026-05-18', 0, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('교과서', '교과서', 'paper', '·종이의 종류로는 골판지, 백판지, 백상지, 종이팩 등이 있습니다. ·종이를 배출할 때에는 골판지와 골판지 외 종이류(백판지, 백상지 등)으로 구분하여 배출합니다. ·교과서는 신문지, 백상지 등 기타 종이류와 함께 배출합니다.', '["교과서는 종이류수거함으로 배출합니다."]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 코팅종이, 금박지, 은박지, 검은색 먹지 등은 제거하여 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('계란판의 재질', '계란판의 재질', 'plastic', '· 계란판은 계란을 보관하며 운반시 깨지지 않도록 보호하는 용기로 재질은 주로 종이 또는 합성수지재질로 제작됩니다.', '["계란판의 재질이 종이인 경우에는 종이류수거함으로 배출합니다.", "계란판의 재질이 플라스틱인 경우에는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=35', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 계란판은 계란을 보관하며 운반시 깨지지 않도록 보호하는 용기로 재질은 주로 종이 또는 합성수지재질로 제작됩니다.', '· 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "종이", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 피자박스', '깨끗한 피자박스', 'paper', '· 종이는 수거하여 종류별로 분류한 후 각각의 제지공장으로 운반되어 해리, 정선, 농축, 고해 과정을 거친 후 펄프와 혼합하여 종이로 재활용하고 있습니다. · 피자박스, 치킨박스 등 음식포장박스는 내용물을 비우고 이물질이 묻지 않았다면 종이류로 배출합니다. · 이물질이 묻은 경우에는 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니,', '["깨끗한 피자박스는 종이류로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=37', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 종이는 수거하여 종류별로 분류한 후 각각의 제지공장으로 운반되어 해리, 정선, 농축, 고해 과정을 거친 후 펄프와 혼합하여 종이로 재활용하고 있습니다. · 피자박스, 치킨박스 등 음식포장박스는 내용물을 비우고 이물질이 묻지 않았다면 종이류로 배출합니다. · 이물질이 묻은 경우에는 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이...', '', '2026-05-18', 0, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('슈트리', '슈트리', 'general', '· 슈트리는 신발 모양을 유지해주는 제품입니다. · 슈트리가 단일재질이 경우에는 재질에 맞게 종이와 플라스틱으로 각각 배출합니다. · 나무, 플라스틱, 고철 등 복합재질인 경우 일반쓰레기로 배출합니다.', '["슈트리는 재질에 맞게 종이류 수거함, 플라스틱 수거함에 배출합니다.", "슈트리가 복합재질인 경우 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=38', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 슈트리는 신발 모양을 유지해주는 제품입니다. · 슈트리가 단일재질이 경우에는 재질에 맞게 종이와 플라스틱으로 각각 배출합니다. · 나무, 플라스틱, 고철 등 복합재질인 경우 일반쓰레기로 배출합니다.', '· 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "종이", "합성수지 용기류", "일반폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('담뱃갑', '담뱃갑', 'general', '· 담뱃갑은 종이, 비닐, 은박지가 혼합된 제품으로 일반쓰레기로 배출합니다. · 다만 비닐과 종이를 분리하여 배출하는 경우에는 포장비닐은 비닐류로 배출하고, 종이 케이스는 은박지를 제거하고 종이류 수거함으로 배출합니다. · 은박지는 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해', '["담뱃갑은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=39', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 담뱃갑은 종이, 비닐, 은박지가 혼합된 제품으로 일반쓰레기로 배출합니다. · 다만 비닐과 종이를 분리하여 배출하는 경우에는 포장비닐은 비닐류로 배출하고, 종이 케이스는 은박지를 제거하고 종이류 수거함으로 배출합니다. · 은박지는 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다....', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('냄비', '냄비', 'can', '· 냄비, 프라이팬 등은 대부분 금속으로 제작되어 있어 고철수거함으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["냄비는 고철수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=45', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 냄비, 프라이팬 등은 대부분 금속으로 제작되어 있어 고철수거함으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 고철 외 다른 재질이 섞인 정도에 따라 고철 수거함 또는 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('가마솥', '가마솥', 'furniture', '· 가마솥은 예로부터 음식을 끓이거나 밥을 짓는데 사용하는 주방도구로 주로 철(무쇠)로 제작하고 있습니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정', '["가마솥은 고철수거함으로 배출합니다.", "가마솥의 크기, 무게가 커 고철수거함으로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=46', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가마솥은 예로부터 음식을 끓이거나 밥을 짓는데 사용하는 주방도구로 주로 철(무쇠)로 제작하고 있습니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법...', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('철사', '철사', 'can', '· 철사는 쇠로 만든 가는 줄로 공예, 원예 등에 주로 사용되는 제품입니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["철사는 고철수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=47', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 철사는 쇠로 만든 가는 줄로 공예, 원예 등에 주로 사용되는 제품입니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 긴 철사는 접거나 묶은 후 배출 · 철사에 피복이 있는 경우에는 재활용이 어려워 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('다량의 클립', '다량의 클립', 'can', '· 클립은 고철 단일재질로 재활용이 가능합니다. · 다만, 클립의 크기가 작아 낱개로 배출할 경우 선별시설에서 선별이 어려워 잔재물로 배출되는 경우가 많습니다. · 크기가 작은 고철제품은 낱개로 배출할 경우 종량제봉투로 배출하는 것이 좋으며, 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별', '["다량의 클립은 고철수거함으로 배출합니다.", "낱개의 클립은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=48', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 클립은 고철 단일재질로 재활용이 가능합니다. · 다만, 클립의 크기가 작아 낱개로 배출할 경우 선별시설에서 선별이 어려워 잔재물로 배출되는 경우가 많습니다. · 크기가 작은 고철제품은 낱개로 배출할 경우 종량제봉투로 배출하는 것이 좋으며, 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다. · 다량으...', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('압축봉', '압축봉', 'plastic', '· 압축봉은 금속, 플라스틱, 목재 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 금속, 플라스틱 등 단일재질로 분리가 가능한 경우에는 각각 분리하여 금속은 고철 수거함에 배출하고, 플라스틱은 재활용품으로, 목재는 일반쓰레기로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 제품인 경우 대형폐기물로 배출합니다.', '["압축봉은 분리한 후 재질에 맞게 고철수거함, 플라스틱 수거함 등으로 배출합니다.", "재질별 분리가 어려운 경우에는 종량제봉투로 배출합니다.", "크기가 크거나 무게가 무거운 제품은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=50', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 압축봉은 금속, 플라스틱, 목재 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 금속, 플라스틱 등 단일재질로 분리가 가능한 경우에는 각각 분리하여 금속은 고철 수거함에 배출하고, 플라스틱은 재활용품으로, 목재는 일반쓰레기로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 제품인 경우 대형폐기물로 배출합니다.', '· 재질별로 분리가 가능하다면 가급적 분리한 후 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('아령(덤벨)', '아령(덤벨)', 'furniture', '· 아령, 덤벨 등 소형 운동기구는 대부분 철로 구성되어 있습니다. · 일부 제품의 경우 플라스틱, 고무 등이 혼합되어 있으나 전체 중량 대비 소량에 해당되므로 고철로 배출하면 됩니다. · 바벨, 벤치프레스 등 제품의 크기가 크고 무거운 제품은 대형폐기물로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여', '["아령(덤벨)은 고철수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=51', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 아령, 덤벨 등 소형 운동기구는 대부분 철로 구성되어 있습니다. · 일부 제품의 경우 플라스틱, 고무 등이 혼합되어 있으나 전체 중량 대비 소량에 해당되므로 고철로 배출하면 됩니다. · 바벨, 벤치프레스 등 제품의 크기가 크고 무거운 제품은 대형폐기물로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을...', '· 덤벨봉과 덤벨원판은 분리한 후 배출 · 고철 외 다른 재질이 섞인 정도에 따라 고철 수거함 또는 대형폐기물로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('수도배관의 재질', '수도배관의 재질', 'general', '· 수도관은 스테인리스 강관이나 동관, PVC 등으로 제작하고 있습니다. · 금속재질의 수도관은 가급적 부피를 최소화한 후 이물질을 제거하여 고철수거함으로 배출하여 주시면 재활용이 가능합니다. · 플라스틱 관 또는 다양한 재질이 혼합된 복합재질 제품은 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이', '["수도배관의 재질이 금속 단일재질인 경우에는 고철수거함으로 배출합니다.", "수도배관이 플라스틱, 고무 등 다양한 재질이 혼합된 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=52', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 수도관은 스테인리스 강관이나 동관, PVC 등으로 제작하고 있습니다. · 금속재질의 수도관은 가급적 부피를 최소화한 후 이물질을 제거하여 고철수거함으로 배출하여 주시면 재활용이 가능합니다. · 플라스틱 관 또는 다양한 재질이 혼합된 복합재질 제품은 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출...', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('수전의 재질', '수전의 재질', 'general', '· 수전은 금속, 플라스틱, 고무 등이 혼합된 복합재질 제품입니다. · 가급적 재질에 맞게 분리하여 배출하고 분리가 어려운 경우에는 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장', '["수전의 재질이 금속 단일재질인 경우에는 고철 수거함으로 배출합니다.", "수전이 플라스틱, 고무 등 다양한 재질이 혼합된 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=53', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 수전은 금속, 플라스틱, 고무 등이 혼합된 복합재질 제품입니다. · 가급적 재질에 맞게 분리하여 배출하고 분리가 어려운 경우에는 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을...', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('선반', '선반', 'plastic', '· 욕실에 설치하는 선반은 플라스틱, 스테인리스 등으로 제작하고 있으며, 종류에 따라 크기가 다양합니다. · 스테인리스 재질의 선반은 고철수거함으로 배출하고 플라스틱 재질은 플라스틱 수거함으로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 제품인 경우 대형폐기물로 배출합니다.', '["선반은 재질에 맞게 분리한 후 전용수거함으로 배출합니다.", "선반이 플라스틱, 목재 등 다양한 재질이 혼합된 경우에는 종량제봉투로 배출합니다.", "크기가 크거나 무게가 무거운 제품은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=54', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 욕실에 설치하는 선반은 플라스틱, 스테인리스 등으로 제작하고 있으며, 종류에 따라 크기가 다양합니다. · 스테인리스 재질의 선반은 고철수거함으로 배출하고 플라스틱 재질은 플라스틱 수거함으로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 제품인 경우 대형폐기물로 배출합니다.', '· 단일재질 제품이더라도 크기가 큰 제품은 대형폐기물로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('바비큐 그릴', '바비큐 그릴', 'can', '· 바비큐 그릴은 스테인리스, 무쇠 등으로 제작하고 있어 고철수거함으로 배출하면 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["바비큐 그릴은 고철수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=55', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 바비큐 그릴은 스테인리스, 무쇠 등으로 제작하고 있어 고철수거함으로 배출하면 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('불판', '불판', 'can', '· 불판은 스테인리스, 무쇠 등으로 제작하고 있어 고철수거함으로 배출하면 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["불판은 고철수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=56', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 불판은 스테인리스, 무쇠 등으로 제작하고 있어 고철수거함으로 배출하면 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('석쇠', '석쇠', 'can', '· 석쇠는 스테인리스와 같은 금속으로 제작하고 있어 고철수거함으로 배출하면 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["석쇠는 고철수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=57', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 석쇠는 스테인리스와 같은 금속으로 제작하고 있어 고철수거함으로 배출하면 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('반려동물 펜스', '반려동물 펜스', 'furniture', '· 반려동물 펜스는 금속 단일재질로 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유', '["반려동물 펜스는 고철수거함으로 배출합니다.", "크기가 크거나 무게가 무거운 제품은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=58', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 반려동물 펜스는 금속 단일재질로 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수료에 준하여 책정하고...', '· 단일재질 제품이더라도 크기가 큰 제품은 대형폐기물로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('맥주케그', '맥주케그', 'furniture', '· 맥주케그는 일부 금속 외 타 재질이 포함되어 있으나 대부분 금속재질이므로 내용물을 최대한 제거하신 후 고철수거함으로 배출하여야 합니다. · 제품을 폐기하실 때 일부 제품에 한하여 금속, 합성수지 등이 포함된 경우가 있으나 이 경우 제품에 표기된 분리배출 표시 또는 재질을 참고하여 배출하여 주시기 바랍니다.', '["맥주케그는 고철수거함으로 배출하여 주시기 바랍니다.", "크기가 크거나 무게가 무거운 제품은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=59', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 맥주케그는 일부 금속 외 타 재질이 포함되어 있으나 대부분 금속재질이므로 내용물을 최대한 제거하신 후 고철수거함으로 배출하여야 합니다. · 제품을 폐기하실 때 일부 제품에 한하여 금속, 합성수지 등이 포함된 경우가 있으나 이 경우 제품에 표기된 분리배출 표시 또는 재질을 참고하여 배출하여 주시기 바랍니다.', '· 제품 내부에 들어있는 물품은 억지로 제거하지 않고 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('금속 재질의 메달', '금속 재질의 메달', 'can', '· 메달은 금, 은, 동, 철 등 금속으로 제작하고 있으며, 고철 수거함으로 배출하여 주시면 재활용이 가능합니다. · 다만, 고철 외 타 재질로 제작하였거나, 타 재질의 함량이 높은 경우에는 재활용이 어렵습니다.', '["금속 재질의 메달은 고철수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=60', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 메달은 금, 은, 동, 철 등 금속으로 제작하고 있으며, 고철 수거함으로 배출하여 주시면 재활용이 가능합니다. · 다만, 고철 외 타 재질로 제작하였거나, 타 재질의 함량이 높은 경우에는 재활용이 어렵습니다.', '· 이물질을 제거한 후 배출 · 고철 외 다른 재질이 섞인 정도에 따라 고철 수거함 또는 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('클리어파일', '클리어파일', 'general', '· 클리어파일은 내지(비닐류)와 커버(PP재질)로 구성되어 있습니다. · 가급적 재질에 맞게 분리 배출하고, 분리가 어려운 경우에는 제품 그대로 종량제봉투로 배출하여 주시기 바랍니다.', '["클리어파일은 가급적 재질별로 분리하여 배출하며, 분리하기 어려운 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=62', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 클리어파일은 내지(비닐류)와 커버(PP재질)로 구성되어 있습니다. · 가급적 재질에 맞게 분리 배출하고, 분리가 어려운 경우에는 제품 그대로 종량제봉투로 배출하여 주시기 바랍니다.', '· 클리어 파일은 내지와 커버는 분리한 후 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "합성수지 비닐류", "일반폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('정리함', '정리함', 'furniture', '· 정리함은 주로 플라스틱으로 되어 있으며, 일부 제품은 케이스와 수납함의 재질이 다른 경우가 있습니다. · 정리함이 단일재질 제품인 경우에는 재질에 맞게 배출하며, 재질이 혼합된 경우 종량제봉투 또는 대형폐기물로 배출합니다.', '["정리함이 단일재질인 경우 재질에 맞게 배출합니다.", "정리함이 복합재질인 경우 종량제봉투로 배출합니다.", "크기가 커 수거함 또는 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=63', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 정리함은 주로 플라스틱으로 되어 있으며, 일부 제품은 케이스와 수납함의 재질이 다른 경우가 있습니다. · 정리함이 단일재질 제품인 경우에는 재질에 맞게 배출하며, 재질이 혼합된 경우 종량제봉투 또는 대형폐기물로 배출합니다.', '· 재질별로 분리가 가능하다면 가급적 분리한 후 재질에 맞게 배출 · 대형폐기물로 배출하는 경우 수납함이 분리되지 않도록 테이프 등으로 붙여서 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('바디로션', '바디로션', 'plastic', '· 바디로션과 같이 가정에서 사용하는 플라스틱의 용기는 대부분 생산자책임재활용제도(EPR) 대상 품목에 해당되며 재활용이 가능합니다. · 일부 제품의 경우 용기 속의 내용물을 쉽게 배출될 수 있도록 펌프를 사용합니다. 펌프는 플라스틱과 고철 등이 혼합된 복합재질 제품으로 재활용이 어려우므로 제거한 후 배출합니다. · 비닐 라벨이 붙어 있는 경우에는 제거하여', '["바디로션은 내용물을 비우고 라벨, 펌프 등 이물질을 제거한 후 용기는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=64', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 바디로션과 같이 가정에서 사용하는 플라스틱의 용기는 대부분 생산자책임재활용제도(EPR) 대상 품목에 해당되며 재활용이 가능합니다. · 일부 제품의 경우 용기 속의 내용물을 쉽게 배출될 수 있도록 펌프를 사용합니다. 펌프는 플라스틱과 고철 등이 혼합된 복합재질 제품으로 재활용이 어려우므로 제거한 후 배출합니다. · 비닐 라벨이 붙어 있는 경우에는 제거하여 비닐 수거함에 배출합니다. · 다량...', '· 용기류를 배출할 때에는 라벨, 펌프를 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('펌핑용기', '펌핑용기', 'plastic', '· 세안에 사용하는 클렌징 폼은 펌핑 용기 형태와 튜브형태가 있습니다. · 가정에서 사용하는 합성수지 용기는 대부분 생산자책임재활용제도 (EPR)대상 품목에 해당되어 재활용이 가능합니다. · 펌핑용기를 배출하실 때에는 뚜껑과 펌프를 제거한 후 펌프는 일반쓰레기로 배출하며, 용기는 재활용품으로 배출합니다. · 비닐 라벨이 붙어 있는 경우에는 제거하여 비닐 수', '["펌핑용기는 펌프와 내용물을 제거한 후 물로 헹구는 등 깨끗한 상태로 플라스틱 수거함으로 배출합니다.", "튜브제품은 내용물을 비운후 플라스틱수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=65', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 세안에 사용하는 클렌징 폼은 펌핑 용기 형태와 튜브형태가 있습니다. · 가정에서 사용하는 합성수지 용기는 대부분 생산자책임재활용제도 (EPR)대상 품목에 해당되어 재활용이 가능합니다. · 펌핑용기를 배출하실 때에는 뚜껑과 펌프를 제거한 후 펌프는 일반쓰레기로 배출하며, 용기는 재활용품으로 배출합니다. · 비닐 라벨이 붙어 있는 경우에는 제거하여 비닐 수거함에 배출합니다. · 치약과 같은...', '· 펌프, 라벨 등 이물질은 제거한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('락스', '락스', 'plastic', '· 세정제의 용기는 HDPE 재질의 플라스틱으로 내용물을 제거한 후 플라스틱 수거함으로 배출하여 주시면 재활용이 가능합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역', '["락스는 내용물을 완전히 제거한 후 물로 헹구는 등 깨끗한 상태로 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=66', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 세정제의 용기는 HDPE 재질의 플라스틱으로 내용물을 제거한 후 플라스틱 수거함으로 배출하여 주시면 재활용이 가능합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('양파망', '양파망', 'vinyl', '· 양파, 배추 등을 담은 합성수지 재질의 포장용기(그물망)는 재활용의무대상(EPR) 품목에 해당됩니다. · 해당 제품은 비닐류와 성질이 유사하여 비닐 수거함으로 배출하면 됩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현', '["양파망은 비닐 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=67', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 양파, 배추 등을 담은 합성수지 재질의 포장용기(그물망)는 재활용의무대상(EPR) 품목에 해당됩니다. · 해당 제품은 비닐류와 성질이 유사하여 비닐 수거함으로 배출하면 됩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('PCR 플라스틱', 'PCR 플라스틱', 'plastic', '· PCR 제품이란 Post-Consumer Recycled 제품의 약자로, 어떤 물건을 소비자가 사용한 뒤 다른 물건을 만드는 재료로 전환하거나 원래 용도를 되살리는 것을 의미합니다. · PCR 제품은 재생원료가 함유된 비율에 따라 PCR 40%, PCR 100% 등으로 명명하고 있습니다. · 현재 PCR 제품의 분리배출 기준이 별도로 정하고 있지 않으므', '["PCR 플라스틱은 플라스틱수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=68', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· PCR 제품이란 Post-Consumer Recycled 제품의 약자로, 어떤 물건을 소비자가 사용한 뒤 다른 물건을 만드는 재료로 전환하거나 원래 용도를 되살리는 것을 의미합니다. · PCR 제품은 재생원료가 함유된 비율에 따라 PCR 40%, PCR 100% 등으로 명명하고 있습니다. · 현재 PCR 제품의 분리배출 기준이 별도로 정하고 있지 않으므로 재질에 맞게 배출하여 주시기 바랍...', '· 타 플라스틱 제품과 동일한 방법으로 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('간장용기', '간장용기', 'plastic', '·간장용기는 플라스틱(무색페트 등) 재질로 내용물을 제거한 후 플라스틱 수거함으로 배출하여 주시면 재활용이 가능합니다.', '["간장용기는 내용물을 비우고 라벨 등 이물질을 제거한 후 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=69', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·간장용기는 플라스틱(무색페트 등) 재질로 내용물을 제거한 후 플라스틱 수거함으로 배출하여 주시면 재활용이 가능합니다.', '· 라벨을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('강판의 재질', '강판의 재질', 'can', '· 강판은 채소나 과일 등의 식재료를 문질러 잘게 만드는 주방기구로 주로 금속 또는 합성수지제품으로 제작됩니다. · 강판의 외부 표면이 날카로워 사람이 찔리거나 베이는 등 다칠 우려가 있으므로 신문지, 테이프 등으로 감싼 후 배출하는 것이 좋습니다.', '["강판의 재질이 합성수지인 경우에는 플라스틱 수거함으로 배출합니다.", "강판의 재질이 금속인 경우에는 고철수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=70', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 강판은 채소나 과일 등의 식재료를 문질러 잘게 만드는 주방기구로 주로 금속 또는 합성수지제품으로 제작됩니다. · 강판의 외부 표면이 날카로워 사람이 찔리거나 베이는 등 다칠 우려가 있으므로 신문지, 테이프 등으로 감싼 후 배출하는 것이 좋습니다.', '· 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('L자 파일', 'L자 파일', 'vinyl', '· 사무실에서 문서 보관을 위해 사용하는 L자 파일은 합성수지 제품이나 부드럽고 무른 성질을 가지고 있습니다. · 플라스틱 제품 중 부드럽고 무른 성질이 있는 제품은 비닐류로도 배출할 수 있습니다.', '["L자 파일은 플라스틱 수거함 또는 비닐류 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=71', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 사무실에서 문서 보관을 위해 사용하는 L자 파일은 합성수지 제품이나 부드럽고 무른 성질을 가지고 있습니다. · 플라스틱 제품 중 부드럽고 무른 성질이 있는 제품은 비닐류로도 배출할 수 있습니다.', '· 플라스틱 제품 중 부드럽고 무른 성질이 있는 제품은 비닐류로 배출 가능', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('스노우 체인', '스노우 체인', 'can', '· 스노우 체인은 눈길에서 자동차가 미끄러지는 것을 방지하기 위하여 타이어에 감는 금속 사슬을 말합니다. · 스노우 체인은 금속 단일재질로 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. ※ 배출방법은 지역', '["스노우 체인은 고철 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=72', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 스노우 체인은 눈길에서 자동차가 미끄러지는 것을 방지하기 위하여 타이어에 감는 금속 사슬을 말합니다. · 스노우 체인은 금속 단일재질로 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당...', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('바나나우유 용기', '바나나우유 용기', 'plastic', '· 바나나우유의 용기는 플라스틱(PS)재질로 재활용이 가능합니다. · 용기 내의 내용물을 비우고 물로 헹군 후 플라스틱 수거함으로 배출합니다. · 용기에서 제거한 뚜껑(리드)은 종량제봉투로 배출합니다.', '["바나나우유 용기는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=73', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 바나나우유의 용기는 플라스틱(PS)재질로 재활용이 가능합니다. · 용기 내의 내용물을 비우고 물로 헹군 후 플라스틱 수거함으로 배출합니다. · 용기에서 제거한 뚜껑(리드)은 종량제봉투로 배출합니다.', '· 내용물을 비우고 물로 헹군 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('요거트 용기', '요거트 용기', 'plastic', '· 요거트의 용기는 플라스틱(PS)재질로 내용물을 비우고 물로 헹군 후 플라스틱 수거함으로 배출합니다. · 용기에서 제거한 뚜껑(리드)은 종량제봉투로 배출합니다.', '["요거트 용기는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=74', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 요거트의 용기는 플라스틱(PS)재질로 내용물을 비우고 물로 헹군 후 플라스틱 수거함으로 배출합니다. · 용기에서 제거한 뚜껑(리드)은 종량제봉투로 배출합니다.', '· 내용물을 비우고 물로 헹군 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('수저의 재질', '수저의 재질', 'general', '· 수저는 숟가락과 젓가락을 합해 이루는 것이며, 스테인리스로 된 수저는 고철 수거함에 배출합니다. · 나무 재질로 되어 있거나 나무, 플라스틱 손잡이 등 다른 재질이 포함되어 재질별 분리가 어려운 수저는 일반쓰레기로 배출합니다.', '["수저의 재질이 금속 단일재질인 경우에는 고철수거함으로 배출합니다.", "목재제품인 경우에는 종량제봉투로 배출합니다.", "수저가 다양한 재질이 혼합된 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=75', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 수저는 숟가락과 젓가락을 합해 이루는 것이며, 스테인리스로 된 수저는 고철 수거함에 배출합니다. · 나무 재질로 되어 있거나 나무, 플라스틱 손잡이 등 다른 재질이 포함되어 재질별 분리가 어려운 수저는 일반쓰레기로 배출합니다.', '· 재질을 확인한 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('후드 필터의 재질', '후드 필터의 재질', 'can', '· 후드 필터의 프레임과 망이 모두 금속 재질인 경우에는 고철류로 배출합니다. · 다만, 고철 이외의 다른 재질이 혼합되어 있는 경우는 재활용이 어려우니 종량제봉투에 담아서 배출하거나, 담기 어려운 경우에는 대형폐기물로 배출하여 주시기 바랍니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에', '["후드 필터의 재질이 금속인 경우에는 고철 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=76', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 후드 필터의 프레임과 망이 모두 금속 재질인 경우에는 고철류로 배출합니다. · 다만, 고철 이외의 다른 재질이 혼합되어 있는 경우는 재활용이 어려우니 종량제봉투에 담아서 배출하거나, 담기 어려운 경우에는 대형폐기물로 배출하여 주시기 바랍니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분...', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('텀블러', '텀블러', 'plastic', '· 텀블러의 재질이 금속과 플라스틱 단일재질로 되어 있는 경우에는 금속과 플라스틱으로 각각 배출합니다. · 재질별로 분리하기 어렵거나 혼합재질인 제품은 일반쓰레기로 배출합니다.', '["텀블러는 재질에 맞게 분리한 후 전용수거함으로 배출합니다.", "재질별로 분리하기 어려운 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=77', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 텀블러의 재질이 금속과 플라스틱 단일재질로 되어 있는 경우에는 금속과 플라스틱으로 각각 배출합니다. · 재질별로 분리하기 어렵거나 혼합재질인 제품은 일반쓰레기로 배출합니다.', '· 재질별로 분리가 가능하다면 가급적 분리한 후 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('부탄가스', '부탄가스', 'can', '· 부탄가스, 스프레이 용기는 내부 가스로 인하여 폭발 위험이 있으므로 환기가 잘되는 장소에서 노즐을 눌러 내용물을 완전히 제거한 후 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["부탄가스는 금속캔 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=78', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 부탄가스, 스프레이 용기는 내부 가스로 인하여 폭발 위험이 있으므로 환기가 잘되는 장소에서 노즐을 눌러 내용물을 완전히 제거한 후 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 내용물(가스)을 완전히 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "기타캔류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('펜치', '펜치', 'can', '· 펜치 등 공구류는 대부분 금속재질로 고철로 배출하면 됩니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["펜치는 고철수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=79', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 펜치 등 공구류는 대부분 금속재질로 고철로 배출하면 됩니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 고철 외 다른 재질이 섞인 정도에 따라 고철 수거함 또는 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('나사', '나사', 'can', '· 나사, 너트, 볼트 등의 부품은 금속재질로 고철로 배출하면 됩니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법', '["나사는 고철수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=80', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 나사, 너트, 볼트 등의 부품은 금속재질로 고철로 배출하면 됩니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운...', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('법랑냄비', '법랑냄비', 'can', '· 법랑냄비는 금속 표면에 유리질 유약을 바른 후 만든 제품으로 고철 수거함으로 배출합니다. · 내열유리뚜껑은 불연성종량제봉투(특수규격마대)에 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. ※ 배출방법은 지역별로', '["법랑냄비는 고철수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=81', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 법랑냄비는 금속 표면에 유리질 유약을 바른 후 만든 제품으로 고철 수거함으로 배출합니다. · 내열유리뚜껑은 불연성종량제봉투(특수규격마대)에 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자...', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('집게의 재질', '집게의 재질', 'general', '· 집게가 스테인리스 단일 재질인 경우 고철수거함으로 배출합니다. · 집게손잡이에 플라스틱, 고무 등이 혼합된 제품이라면 종량제봉투로 배출하여 주시기 바랍니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배', '["집게의 재질이 금속 단일재질인 경우에는 고철수거함으로 배출합니다.", "집게가 다양한 재질이 혼합된 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=82', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 집게가 스테인리스 단일 재질인 경우 고철수거함으로 배출합니다. · 집게손잡이에 플라스틱, 고무 등이 혼합된 제품이라면 종량제봉투로 배출하여 주시기 바랍니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역...', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('청소솔', '청소솔', 'plastic', '· 청소솔은 금속, 플라스틱 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 금속, 플라스틱 등 단일재질로 분리가 가능한 경우에는 각각 분리하여 금속은 고철 수거함에 배출하고, 플라스틱은 재활용품으로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 제품인 경우 대형폐기물로 배출합니다.', '["청소솔은 재질에 맞게 분리한 후 전용수거함으로 배출합니다.", "재질별로 분리하기 어려운 경우에는 종량제봉투로 배출합니다.", "크기가 커 수거함 또는 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=83', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 청소솔은 금속, 플라스틱 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 금속, 플라스틱 등 단일재질로 분리가 가능한 경우에는 각각 분리하여 금속은 고철 수거함에 배출하고, 플라스틱은 재활용품으로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 제품인 경우 대형폐기물로 배출합니다.', '· 재질별로 분리가 가능하다면 가급적 분리한 후 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('스마트폰거치대', '스마트폰거치대', 'general', '· 스마트폰거치대가 금속재질(알루미늄)인 경우에는 고철로 배출합니다. · 금속재질 이외 실리콘, 자석 등의 다른 재질이 포함되어 재질별 분리가 어려운 경우에는 일반쓰레기로 배출합니다.', '["스마트폰거치대는 고철 수거함으로 배출합니다.", "다양한 재질이 혼합된 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=87', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 스마트폰거치대가 금속재질(알루미늄)인 경우에는 고철로 배출합니다. · 금속재질 이외 실리콘, 자석 등의 다른 재질이 포함되어 재질별 분리가 어려운 경우에는 일반쓰레기로 배출합니다.', '· 재질 확인 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('분유통', '분유통', 'can', '· 분유통는 몸체(철)와 속뚜껑(알루미늄)은 금속 재질로 금속캔 수거함으로 배출합니다. · 뚜껑과 스푼은 플라스틱 재질(PP)로 몸체와 분리하여 플라스틱 수거함으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["분유통은 금속캔 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=88', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 분유통는 몸체(철)와 속뚜껑(알루미늄)은 금속 재질로 금속캔 수거함으로 배출합니다. · 뚜껑과 스푼은 플라스틱 재질(PP)로 몸체와 분리하여 플라스틱 수거함으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 내용물을 비우고 물로 헹군 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "기타캔류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('와이퍼', '와이퍼', 'plastic', '· 자동차 부품인 와이퍼는 플라스틱, 금속, 고무, 실리콘 등이 혼합된 복합재질 제품입니다. · 금속, 플라스틱 등 단일재질로 분리가 가능한 경우에는 각각 분리하여 금속은 고철 수거함에 배출하고, 플라스틱은 플라스틱 수거함으로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 제품인 경우 대형폐기물로 배출합니다.', '["와이퍼는 재질에 맞게 분리한 후 전용수거함으로 배출합니다.", "재질별로 분리하기 어려운 경우에는 종량제봉투 또는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=90', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 자동차 부품인 와이퍼는 플라스틱, 금속, 고무, 실리콘 등이 혼합된 복합재질 제품입니다. · 금속, 플라스틱 등 단일재질로 분리가 가능한 경우에는 각각 분리하여 금속은 고철 수거함에 배출하고, 플라스틱은 플라스틱 수거함으로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 제품인 경우 대형폐기물로 배출합니다.', '· 재질별로 분리가 가능하다면 분리한 후 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('새장', '새장', 'plastic', '· 새장은 주로 프레임은 금속재질이며, 모이통 및 배변판은 플라스틱 재질입니다. · 금속, 플라스틱 등 단일재질로 분리가 가능한 경우에는 각각 분리하여 금속은 고철 수거함에 배출하고, 플라스틱은 물로 헹구는 등 이물질을 제거한 후 플라스틱 수거함으로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 새장인 경우 대형폐기물로', '["새장은 재질에 맞게 분리한 후 전용수거함으로 배출합니다.", "재질별로 분리하기 어려운 경우에는 종량제봉투 또는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=91', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 새장은 주로 프레임은 금속재질이며, 모이통 및 배변판은 플라스틱 재질입니다. · 금속, 플라스틱 등 단일재질로 분리가 가능한 경우에는 각각 분리하여 금속은 고철 수거함에 배출하고, 플라스틱은 물로 헹구는 등 이물질을 제거한 후 플라스틱 수거함으로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 새장인 경우 대형폐기물로 배출합니다.', '· 재질별로 분리가 가능하다면 분리한 후 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('가스압력밥솥', '가스압력밥솥', 'furniture', '· 가스압력밥솥은 손잡이는 플라스틱이나 제품 대부분이 금속으로 제작되어 있어 고철수거함으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["가스압력밥솥은 고철수거함으로 배출합니다.", "가스압력밥솥의 크기, 무게가 커 고철수거함으로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=93', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가스압력밥솥은 손잡이는 플라스틱이나 제품 대부분이 금속으로 제작되어 있어 고철수거함으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 고철 외 다른 재질이 섞인 정도에 따라 고철 수거함 또는 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('채망', '채망', 'can', '· 채망 손잡이는 플라스틱이나 채망 제품의 대부분이 금속으로 제작되어 있어 고철 수거함으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["채망은 고철수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=94', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 채망 손잡이는 플라스틱이나 채망 제품의 대부분이 금속으로 제작되어 있어 고철 수거함으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 고철 외 다른 재질이 섞인 정도에 따라 고철 수거함 또는 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('휴대용 가스버너', '휴대용 가스버너', 'can', '· 휴대용 가스버너는 대부분 금속으로 제작되어 있어 고철수거함으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["휴대용 가스버너는 고철수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=95', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 휴대용 가스버너는 대부분 금속으로 제작되어 있어 고철수거함으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 고철 외 다른 재질이 섞인 정도에 따라 고철 수거함 또는 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('수분리성 라벨', '수분리성 라벨', 'vinyl', '· 수분리성 점착라벨이란 PET 용기의 재활용을 향상시킬 수 있도록 제작된 비닐로 재활용공정에서 일정온도의 물과 접촉시 라벨이 쉽게 분리되는 특징을 가지고 있습니다. · 합성수지 비닐과 용기류는 동일한 재질이더라도 물성이 달라 함께 재활용하기 어려우므로 분리하여 배출하는 것이 좋습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서', '["수분리성 라벨은 비닐류로 분리하여 배출하여 주시는 것이 좋습니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=96', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 수분리성 점착라벨이란 PET 용기의 재활용을 향상시킬 수 있도록 제작된 비닐로 재활용공정에서 일정온도의 물과 접촉시 라벨이 쉽게 분리되는 특징을 가지고 있습니다. · 합성수지 비닐과 용기류는 동일한 재질이더라도 물성이 달라 함께 재활용하기 어려우므로 분리하여 배출하는 것이 좋습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('과자봉지', '과자봉지', 'vinyl', '· 과일, 과자 등을 포장하기 위해 사용하는 대부분의 합성수지 비닐은 생산자책임재활용제도 (EPR)대상 품목에 해당되어 재활용이 가능합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '["과자봉지는 비닐류수거함으로 배출합니다."]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '·이물질을 제거한 후 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('즉석밥용기', '즉석밥용기', 'plastic', '· 플라스틱에는 PP, PE, PS, PET와 OTHER류가 있으며, 2가지 이상의 플라스틱이 복합된 복합재질 또는 PVC, ABS재질 등의 단일재질 제품은 OTHER류에 해당합니다. · 플라스틱은 재활용 선별장에서 재질별(PP, PE, PET, PS, OTHER)로 선별한 후 각 재활용업체로 운반하여 재활용하고 있습니다. OTEHR류의 경우 물질 재활용은', '["즉석밥용기는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=98', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 플라스틱에는 PP, PE, PS, PET와 OTHER류가 있으며, 2가지 이상의 플라스틱이 복합된 복합재질 또는 PVC, ABS재질 등의 단일재질 제품은 OTHER류에 해당합니다. · 플라스틱은 재활용 선별장에서 재질별(PP, PE, PET, PS, OTHER)로 선별한 후 각 재활용업체로 운반하여 재활용하고 있습니다. OTEHR류의 경우 물질 재활용은 어려우나 화학적 재활용 또는 에너지...', '· OTHER류 제품은 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 플라스틱 도마', '깨끗한 플라스틱 도마', 'plastic', '· 폴리프로필렌(pp) 재질로 된 밀폐보관용기, 도마, 바구니, 옷걸이 등의 생활용품은 EPR 대상 품목으로 지정되어 재활용이 됩니다. · 도마가 플라스틱(PP) 단일 재질인 경우 음식물 등 이물질을 제거한 후 플라스틱수거함으로 배출합니다. · 다만, 도마가 음식물 등 이물질 제거가 어렵거나 오염된 경우에는 일반쓰레기로 배출합니다.', '["깨끗한 플라스틱 도마는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=99', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 폴리프로필렌(pp) 재질로 된 밀폐보관용기, 도마, 바구니, 옷걸이 등의 생활용품은 EPR 대상 품목으로 지정되어 재활용이 됩니다. · 도마가 플라스틱(PP) 단일 재질인 경우 음식물 등 이물질을 제거한 후 플라스틱수거함으로 배출합니다. · 다만, 도마가 음식물 등 이물질 제거가 어렵거나 오염된 경우에는 일반쓰레기로 배출합니다.', '· 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('워셔액 용기', '워셔액 용기', 'plastic', '· 생수 및 음료 이외의 투명페트병(주류, 양념류, 식용유, 워셔액, 손세정제 등)은 플라스틱으로 배출합니다.', '["워셔액 용기는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=100', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 생수 및 음료 이외의 투명페트병(주류, 양념류, 식용유, 워셔액, 손세정제 등)은 플라스틱으로 배출합니다.', '· 먹는 샘물, 음료 외 타 무색페트용기는 전용수거함으로 배출 불가', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('스프봉지', '스프봉지', 'vinyl', '· 비닐봉지안의 내용물을 비우고 물로 헹구는 등 이물질을 제거하여 비닐류수거함으로 배출합니다. · 작은 크기의 비닐봉지는 흩날리지 않도록 투명 또는 반투명봉투에 담아 비닐류수거함으로 배출합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '["스프봉지는 비닐류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=102', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 비닐봉지안의 내용물을 비우고 물로 헹구는 등 이물질을 제거하여 비닐류수거함으로 배출합니다. · 작은 크기의 비닐봉지는 흩날리지 않도록 투명 또는 반투명봉투에 담아 비닐류수거함으로 배출합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '· 내용물을 비우고 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('커피봉지', '커피봉지', 'vinyl', '· 스틱봉지처럼 작은 크기의 비닐봉지는 흩날리지 않도록 투명 또는 반투명봉투에 담아 비닐류수거함으로 배출합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '["커피봉지는 비닐류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=103', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 스틱봉지처럼 작은 크기의 비닐봉지는 흩날리지 않도록 투명 또는 반투명봉투에 담아 비닐류수거함으로 배출합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '· 내용물을 비우고 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('스파우트 파우치', '스파우트 파우치', 'vinyl', '· 스파우트 파우치는 위생적이고 마시기 쉽도록 입구 부분에 돌림형 마개를 부착한 용기입니다. · 용기의 몸체는 비닐류수거함으로 배출하며, 뚜껑은 플라스틱 수거함으로 배출하여 주시기 바랍니다', '["스파우트 파우치는 비닐류 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=104', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 스파우트 파우치는 위생적이고 마시기 쉽도록 입구 부분에 돌림형 마개를 부착한 용기입니다. · 용기의 몸체는 비닐류수거함으로 배출하며, 뚜껑은 플라스틱 수거함으로 배출하여 주시기 바랍니다', '· 뚜껑, 캡 제거 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
