INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('일회용 비닐장갑', '일회용 비닐장갑', 'vinyl', '· 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '["일회용 비닐장갑는 비닐류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=108', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '· 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('위생팩', '위생팩', 'vinyl', '· 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '["위생팩는 비닐류 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=109', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '· 내용물을 비우고 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('다 쓴 립밤', '다 쓴 립밤', 'plastic', '· 립밤을 다 사용하여 내용물이 남아 있지 않은 립밤 용기는 플라스틱으로 배출합니다. · 화장품의 내용물이 남아 있어서 제거하기 곤란한 경우에는 종량제봉투에 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에', '["다 쓴 립밤은 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=110', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 립밤을 다 사용하여 내용물이 남아 있지 않은 립밤 용기는 플라스틱으로 배출합니다. · 화장품의 내용물이 남아 있어서 제거하기 곤란한 경우에는 종량제봉투에 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('카페 일회용컵', '카페 일회용컵', 'plastic', '· 카페 일회용컵과 같은 일반 페트재질의 플라스틱 용기는 무색페트병과 달리 포장재 제품에 따라 다른 플라스틱이 혼합되는 경우가 있습니다. · 이러한 용기가 무색페트병과 함께 재활용할 시 재생원료의 품질이 떨어질 수 있으므로 반드시 일반페트 용기와 무색페트병은 구분하여 배출하여야 합니다. · 카페 일회용컵이 자원순환보증금 대상인 경우 해당 매장에 반납하여 보', '["카페 일회용컵은 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=111', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 카페 일회용컵과 같은 일반 페트재질의 플라스틱 용기는 무색페트병과 달리 포장재 제품에 따라 다른 플라스틱이 혼합되는 경우가 있습니다. · 이러한 용기가 무색페트병과 함께 재활용할 시 재생원료의 품질이 떨어질 수 있으므로 반드시 일반페트 용기와 무색페트병은 구분하여 배출하여야 합니다. · 카페 일회용컵이 자원순환보증금 대상인 경우 해당 매장에 반납하여 보증금을 받으실 수 있습니다.', '· 먹는 샘물, 음료 외 타 무색페트용기는 전용수거함으로 배출 불가 · 내용물을 비우고 물로 헹군 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('케찹 용기', '케찹 용기', 'plastic', '·케찹용기는 플라스틱(PE) 재질로 내용물을 비우고 물로 헹구는 등 이물질을 제거한 후 플라스틱 수거함으로 배출합니다.', '["케찹 용기는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=114', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·케찹용기는 플라스틱(PE) 재질로 내용물을 비우고 물로 헹구는 등 이물질을 제거한 후 플라스틱 수거함으로 배출합니다.', '·내용물을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('도시락 김 용기', '도시락 김 용기', 'plastic', '· 김을 담은 트레이는 플라스틱 재질로 재활용이 가능합니다. 다만 김, 기름 등 이물질을 제거한 후 플라스틱 수거함으로 배출합니다.', '["도시락 김 용기는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=115', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 김을 담은 트레이는 플라스틱 재질로 재활용이 가능합니다. 다만 김, 기름 등 이물질을 제거한 후 플라스틱 수거함으로 배출합니다.', '· 이물질 제거 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('쭈쭈바', '쭈쭈바', 'vinyl', '·일반적으로 쭈쭈바로 불리는 튜브형 아이스크림 용기는 PE 재질로 내용물을 비우고 물로 헹구는 등 이물질을 제거한 후 비닐류수거함으로 배출합니다. ·비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '["쭈쭈바는 비닐류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=116', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·일반적으로 쭈쭈바로 불리는 튜브형 아이스크림 용기는 PE 재질로 내용물을 비우고 물로 헹구는 등 이물질을 제거한 후 비닐류수거함으로 배출합니다. ·비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '·내용물을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('삼각커피우유', '삼각커피우유', 'vinyl', '· 삼각커피우유는 삼각형 비닐 포장재에 담긴 제품으로 내용물을 비우고 물로 헹구는 등 이물질을 제거한 후 비닐류수거함으로 배출합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '["삼각커피우유는 비닐류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=117', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 삼각커피우유는 삼각형 비닐 포장재에 담긴 제품으로 내용물을 비우고 물로 헹구는 등 이물질을 제거한 후 비닐류수거함으로 배출합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '· 내용물을 비우고 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('그레인프로백', '그레인프로백', 'vinyl', '· 그레인프로백 (GrainPro Bag)는 커피 생두를 보관하는 포장재로 PE재질의 비닐입니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배', '["그레인프로백는 비닐류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=118', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 그레인프로백 (GrainPro Bag)는 커피 생두를 보관하는 포장재로 PE재질의 비닐입니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 랩', '깨끗한 랩', 'vinyl', '· 식품포장용 랩은 재활용의무 대상품목으로 재활용이 가능합니다. · 가정용 랩은 PE재질이며, 물로 헹구는 등 이물질을 제거한 깨끗한 랩은 비닐류로 배출합니다. · 다만 음식물 등으로 인하여 오염된 랩은 일반쓰레기로 배출합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고', '["깨끗한 랩은 비닐류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=119', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 식품포장용 랩은 재활용의무 대상품목으로 재활용이 가능합니다. · 가정용 랩은 PE재질이며, 물로 헹구는 등 이물질을 제거한 깨끗한 랩은 비닐류로 배출합니다. · 다만 음식물 등으로 인하여 오염된 랩은 일반쓰레기로 배출합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '· 배달음식 포장랩, 마트에서 사용하는 포장용 랩은 PVC로 재활용 불가', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('테이프클리너', '테이프클리너', 'plastic', '· 테이프 클리너는 침구, 옷 등 먼지를 제거하는데 사용하는 제품으로 플라스틱 재질의 몸체와 테이프로 구성되어 있습니다. · 제품을 각각 분리하여 플라스틱 재질의 몸체는 플라스틱 수거함에 배출하고, 테이프는 일반쓰레기로 배출합니다.', '["테이프클리너는 테이프를 제거한 후 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=120', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 테이프 클리너는 침구, 옷 등 먼지를 제거하는데 사용하는 제품으로 플라스틱 재질의 몸체와 테이프로 구성되어 있습니다. · 제품을 각각 분리하여 플라스틱 재질의 몸체는 플라스틱 수거함에 배출하고, 테이프는 일반쓰레기로 배출합니다.', '· 테이프를 제거하고 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('반찬통의 재질', '반찬통의 재질', 'plastic', '· 금속(스테인리스) 단일 재질의 반찬통은 고철 수거함으로 배출합니다. · 뚜껑 내 실리콘 패킹은 분리하여 종량제봉투로 배출하시고 뚜껑은 플라스틱 수거함으로 배출합니다. · 반찬통 용기 및 뚜껑이 모두 플라스틱 재질인 경우에는 플라스틱 수거함으로 배출합니다.', '["반찬통의 재질이 금속 단일재질인 경우에는 고철 수거함으로 배출합니다.", "반찬통의 재질이 플라스틱 단일재질인 경우에는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=121', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 금속(스테인리스) 단일 재질의 반찬통은 고철 수거함으로 배출합니다. · 뚜껑 내 실리콘 패킹은 분리하여 종량제봉투로 배출하시고 뚜껑은 플라스틱 수거함으로 배출합니다. · 반찬통 용기 및 뚜껑이 모두 플라스틱 재질인 경우에는 플라스틱 수거함으로 배출합니다.', '·고무패킹 제거 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('먹', '먹', 'plastic', '·유색의 페트병 또는 페트재질의 용기는 플라스틱류로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색', '["먹는 샘물과 음료를 담은 무색페트병은 무색페트병 수거함으로 배출합니다.", "라벨과 내용물을 제거하고 물로 헹군 후 압착하여 뚜껑을 닫아 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=122', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 우리나라는 공동주택은 2020년 12월부터, 단독주택은 2021년 12월부터 무색페트병의 분리배출을 시행하고 있습니다. · 별도 분리배출된 음료, 생수 투명페트병은 품질 좋은 재생원료로 재활용되어, 옷이나 신발, 새로운 페트병(식품용기) 등의 원료가 됩니다. · 유색페트병 또는 여러 재질이 혼합된 플라스틱 제품은 투명 페트병과 혼합 배출될 경우 재활용 품질을 낮출 우려가 있기 때문에, 음...', '· 무색페트병은 내용물을 깨끗이 비우고 부착상표(라벨) 등을 제거한 후 가능한 압착하여 뚜껑을 닫아 배출', '2026-05-18', 0, '["재활용폐기물", "무색페트병"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('보조배터리', '보조배터리', 'battery', '· 보조배터리인 리튬이온 전지는 생산자책임재활용제도(EPR) 대상에 해당되지 않는 제품이나 재활용이 가능합니다. · 전지에 내부에는 전해질, 아연 등이 포함되어 있어 외부로 유출될 시 환경 오염에 우려가 될 뿐만 아니라 인체에 들어갈 시 유해할 수 있으므로 주의가 필요합니다. · 전지는 재활용품으로 배출할 시 화재가 발생할 우려가 있으므로 재활용품으로 배출', '["보조배터리는 전지수거함으로 배출합니다."]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 과일포장재(스티로폼)', '깨끗한 과일포장재(스티로폼)', 'styrofoam', '· 과일, 축산물 등을 담은 스티로폼 포장재는 생산자책임재활용제도(EPR) 대상 품목에 해당되어 재활용이 가능합니다. · 발포합성수지는 PP, PE, PS 등의 합성수지를 증기로 부풀린 제품을 말하며, 가정에서 발생하는 대부분의 발포합성수지는 EPS(스티로폼) 제품입니다. · 발포합성수지 제품은 수거 후 재활용업체에서 분쇄, 감용과정을 거쳐 잉고트를 생산하', '["깨끗한 과일포장재(스티로폼)은 스티로폼수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=126', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 과일, 축산물 등을 담은 스티로폼 포장재는 생산자책임재활용제도(EPR) 대상 품목에 해당되어 재활용이 가능합니다. · 발포합성수지는 PP, PE, PS 등의 합성수지를 증기로 부풀린 제품을 말하며, 가정에서 발생하는 대부분의 발포합성수지는 EPS(스티로폼) 제품입니다. · 발포합성수지 제품은 수거 후 재활용업체에서 분쇄, 감용과정을 거쳐 잉고트를 생산하며 이후 제조업체로 이송하여 액자 또...', '· 택배송장, 테이프 등 이물질 제거후 배출', '2026-05-18', 0, '["재활용폐기물", "발포합성수지(스티로폼 등)"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('가정에서 발생하', '가정에서 발생하', 'styrofoam', '· 일반 발포합성수지와 성상이 유사하며 가정에서 소량 발생한 경우에는 스티로품 수거함으로 배출합니다. · 산업현장에서 발생하는 단열스티로폼은 전문 처리업체에 위탁하여 처리합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재', '["가정에서 발생하는 단열스티로폼은 스티로폼수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=127', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 일반 발포합성수지와 성상이 유사하며 가정에서 소량 발생한 경우에는 스티로품 수거함으로 배출합니다. · 산업현장에서 발생하는 단열스티로폼은 전문 처리업체에 위탁하여 처리합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다....', '', '2026-05-18', 0, '["재활용폐기물", "발포합성수지(스티로폼 등)"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('그물 무늬 스티로폼 용기', '그물 무늬 스티로폼 용기', 'styrofoam', '· 수산물, 축산물 등을 담은 스티로폼 포장재는 생산자책임재활용제도(EPR) 대상 품목에 해당되어 재활용이 가능합니다. · 스티로폼 용기는 색상, 무늬와 상관없이 스티로폼 수거함으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확', '["그물 무늬 스티로폼 용기는 스티로폼수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=128', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 수산물, 축산물 등을 담은 스티로폼 포장재는 생산자책임재활용제도(EPR) 대상 품목에 해당되어 재활용이 가능합니다. · 스티로폼 용기는 색상, 무늬와 상관없이 스티로폼 수거함으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출...', '', '2026-05-18', 0, '["재활용폐기물", "발포합성수지(스티로폼 등)"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('빈용기보증금 대상 음료수병', '빈용기보증금 대상 음료수병', 'glass', '· 우리나라는 지난 1985년부터 빈용기에 재사용을 활성화하기 위하여 소주병, 맥주병, 청량음료병(ex. 콜라, 사이다 등)에 대하여 보증금을 부과하고 있습니다. · 소비자는 제품을 구매할 때 일정 금액의 보증금을 납부하며 이후 사용한 빈용기를 소매점 등 빈용기반환수집소 또는 무인회수기에 반환하여 보증금을 환급하시기 바랍니다. · 이때, 용기가 깨지거나 참', '["빈용기보증금 대상 음료수병은 가까운 빈용기반환수집소 및 무인회수기에 반환하여 보증금을 환급받으시거나 유리병 수거함에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=129', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 우리나라는 지난 1985년부터 빈용기에 재사용을 활성화하기 위하여 소주병, 맥주병, 청량음료병(ex. 콜라, 사이다 등)에 대하여 보증금을 부과하고 있습니다. · 소비자는 제품을 구매할 때 일정 금액의 보증금을 납부하며 이후 사용한 빈용기를 소매점 등 빈용기반환수집소 또는 무인회수기에 반환하여 보증금을 환급하시기 바랍니다. · 이때, 용기가 깨지거나 참기름, 담뱃재, 곰팡이 등으로 인하여...', '', '2026-05-18', 0, '["재활용폐기물", "유리병", "빈용기보증금 대상 유리병"]');
