INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 기름병', '깨끗한 기름병', 'glass', '· 기름병은 깨끗이 씻어서 배출하면 재활용이 가능합니다. · 최대한 헹구어 기름이 제거된 경우에는 깨지지 않도록 주의하여 유리병류로 배출합니다. · 만약 기름이 남아 있는 상태로 배출하면 다른 재활용품까지도 오염되기 때문에 기름이 제거되지 않는다면 일반 종량제봉투 또는 불연성 특수마대에 배출합니다.', '["깨끗한 기름병은 유리병 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=131', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 기름병은 깨끗이 씻어서 배출하면 재활용이 가능합니다. · 최대한 헹구어 기름이 제거된 경우에는 깨지지 않도록 주의하여 유리병류로 배출합니다. · 만약 기름이 남아 있는 상태로 배출하면 다른 재활용품까지도 오염되기 때문에 기름이 제거되지 않는다면 일반 종량제봉투 또는 불연성 특수마대에 배출합니다.', '· 남은 기름은 베이킹소다를 넣고 따뜻한 물로 헹구면 깨끗하게 씻겨집니다.', '2026-05-18', 0, '["재활용폐기물", "유리병"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 소스병', '깨끗한 소스병', 'glass', '· 소스병의 용기는 내용물을 비우고 물 등으로 헹군 뒤 깨지지 않도록 주의하여 유리병류로 배출합니다. · 유리병의 뚜껑은 재활용 과정에서 분리하여 고철로 모아 재활용하게 되기 때문에 제거하지 않고 배출하셔도 됩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까', '["깨끗한 소스병은 유리병 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=132', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 소스병의 용기는 내용물을 비우고 물 등으로 헹군 뒤 깨지지 않도록 주의하여 유리병류로 배출합니다. · 유리병의 뚜껑은 재활용 과정에서 분리하여 고철로 모아 재활용하게 되기 때문에 제거하지 않고 배출하셔도 됩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현...', '', '2026-05-18', 0, '["재활용폐기물", "유리병"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 드링크병', '깨끗한 드링크병', 'glass', '· 드링크병은 내용물을 비우고 물 등으로 헹군 뒤 깨지지 않도록 주의하여 유리병류로 배출합니다. · 유리병의 뚜껑은 재활용 과정에서 분리하여 고철로 모아 재활용하게 되기 때문에 제거하지 않고 배출하셔도 됩니다. · 유리병은 3색(무색, 녹색, 갈색) 등으로 분류한 후 파쇄, 분쇄, 용융과정을 거쳐 재활용하고 있으므로 색상구분 없이 배출합니다. ※ 배출방법은', '["깨끗한 드링크병은 유리병 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=133', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 드링크병은 내용물을 비우고 물 등으로 헹군 뒤 깨지지 않도록 주의하여 유리병류로 배출합니다. · 유리병의 뚜껑은 재활용 과정에서 분리하여 고철로 모아 재활용하게 되기 때문에 제거하지 않고 배출하셔도 됩니다. · 유리병은 3색(무색, 녹색, 갈색) 등으로 분류한 후 파쇄, 분쇄, 용융과정을 거쳐 재활용하고 있으므로 색상구분 없이 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니,...', '', '2026-05-18', 0, '["재활용폐기물", "유리병"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('향수병', '향수병', 'glass', '· 내용물을 모두 사용한 향수병은 물로 헹구는 등 이물질을 제거한 후 유리병수거함으로 배출합니다. · 소량의 내용물이 남아 있는 경우에는 내용물을 휴지 등으로 흡수시킨 후 종량제봉투로 배출합니다. · 향수병의 뚜껑은 고철, 플라스틱 등 다양한 재질로 이루어진 복합재질로 재활용이 어려우므로 제거한 후 배출합니다.', '["향수병은 유리병 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=134', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 내용물을 모두 사용한 향수병은 물로 헹구는 등 이물질을 제거한 후 유리병수거함으로 배출합니다. · 소량의 내용물이 남아 있는 경우에는 내용물을 휴지 등으로 흡수시킨 후 종량제봉투로 배출합니다. · 향수병의 뚜껑은 고철, 플라스틱 등 다양한 재질로 이루어진 복합재질로 재활용이 어려우므로 제거한 후 배출합니다.', '· 뚜껑, 내용물을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "유리병"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('다 쓴 속눈썹영양제 용기', '다 쓴 속눈썹영양제 용기', 'general', '· 속눈썹 영양제, 마스카라 등의 화장품(내용물)은 재활용이 어렵습니다. · 내용물을 모두 사용한 화장품 용기는 EPR 대상에 해당하므로 물로 헹구는 등 이물질을 제거한 후 재질에 따라 플라스틱이나 유리로 배출합니다. · 화장품의 내용물이 남아 있어서 제거하기 곤란한 경우에는 종량제봉투에 배출합니다.', '["다 쓴 속눈썹영양제 용기는 재질에 따라 유리병 수거함 또는 플라스틱 수거함으로 배출합니다.", "용기의 내용물 제거가 어려운 경우 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=135', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 속눈썹 영양제, 마스카라 등의 화장품(내용물)은 재활용이 어렵습니다. · 내용물을 모두 사용한 화장품 용기는 EPR 대상에 해당하므로 물로 헹구는 등 이물질을 제거한 후 재질에 따라 플라스틱이나 유리로 배출합니다. · 화장품의 내용물이 남아 있어서 제거하기 곤란한 경우에는 종량제봉투에 배출합니다.', '· 내용물을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "유리병", "일반폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('광택제', '광택제', 'hazardous', '· 폐광택제는 제품에 포함된 유해물질로 인하여 폐기물관리법 시행규칙 및 환경부 고시로 정하고 있는 생활계유해폐기물에 해당됩니다. * 생활계유해폐기물이란 폐농약, 폐의약품 등 인간의 건광과 주변환경에 피해를 유발할 수 있는 폐기물을 말합니다. · 광택제는 고철재질의 스프레이 용기와 플라스틱의 스프레이 용기가 있습니다. · 고철재질의 스프레이 용기는 구멍을 뚫', '["광택제는 파손으로 인하여 내용물이 유출되지 않도록 밀봉한 후 전용수거함으로 배출합니다.", "용기가 완전히 밀봉되지 않아 외부로 유출될 우려가 있는 경우에는 더 큰 용기(비닐, 플라스틱 용기 등)에 담아 배출합니다.", "인근에 전용수거함이 없는 경우에는 용기를 밀봉한 후 종량제봉투 등 지자체 조례에 따라 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=138', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 폐광택제는 제품에 포함된 유해물질로 인하여 폐기물관리법 시행규칙 및 환경부 고시로 정하고 있는 생활계유해폐기물에 해당됩니다. * 생활계유해폐기물이란 폐농약, 폐의약품 등 인간의 건광과 주변환경에 피해를 유발할 수 있는 폐기물을 말합니다. · 광택제는 고철재질의 스프레이 용기와 플라스틱의 스프레이 용기가 있습니다. · 고철재질의 스프레이 용기는 구멍을 뚫지 않고 배출합니다.', '· 내용물이 남아있는 경우 외부로 유출되지 않도록 완전히 밀봉한 후 배출', '2026-05-18', 0, '["생활계 유해폐기물", "폐페인트, 폐광택제, 폐접착제"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('라돈', '라돈', 'hazardous', '· 라돈이 검출된 침대는 생활주변방사선 안전관리법의 안전기준에 부적합한 침대 및 침구류로 천연방사선제품 생활폐기물에 해당됩니다. * 천연방사선제품 생활폐기물이란 생활주변방사선 안전관리법에 따른 가공제품 중 같은법 제15조제1항에 따른 안전기준에 적합하지 않은 제품으로서 방사능 농도가 그램당 10베크렐 미만인 폐기물을 말합니다. · 라돈은 기체 상태의 방사성', '["라돈이 검출된 침대는 전문기관 또는 지자체에 상담하여 배출합니다.", "지자체에서 처리하는 경우 신고 후 방진마스크를 착용하고 유해물질이 비산, 유출되지 않도록 폐기물 전체를 비닐로 완전하게 포장하여 지정된 장소에 배출합니다.", "국내 사업자가 존재할 경우 업체에 수거요청합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=139', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 라돈이 검출된 침대는 생활주변방사선 안전관리법의 안전기준에 부적합한 침대 및 침구류로 천연방사선제품 생활폐기물에 해당됩니다. * 천연방사선제품 생활폐기물이란 생활주변방사선 안전관리법에 따른 가공제품 중 같은법 제15조제1항에 따른 안전기준에 적합하지 않은 제품으로서 방사능 농도가 그램당 10베크렐 미만인 폐기물을 말합니다. · 라돈은 기체 상태의 방사성 물질로 세계보건기구(WHO)에서는...', '· 천연방사성 제품 폐기물로 의심되는 제품은 한국 원자력안전기술원 생활주변방사선 정보서비스 및 생활방사선기술지원센터(1811-8336)를 통해 라독측정기 우편대여서비스를 이용하거나 지자체로부터 라돈측정기를 대여하여 확인', '2026-05-18', 0, '["생활계 유해폐기물", "천연방사성제품"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('페인트', '페인트', 'hazardous', '· 페인트는 제품을 보호하고 외관을 장식하기 위하여 제작된 제품으로 액상 또는 분말형태가 있습니다. · 폐페인트는 제품에 포함된 유해물질로 인하여 폐기물관리법 시행규칙 및 환경부 고시로 정하고 있는 생활계유해폐기물에 해당됩니다. * 생활계유해폐기물이란 폐농약, 폐의약품 등 인간의 건강과 주변환경에 피해를 유발할 수 있는 폐기물을 말합니다. · 가정에서 배출', '["페인트는 파손으로 인하여 내용물이 유출되지 않도록 밀봉한 후 전용수거함으로 배출합니다.", "용기가 완전히 밀봉되지 않아 외부로 유출될 우려가 있는 경우에는 더 큰 용기(비닐, 플라스틱 용기 등)에 담아 배출합니다.", "인근에 전용수거함이 없는 경우에는 용기를 밀봉한 후 종량제봉투 등 지자체 조례에 따라 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=140', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 페인트는 제품을 보호하고 외관을 장식하기 위하여 제작된 제품으로 액상 또는 분말형태가 있습니다. · 폐페인트는 제품에 포함된 유해물질로 인하여 폐기물관리법 시행규칙 및 환경부 고시로 정하고 있는 생활계유해폐기물에 해당됩니다. * 생활계유해폐기물이란 폐농약, 폐의약품 등 인간의 건강과 주변환경에 피해를 유발할 수 있는 폐기물을 말합니다. · 가정에서 배출하는 페인트는 생활계 유해폐기물에 해...', '· 내용물이 남아있는 경우 외부로 유출되지 않도록 완전히 밀봉한 후 배출', '2026-05-18', 0, '["생활계 유해폐기물", "폐페인트, 폐광택제, 폐접착제"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('감기약', '감기약', 'medicine', '· 가정에서 배출하는 의약품은 약국에서 판매하는 해열제, 감기약 등의 상비약과 의사의 처방이 필요한 전문의약품으로 구분됩니다. · 그 밖에 치약, 가글, 살충제 등 인체에 약하거나 직접적으로 작용하지 않는 의약외품이 있습니다. · 의약품과 의약외품을 구분하는 방법은 처방여부, 포장재 겉면에 표기된 문구를 통해 확인하실 수 있습니다. · 가정에서 배출하는 의', '["감기약은 폐의약품수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=141', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 배출하는 의약품은 약국에서 판매하는 해열제, 감기약 등의 상비약과 의사의 처방이 필요한 전문의약품으로 구분됩니다. · 그 밖에 치약, 가글, 살충제 등 인체에 약하거나 직접적으로 작용하지 않는 의약외품이 있습니다. · 의약품과 의약외품을 구분하는 방법은 처방여부, 포장재 겉면에 표기된 문구를 통해 확인하실 수 있습니다. · 가정에서 배출하는 의약품은 가까운 약국이나 보건소, 주민...', '· 병원에서 조제한 약은 반드시 폐의약품전용수거함으로 배출', '2026-05-18', 0, '["생활계 유해폐기물", "폐의약품"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('나잘스프레이', '나잘스프레이', 'medicine', '· 가정에서 배출하는 의약품은 약국에서 판매하는 해열제, 감기약 등의 상비약과 의사의 처방이 필요한 전문의약품으로 구분됩니다. · 그 밖에 치약, 가글, 살충제 등 인체에 약하거나 직접적으로 작용하지 않는 의약외품이 있습니다. · 의약품과 의약외품을 구분하는 방법은 처방여부, 포장재 겉면에 표기된 문구를 통해 확인하실 수 있습니다. · 가정에서 배출하는 의', '["나잘스프레이는 폐의약품수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=142', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 배출하는 의약품은 약국에서 판매하는 해열제, 감기약 등의 상비약과 의사의 처방이 필요한 전문의약품으로 구분됩니다. · 그 밖에 치약, 가글, 살충제 등 인체에 약하거나 직접적으로 작용하지 않는 의약외품이 있습니다. · 의약품과 의약외품을 구분하는 방법은 처방여부, 포장재 겉면에 표기된 문구를 통해 확인하실 수 있습니다. · 가정에서 배출하는 의약품은 가까운 약국이나 보건소, 주민...', '· 병원에서 조제한 약은 반드시 폐의약품전용수거함으로 배출', '2026-05-18', 0, '["생활계 유해폐기물", "폐의약품"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('엔진 오일', '엔진 오일', 'general', '· 엔진오일, 베어링 오일 등의 폐유는 누출 시 신체에 화상을 입힐 수 있으며, 화재 및 환경오염의 위험성이 있어 주의하여 배출하여야 합니다. · 가정에서 배출하는 차량용품은 전용수거함으로 배출하거나 구입처 또는 자동차 정비소를 통해 역회수 처리할 수 있습니다.', '["엔진 오일은 전용수거함으로 배출하거나 자동차 정비소 등역회수 루트를 통하여 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=144', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 엔진오일, 베어링 오일 등의 폐유는 누출 시 신체에 화상을 입힐 수 있으며, 화재 및 환경오염의 위험성이 있어 주의하여 배출하여야 합니다. · 가정에서 배출하는 차량용품은 전용수거함으로 배출하거나 구입처 또는 자동차 정비소를 통해 역회수 처리할 수 있습니다.', '· 내용물이 남아있는 경우 외부로 유출되지 않도록 완전히 밀봉한 후 배출', '2026-05-18', 0, '["생활계 유해폐기물", "기타"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('폐농약', '폐농약', 'hazardous', '· 폐농약은 농작을 해치는 균, 곤충, 잡초 등을 제거하기 위해 사용하는 약품으로 살균제, 살충제, 제초제 등이 있습니다. · 폐농약은 제품에 포함된 유해물질로 인하여 폐기물관리법 시행규칙 및 환경부 고시로 정하고 있는 생활계유해폐기물에 해당됩니다. * 생활계유해폐기물이란 폐농약, 폐의약품 등 인간의 건광과 주변환경에 피해를 유발할 수 있는 폐기물을 말합니', '["폐농약은 전용수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=145', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 폐농약은 농작을 해치는 균, 곤충, 잡초 등을 제거하기 위해 사용하는 약품으로 살균제, 살충제, 제초제 등이 있습니다. · 폐농약은 제품에 포함된 유해물질로 인하여 폐기물관리법 시행규칙 및 환경부 고시로 정하고 있는 생활계유해폐기물에 해당됩니다. * 생활계유해폐기물이란 폐농약, 폐의약품 등 인간의 건광과 주변환경에 피해를 유발할 수 있는 폐기물을 말합니다. · 폐농약은 잔류농약이 담긴 용...', '·내용물이 남아있는 경우 외부로 유출되지 않도록 완전히 밀봉한 후 배출', '2026-05-18', 0, '["생활계 유해폐기물", "폐농약"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('연고', '연고', 'medicine', '· 포장재 겉면에 의약품으로 표기된 연고는 가까운 약국이나 보건소, 주민센터 등에 비치된 폐의약품전용수거함으로 배출합니다. · 의약품의 경우(물약 제외) 일부 지자체에 한하여 우정산업본부와 사전협의를 통해 우체통으로 배출하는 경우도 있습니다. · 의약외품인 연고 경우 종량제봉투로 배출하여 주시면 됩니다.', '["연고는 폐의약품수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=146', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 제품 포장재 의약품/의약외품 확인후 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('알약', '알약', 'medicine', '· 포장재 겉면에 의약품으로 표기된 알약은 가까운 약국이나 보건소, 주민센터 등에 비치된 폐의약품전용수거함으로 배출합니다. · 의약품의 경우(물약 제외) 일부 지자체에 한하여 우정산업본부와 사전협의를 통해 우체통으로 배출하는 경우도 있습니다.', '["알약은 폐의약품수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=147', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 제품 포장재 의약품/의약외품 확인후 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('한약', '한약', 'medicine', '· 한약은 의약품에 해당하여 가까운 약국이나 보건소, 주민센터 등에 비치된 폐의약품전용수거함으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요.', '["한약은 폐의약품수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=148', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 한약은 의약품에 해당하여 가까운 약국이나 보건소, 주민센터 등에 비치된 폐의약품전용수거함으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도...', '', '2026-05-18', 0, '["생활계 유해폐기물", "폐의약품"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('물약', '물약', 'medicine', '· 포장재 겉면에 의약품으로 표기된 물약은 가까운 약국이나 보건소, 주민센터 등에 비치된 폐의약품전용수거함으로 배출합니다. · 의약품의 경우(물약 제외) 일부 지자체에 한하여 우정산업본부와 사전협의를 통해 우체통으로 배출하는 경우도 있습니다. 물약은 새서 다른 우편물이 훼손될 우려가 있기 때문에 우체통을 통한 배출이 불가합니다.', '["물약은 폐의약품수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=149', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 제품 포장재 의약품/의약외품 확인후 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('가정에서 배출하', '가정에서 배출하', 'food', '· 고추장, 된장 등 장류는 가정에서 소량으로 발생하므로 음식물류폐기물로 배출합니다. · 내용물(고추장, 된장 등) 제거가 어려운 경우에는 뚜껑을 닫아 제품 그대로 종량제봉투로 배출하여 주시기 바랍니다.', '["가정에서 배출하는 고추장은 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=156', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 염분이 높은 젓갈, 된장, 김치 등은 가정에서 소량으로 배출하고 있어 음식물류폐기물로 배출하셔도 괜찮습니다. · 반면, 제조공장, 식당 등에서 다량으로 배출하...', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('매실주 건더기', '매실주 건더기', 'food', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 담금주에 사용한 과일, 채소, 약초 등 건더기는 음식물류폐기물로 배출하셔도 괜찮습니다.', '["매실주 건더기는 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=158', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 담금주에 사용한 과일, 채소, 약초 등 건더기는 음식물류폐기물로 배출하셔도 괜찮습니다.', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
