INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('상한 음식', '상한 음식', 'food', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 사료화는 파쇄선별-탈수-건조/살균-분쇄-사료생산 과정을 거쳐 재활용하고 있습니다. · 살균과정은 농림축산식품부의 사료 기준', '["상한 음식은 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=164', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 사료화는 파쇄선별-탈수-건조/살균-분쇄-사료생산 과정을 거쳐 재활용하고 있습니다. · 살균과정은 농림축산식품부의 사료 기준에 따라 100℃에서 30분 이상 가...', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('고등어', '고등어', 'food', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 고등어는 우럭, 갈치 등과 같은 생선의 일종으로 음식물류폐기물로 배출합니다.', '["고등어는 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=165', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 고등어는 우럭, 갈치 등과 같은 생선의 일종으로 음식물류폐기물로 배출합니다.', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('시리얼', '시리얼', 'food', '· 시리얼은 조리되거나 가공된 곡류로 음식물류폐기물이므로 음식물류폐기물로 배출합니다.', '["시리얼은 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=166', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 시리얼은 조리되거나 가공된 곡류로 음식물류폐기물이므로 음식물류폐기물로 배출합니다.', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('밀가루', '밀가루', 'food', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 밀가루, 부침가루 등 곡물 가루는 음식물류폐기물로 배출합니다.', '["밀가루는 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=167', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 밀가루, 부침가루 등 곡물 가루는 음식물류폐기물로 배출합니다.', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('어성초 가루', '어성초 가루', 'food', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 어성초, 감초 등 약초가루는 기타가공품으로 원료를 제조·가공한 식품으로 음식물류폐기물로 배출합니다.', '["어성초 가루는 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=168', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 어성초, 감초 등 약초가루는 기타가공품으로 원료를 제조·가공한 식품으로 음식물류폐기물로 배출합니다.', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('마요네즈', '마요네즈', 'food', '· 마요네즈, 케찹 등 소스(내용물)는 가정에서 소량으로 발생하므로 음식물류폐기물로 배출합니다.', '["마요네즈는 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=169', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 마요네즈, 케찹 등 소스(내용물)는 가정에서 소량으로 발생하므로 음식물류폐기물로 배출합니다.', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('라면스프', '라면스프', 'food', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 라면 스프(분말스프, 건더기스프)는 가정에서 소량으로 발생하므로 스프의 내용물은 음식물류폐기물로 배출하며, 라면 스프 봉지', '["라면스프는 음식물폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=172', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 라면 스프(분말스프, 건더기스프)는 가정에서 소량으로 발생하므로 스프의 내용물은 음식물류폐기물로 배출하며, 라면 스프 봉지는 비닐류로 배출합니다.', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('분유가루', '분유가루', 'food', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 분유가루는 우유를 분말로 만든 유가공품으로 음식물류폐기물로 배출합니다.', '["분유가루는 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=173', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 분유가루는 우유를 분말로 만든 유가공품으로 음식물류폐기물로 배출합니다.', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('엿기름', '엿기름', 'food', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 식혜의 주재료인 엿기름은 보리 씨를 발아시켜 만든 식품으로 음식물류폐기물로 배출합니다.', '["엿기름은 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=174', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 식혜의 주재료인 엿기름은 보리 씨를 발아시켜 만든 식품으로 음식물류폐기물로 배출합니다.', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('빈 농약용기', '빈 농약용기', 'general', '· 영농 후 배출되는 폐비닐과 농약 빈용기는 영농폐기물에 해당됩니다. · 한국환경공단에서는 농촌 환경오염의 주요 요인으로 꼽히는 영농폐비닐과 농약용기를 수거하여 재활용하는 사업을 운영하고 있습니다. · 농가에서는 영농 후 발생하는 빈 농약용기는 마을 내 지정된 장소에 재질별(유리병, 플라스틱, 비닐, 종이)로 구분하여 배출한 후 수거보상금을 받을 수 있습니', '["빈 농약용기는 지정된 장소로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=175', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 영농 후 배출되는 폐비닐과 농약 빈용기는 영농폐기물에 해당됩니다. · 한국환경공단에서는 농촌 환경오염의 주요 요인으로 꼽히는 영농폐비닐과 농약용기를 수거하여 재활용하는 사업을 운영하고 있습니다. · 농가에서는 영농 후 발생하는 빈 농약용기는 마을 내 지정된 장소에 재질별(유리병, 플라스틱, 비닐, 종이)로 구분하여 배출한 후 수거보상금을 받을 수 있습니다. 이후 수거한 폐기물은 자체 재활...', '· 농약을 완전히 사용한 후 배출', '2026-05-18', 0, '["기타"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('영농폐비닐', '영농폐비닐', 'general', '· 영농 후 배출되는 폐비닐과 농약 빈용기는 영농폐기물에 해당됩니다. · 한국환경공단에서는 농촌 환경오염의 주요 요인으로 꼽히는 영농폐비닐과 농약용기를 수거하여 재활용하는 사업을 운영하고 있습니다. · 농가에서는 영농 후 발생하는 폐비닐은 마을내 지정된 장소에 재질별(하우스, 멀칭로덴, 하이덴), 색상별(흰색, 검정색)로 구분하여 배출한 후 수거보상금을 받', '["영농폐비닐은 지정된 장소로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=176', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 영농 후 배출되는 폐비닐과 농약 빈용기는 영농폐기물에 해당됩니다. · 한국환경공단에서는 농촌 환경오염의 주요 요인으로 꼽히는 영농폐비닐과 농약용기를 수거하여 재활용하는 사업을 운영하고 있습니다. · 농가에서는 영농 후 발생하는 폐비닐은 마을내 지정된 장소에 재질별(하우스, 멀칭로덴, 하이덴), 색상별(흰색, 검정색)로 구분하여 배출한 후 수거보상금을 받을 수 있습니다. 이후 수거한 폐기물...', '· 이물질(흙, 돌, 잡초 등) 제거 후 배출', '2026-05-18', 0, '["기타"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('연탄재', '연탄재', 'general', '· 연탄은 무연탄을 활용하여 만든 연료로 과거 가정에서 많이 사용하였으나 최근 도시가스, 보일러의 발전으로 사용하는 추세가 많이 줄어들고 있습니다. · 가정에서 발생된 연탄재는 지자체에서 지정된 수거일 및 장소에 배출하면 지자체에서 무상으로 수거하고 있습니다. · 화훼 농가 등 사업활동에서 수반되어 다량 발생되는 연탄재는 지자체에 따라 조례로 정하여 수수료', '["연탄재는 지자체 조례에서 정하는 배출방법에 따라 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=177', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 연탄은 무연탄을 활용하여 만든 연료로 과거 가정에서 많이 사용하였으나 최근 도시가스, 보일러의 발전으로 사용하는 추세가 많이 줄어들고 있습니다. · 가정에서 발생된 연탄재는 지자체에서 지정된 수거일 및 장소에 배출하면 지자체에서 무상으로 수거하고 있습니다. · 화훼 농가 등 사업활동에서 수반되어 다량 발생되는 연탄재는 지자체에 따라 조례로 정하여 수수료를 부과하거나 사업장폐기물로 처리됩니...', '해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["기타"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('식용유', '식용유', 'general', '· 식물성 기름(참기름, 들기름 등)은 바이오디젤로 재활용이 가능합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도', '["식용유는 폐식용유 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=178', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 식물성 기름(참기름, 들기름 등)은 바이오디젤로 재활용이 가능합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분리배출 장소...', '', '2026-05-18', 0, '["기타"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('젤아이스팩', '젤아이스팩', 'general', '· 아이스팩은 냉매가 물인 아이스팩과 고흡수성수지(SAP)인 젤아이스팩이 있습니다. · 젤아이스팩은 아이스팩 그대로 전용수거함 또는 종량제봉투로 배출합니다. · 물아이스팩은 내용물은 하수구를 통해 배출하고, 포장용기는 비닐류로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배', '["젤아이스팩은 아이스팩수거함으로 배출합니다.", "물아이스팩은 내용물 제거후 포장용기는 비닐류로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=179', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 아이스팩은 냉매가 물인 아이스팩과 고흡수성수지(SAP)인 젤아이스팩이 있습니다. · 젤아이스팩은 아이스팩 그대로 전용수거함 또는 종량제봉투로 배출합니다. · 물아이스팩은 내용물은 하수구를 통해 배출하고, 포장용기는 비닐류로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출...', '', '2026-05-18', 0, '["기타"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('타이어', '타이어', 'general', '· 가정에서 배출하는 타이어는 자동차 정비소나 타이어 판매소 등에 배출합니다. · 역회수 처리가 어려운 경우에는 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처', '["타이어는 자동차 정비소, 타이어 판매소를 통해 역회수 처리하거나 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=180', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 배출하는 타이어는 자동차 정비소나 타이어 판매소 등에 배출합니다. · 역회수 처리가 어려운 경우에는 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위...', '', '2026-05-18', 0, '["기타"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('수납장(목재재질)', '수납장(목재재질)', 'furniture', '· 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리되어 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다. · 상태가 좋아 다른 사람이 사용할 수 있는 폐가구는 재활용센터에 판매할 수 있으며, 업체에 따라 무상으로 수거하는 경우도 있습니다. 폐가구를 배출하시기 전 가까운 재활용센터에 문의하여 주시기', '["수납장(목재재질)은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=181', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리되어 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다. · 상태가 좋아 다른 사람이 사용할 수 있는 폐가구는 재활용센터에 판매할 수 있으며, 업체에 따라 무상으로 수거하는 경우도 있습니다. 폐가구를 배출하시기 전 가까운 재활용센터에 문의하여 주시기 바랍니다.', '· 재사용 가능여부에 따라 재활용센터로 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('리빙박스(플라스틱 재질)', '리빙박스(플라스틱 재질)', 'furniture', '· 리빙박스가 플라스틱 단일재질인 경우에는 플라스틱으로 배출하면 재활용이 가능합니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수료에 준하여 책정하고 있습니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된', '["리빙박스(플라스틱 재질)은 플라스틱 수거함으로 배출합니다.", "크기가 커 수거함으로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=182', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 리빙박스가 플라스틱 단일재질인 경우에는 플라스틱으로 배출하면 재활용이 가능합니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수료에 준하여 책정하고 있습니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스...', '· 크기가 큰 플라스틱 제품은 합성수지 재질이어도 대형폐기물로 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('매트리스', '매트리스', 'furniture', '· 매트리스와 같은 침구류는 재활용이 어려워 대형폐기물로 수거한 후 소각됩니다.', '["매트리스는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=183', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 매트리스는 부피, 크기가 커 배출하실 때에는 보행자에게 불편을 주지 않도록 주의하여 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('비닐 장판', '비닐 장판', 'general', '· 주로 가정에서 배출하는 비닐장판은 PVC(폴리염화비닐) 재질입니다. · 폴리염화비닐은 다른 플라스틱 제품과 혼합되어 재활용될 경우 재활용제품의 강도가 떨어지고 재활용과정에서 염화수소와 같은 유해화학물질이 발생하는 등 다양한 문제를 일으키고 있습니다. · 따라서 일반 비닐과 함께 배출하면 안됩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지', '["비닐 장판은 대형폐기물로 배출합니다.", "조각형태로 배출하는 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=184', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 주로 가정에서 배출하는 비닐장판은 PVC(폴리염화비닐) 재질입니다. · 폴리염화비닐은 다른 플라스틱 제품과 혼합되어 재활용될 경우 재활용제품의 강도가 떨어지고 재활용과정에서 염화수소와 같은 유해화학물질이 발생하는 등 다양한 문제를 일으키고 있습니다. · 따라서 일반 비닐과 함께 배출하면 안됩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경...', '', '2026-05-18', 0, '["대형폐기물", "공사장 생활폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('마루', '마루', 'general', '· 가정에서 사용하는 마루는 합판 또는 HDF 목재을 가공하여 만든 제품입니다. · 목재제품은 재활용이 어려워 종량제봉투 또는 대형폐기물로 배출해야 합니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. · 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱, 전자제품 등으로 선별한 후 처리업체로 이송되어 처리하', '["마루는 종량제봉투로 배출합니다.", "크기, 부피가 큰 마루는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=185', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 사용하는 마루는 합판 또는 HDF 목재을 가공하여 만든 제품입니다. · 목재제품은 재활용이 어려워 종량제봉투 또는 대형폐기물로 배출해야 합니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. · 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱, 전자제품 등으로 선별한 후 처리업체로 이송되어 처리하고 있습니다.', '· 끈으로 묶어서 부피를 최대한 줄여서 배출', '2026-05-18', 0, '["대형폐기물", "공사장 생활폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('수납장(플라스틱 재질)', '수납장(플라스틱 재질)', 'furniture', '·단일재질의 플라스틱 용기 또는 제품은 플라스틱수거함으로 배출하면 선별장으로 이송되어 재질별(PE, PP, PET, PS)로 선별하고 있습니다. 이후 선별된 제품은 재질별로 전문 재활용업체로 운반되어 재활용하고 있습니다. · 크기가 큰 플라스틱 제품은 수거한 후 재활용 선별장에서 선별하기가 곤란하여 소각하거나 전문 재활용업체로 위탁하여 처리하고 있습니다.', '["수납장(플라스틱 재질)은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=186', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·단일재질의 플라스틱 용기 또는 제품은 플라스틱수거함으로 배출하면 선별장으로 이송되어 재질별(PE, PP, PET, PS)로 선별하고 있습니다. 이후 선별된 제품은 재질별로 전문 재활용업체로 운반되어 재활용하고 있습니다. · 크기가 큰 플라스틱 제품은 수거한 후 재활용 선별장에서 선별하기가 곤란하여 소각하거나 전문 재활용업체로 위탁하여 처리하고 있습니다.', '· 크기가 큰 플라스틱 제품은 합성수지 재질이어도 대형폐기물로 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('쌀통', '쌀통', 'furniture', '· 단일재질의 플라스틱 용기 또는 제품은 플라스틱수거함으로 배출하면 선별장으로 이송되어 재질별(PE, PP, PET, PS)로 선별하고 있습니다. 이후 선별된 제품은 재질별로 전문 재활용업체로 운반되어 재활용하고 있습니다. · 크기가 큰 플라스틱 제품은 수거한 후 재활용 선별장에서 선별하기가 곤란하여 소각하거나 전문 재활용업체로 위탁하여 처리하고 있습니다.', '["쌀통은 플라스틱수거함으로 배출합니다.", "크기, 부피가 큰 플라스틱 제품은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=187', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 단일재질의 플라스틱 용기 또는 제품은 플라스틱수거함으로 배출하면 선별장으로 이송되어 재질별(PE, PP, PET, PS)로 선별하고 있습니다. 이후 선별된 제품은 재질별로 전문 재활용업체로 운반되어 재활용하고 있습니다. · 크기가 큰 플라스틱 제품은 수거한 후 재활용 선별장에서 선별하기가 곤란하여 소각하거나 전문 재활용업체로 위탁하여 처리하고 있습니다.', '· 내용물을 비운 후 전용수거함으로 배출 · 크기가 큰 플라스틱 제품은 합성수지 재질이어도 대형폐기물로 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "PET, PP, PS, PE, OTHER", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('소파', '소파', 'furniture', '· 소파는 목재, 가죽, 섬유, 합성수지 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 복합재질 제품은 재활용이 어려우며, 해당 제품은 크기가 커 대형폐기물로 배출합니다. · 대형폐기물로 배출한 가구는 지자체에서 수거한 후 소각 또는 에너지재활용업체에 위탁하여 처리합니다.', '["소파는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=188', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 소파는 목재, 가죽, 섬유, 합성수지 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 복합재질 제품은 재활용이 어려우며, 해당 제품은 크기가 커 대형폐기물로 배출합니다. · 대형폐기물로 배출한 가구는 지자체에서 수거한 후 소각 또는 에너지재활용업체에 위탁하여 처리합니다.', '· 대형폐기물 배출 시 보행자에게 불편을 주지 않도록 주의하여 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('식탁', '식탁', 'furniture', '· 식탁은 주로 목재, 대리석 등으로 제작하고 있으며 재활용이 어렵습니다. · 복합재질 제품은 재활용이 어려우며, 해당 제품은 크기가 커 대형폐기물로 배출합니다. · 대형폐기물로 배출한 가구는 지자체에서 수거한 후 소각 또는 에너지재활용업체에 위탁하여 처리합니다.', '["식탁은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=189', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 식탁은 주로 목재, 대리석 등으로 제작하고 있으며 재활용이 어렵습니다. · 복합재질 제품은 재활용이 어려우며, 해당 제품은 크기가 커 대형폐기물로 배출합니다. · 대형폐기물로 배출한 가구는 지자체에서 수거한 후 소각 또는 에너지재활용업체에 위탁하여 처리합니다.', '· 대형폐기물 배출 시 보행자에게 불편을 주지 않도록 주의하여 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('에어매트', '에어매트', 'furniture', '· 에어매트는 PVC(폴리염화비닐) 또는 TPU(열가소성폴리우레탄)재질로 구성하고 있습니다. · 가정에서 배출하는 PVC, TPU 재질은 주로 소량으로 배출되어 재활용하기에 어려움이 있습니다. · 폴리염화비닐(PVC)은 다른 합성수지와 혼합되어 재활용될 경우 재활용제품의 강도가 떨어지고 재활용과정에서 염화수소와 같은 유해화학물질이 발생하는 등 다양한 문제를', '["에어매트는 내용물(공기)를 제거한 후 종량제봉투로 배출합니다.", "크기가 큰 에어매트는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=190', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 에어매트는 PVC(폴리염화비닐) 또는 TPU(열가소성폴리우레탄)재질로 구성하고 있습니다. · 가정에서 배출하는 PVC, TPU 재질은 주로 소량으로 배출되어 재활용하기에 어려움이 있습니다. · 폴리염화비닐(PVC)은 다른 합성수지와 혼합되어 재활용될 경우 재활용제품의 강도가 떨어지고 재활용과정에서 염화수소와 같은 유해화학물질이 발생하는 등 다양한 문제를 일으키고 있어 재활용이 어렵습니다.', '· 공기를 제거하여 최대한 부피를 줄인 후 끈으로 묶은 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('욕조', '욕조', 'general', '· 욕실에 고정된 욕조는 세라믹, 대리석, 플라스틱 재질 등으로 제작되며, 플라스틱 제품이더라도 아크릴 등의 열경화성 합성수지로 제작하고 있어 재활용이 어렵습니다. · 열경화성 합성수지란 한 번 열에 의해 모양이 만들어지면 이후 녹지않는 플라스틱을 말하며, 페놀수지, 실리콘수지, 에폭시 수지 등이 해당됩니다. · 인테리어 공사 등에서 발생한 폐기물은 불연성', '["욕조는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=191', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 욕실에 고정된 욕조는 세라믹, 대리석, 플라스틱 재질 등으로 제작되며, 플라스틱 제품이더라도 아크릴 등의 열경화성 합성수지로 제작하고 있어 재활용이 어렵습니다. · 열경화성 합성수지란 한 번 열에 의해 모양이 만들어지면 이후 녹지않는 플라스틱을 말하며, 페놀수지, 실리콘수지, 에폭시 수지 등이 해당됩니다. · 인테리어 공사 등에서 발생한 폐기물은 불연성 마대 또는 대형폐기물로 배출할 수...', '· 리모델링, 인테리어 공사 등 일련의 공사 또는 작업 등으로 전체 기간 동안 발생하는 5톤 미만의 폐기물은 공사장생활폐기물에 해당되며, 올바른 배출방법은 해당 지자체에 문의', '2026-05-18', 0, '["대형폐기물", "공사장 생활폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('이동식 욕조(플라스틱 재질)', '이동식 욕조(플라스틱 재질)', 'furniture', '· 이동식 욕조는 주로 플라스틱 단일재질로 제작하고 있으며, 플라스틱 수거함으로 배출하면 재활용이 가능합니다. · 다만, 크기가 큰 제품은 재활용폐기물로 배출하기 보다는 대형폐기물로 배출하고 있습니다. · 크기가 큰 플라스틱 제품은 수거한 후 재활용 선별장에서 선별하기가 곤란하여 소각하거나 전문 재활용업체로 위탁하여 처리하고 있습니다.', '["이동식 욕조(플라스틱 재질)은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=192', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 이동식 욕조는 주로 플라스틱 단일재질로 제작하고 있으며, 플라스틱 수거함으로 배출하면 재활용이 가능합니다. · 다만, 크기가 큰 제품은 재활용폐기물로 배출하기 보다는 대형폐기물로 배출하고 있습니다. · 크기가 큰 플라스틱 제품은 수거한 후 재활용 선별장에서 선별하기가 곤란하여 소각하거나 전문 재활용업체로 위탁하여 처리하고 있습니다.', '· 크기가 큰 플라스틱 제품은 단일재질이더라도 대형폐기물로 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('건식 반신욕기', '건식 반신욕기', 'furniture', '· 건식용 반신욕기는 전기를 사용하는 전기전자제품에 해당하나 부피가 크고 목재 등 재활용이 어려운 재질이 다량 포함하고 있어 환경성보장제도에 해당되지 않습니다.', '["건식 반신욕기는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=193', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 건식용 반신욕기는 전기를 사용하는 전기전자제품에 해당하나 부피가 크고 목재 등 재활용이 어려운 재질이 다량 포함하고 있어 환경성보장제도에 해당되지 않습니다.', '· 대형폐기물 수수료 기준표에 작성되지 않은 폐기물은 종류 및 규격 등을 감안하여 유사한 품목의 수수료를 적용하고 있으므로 정확한 배출 수수료는 해당 지자체에 문의', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('건조대', '건조대', 'can', '· 건조대는 주로 금속재질(스테인리스 재질)로 구성하고 있으며, 그 밖에 플라스틱, 목재재질이 있습니다. · 스테인리스 재질은 고철에 해당되어 재활용이 가능하나 빨래 건조대의 경우 주로 크기가 커 대형폐기물로 배출해야 합니다. · 건조대의 구성별로 분리가 가능한 경우에는 분리한 후 고철수거함으로 배출할 수 있습니다.', '["건조대는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=194', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 건조대는 주로 금속재질(스테인리스 재질)로 구성하고 있으며, 그 밖에 플라스틱, 목재재질이 있습니다. · 스테인리스 재질은 고철에 해당되어 재활용이 가능하나 빨래 건조대의 경우 주로 크기가 커 대형폐기물로 배출해야 합니다. · 건조대의 구성별로 분리가 가능한 경우에는 분리한 후 고철수거함으로 배출할 수 있습니다.', '· 건조대 재질을 확인한 후 배출', '2026-05-18', 0, '["대형폐기물", "재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('파티션', '파티션', 'general', '· 사무실, 가정에서 사용하는 파티션, 칸막이는 목재, 금속, 합성수지, 유리 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 고철재질의 파티션은 재활용이 가능하나 중량과 부피가 커 고철로 배출하기보다는 대형폐기물로 배출하여야 합니다. · 다량으로 배출할 때에는 지자체에 문의하여 공사장생활폐기물 배출방법에 준수하여 배출합니다. · 인테리어 공사 등에', '["파티션은 대형폐기물로 배출합니다.", "공사장생활폐기물로 배출하는 경우에는 지자체에 문의한 후 전문 처리업체에 연락하여 수거 및 처리합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=196', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 사무실, 가정에서 사용하는 파티션, 칸막이는 목재, 금속, 합성수지, 유리 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 고철재질의 파티션은 재활용이 가능하나 중량과 부피가 커 고철로 배출하기보다는 대형폐기물로 배출하여야 합니다. · 다량으로 배출할 때에는 지자체에 문의하여 공사장생활폐기물 배출방법에 준수하여 배출합니다. · 인테리어 공사 등에서 발생한 파티션은 대형폐기물로 배출...', '', '2026-05-18', 0, '["대형폐기물", "공사장 생활폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('침대 프레임', '침대 프레임', 'furniture', '·침대나 의자, 책상 등의 받침부분인 프레임이 철제로 되어 있어 분리가 가능한 경우에는 고철수거함에 배출하고, 중량과 부피가 큰 제품인 경우 대형폐기물로 배출하여야 합니다.', '["침대 프레임은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=197', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·침대나 의자, 책상 등의 받침부분인 프레임이 철제로 되어 있어 분리가 가능한 경우에는 고철수거함에 배출하고, 중량과 부피가 큰 제품인 경우 대형폐기물로 배출하여야 합니다.', '·크키가 큰 제품은 재질에 상관없이 대형폐기물로 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('변기커버', '변기커버', 'furniture', '· 변기커버(변좌)는 주로 PP와 같은 플라스틱으로 되어 있으며, 일부 제품은 섬유, 고무 등 다른재질이 혼합된 경우가 있습니다. · 변기커버가 플라스틱 단일재질인 경우에는 재활용이 가능합니다. 다만, 변기커버는 크기가 크며 위생상태가 좋지 못하므로 되도록 대형폐기물로 배출합니다. · 변기커버에 추가로 설치하는 섬유 또는 고무 재질의 커버는 종량제봉투로 배', '["변기커버는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=198', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 변기커버(변좌)는 주로 PP와 같은 플라스틱으로 되어 있으며, 일부 제품은 섬유, 고무 등 다른재질이 혼합된 경우가 있습니다. · 변기커버가 플라스틱 단일재질인 경우에는 재활용이 가능합니다. 다만, 변기커버는 크기가 크며 위생상태가 좋지 못하므로 되도록 대형폐기물로 배출합니다. · 변기커버에 추가로 설치하는 섬유 또는 고무 재질의 커버는 종량제봉투로 배출하여야 합니다. ※ 배출방법은 지역...', '', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('골프가방', '골프가방', 'furniture', '· 가방은 가죽, 천, 금속 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 상태가 좋은 의류 및 섬유제품은 의류수거함으로 배출할 수 있으며, 의류수거함으로 배출한 품목은 전문 업체에서 품목별로 선별한 후 국내 또는 국외로 판매하여 재사용하고 있습니다. ·다만, 골프가방과 같이 크기가 크거나 훼손이 심하여 다른 사람이 재사용하기 어려운 제품은 종량제', '["골프가방은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=199', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가방은 가죽, 천, 금속 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 상태가 좋은 의류 및 섬유제품은 의류수거함으로 배출할 수 있으며, 의류수거함으로 배출한 품목은 전문 업체에서 품목별로 선별한 후 국내 또는 국외로 판매하여 재사용하고 있습니다. ·다만, 골프가방과 같이 크기가 크거나 훼손이 심하여 다른 사람이 재사용하기 어려운 제품은 종량제봉투 또는 대형폐기물로 배출하여야 합...', '· 의류수거함에 배출 불가', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('고양', '고양', 'furniture', '· 고양이 스크래쳐는 종이(골판지), 섬유, 나무 등 다양한 재질로 제작됩니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수료에 준하여 책정하고 있습니다.', '["고양이 스크래쳐는 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=200', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 고양이 스크래쳐는 종이(골판지), 섬유, 나무 등 다양한 재질로 제작됩니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수료에 준하여 책정하고 있습니다.', '· 크기가 큰 제품은 재질에 상관없이 대형폐기물로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('그늘 천막', '그늘 천막', 'furniture', '· 가정에서 배출하는 그늘천막은 주로 PE 재질로 제작되어 재활용이 가능하나 크기가 커 재활용품으로 배출하기보단 대형폐기물로 배출하는 것이 좋습니다.', '["그늘 천막은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=201', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 배출하는 그늘천막은 주로 PE 재질로 제작되어 재활용이 가능하나 크기가 커 재활용품으로 배출하기보단 대형폐기물로 배출하는 것이 좋습니다.', '· 크기가 큰 천막을 배출할 때에는 보행자에게 불편을 주지 않도록 끈으로 묶어서 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('목검', '목검', 'furniture', '· 가정에서 배출하는 목재류 제품은 재활용이 어려우므로 종량제봉투로 배출해야 합니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱, 전자제품 등으로 선별한 후 처리업체로 이송됩니다. 이 중 전기전자제품은 전자제품 재활용업체로 이송되어 재활용하고 있습니다. ·', '["목검은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=202', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 배출하는 목재류 제품은 재활용이 어려우므로 종량제봉투로 배출해야 합니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱, 전자제품 등으로 선별한 후 처리업체로 이송됩니다. 이 중 전기전자제품은 전자제품 재활용업체로 이송되어 재활용하고 있습니다. · 크기가 큰 제품은 대형폐기물로 배출해...', '· 가정에서 배출하는 목재제품은 재활용이 어려우므로 종량제봉투로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('목발', '목발', 'furniture', '· 목발은 고철, 섬유, 고무 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '["목발은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=203', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 목발은 고철, 섬유, 고무 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '· 크기가 크거나 길이가 긴 제품은 끈으로 묶은 후 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('문발', '문발', 'furniture', '· 문발은 제품의 종류에 따라 플라스틱, 목재, 섬유 등 다양한 재질로 제작됩니다. · 단일재질의 합성수지 제품은 재활용이 가능합니다. · 다만, 문발과 같이 크기가 큰 플라스틱의 제품은 수거한 후 재활용 선별장에서 선별하기 곤란하여 소각하거나 전문 재활용업체로 위탁하여 처리하고 있습니다.', '["문발은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=204', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 문발은 제품의 종류에 따라 플라스틱, 목재, 섬유 등 다양한 재질로 제작됩니다. · 단일재질의 합성수지 제품은 재활용이 가능합니다. · 다만, 문발과 같이 크기가 큰 플라스틱의 제품은 수거한 후 재활용 선별장에서 선별하기 곤란하여 소각하거나 전문 재활용업체로 위탁하여 처리하고 있습니다.', '· 크기가 크거나 길이가 긴 제품은 끈으로 묶은 후 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('밀대 걸레', '밀대 걸레', 'furniture', '· 밀대 걸레는 고철, 플라스틱 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수료에 준하여 책정하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방', '["밀대 걸레는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=205', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 밀대 걸레는 고철, 플라스틱 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수료에 준하여 책정하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까...', '', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('반려동물 캐리어', '반려동물 캐리어', 'furniture', '· 반려동물 캐리어는 플라스틱, 금속, 섬유 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수료에 준하여 책정하고 있습니다.', '["반려동물 캐리어는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=206', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 반려동물 캐리어는 플라스틱, 금속, 섬유 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수료에 준하여 책정하고 있습니다.', '· 의류수거함에 배출 불가', '2026-05-18', 0, '["대형폐기물"]');
