INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('실내자전거', '실내자전거', 'furniture', '· 가정에서 사용하는 실내 운동기구는 고철, 고무, 플라스틱이 혼합된 복합재질 제품이며, 크기가 커 대형폐기물로 배출하여야 합니다. ·대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱, 전자제품 등으로 선별한 후 처리업체로 이송됩니다. 이 중 전기전자제품은 전자제품 재', '["실내자전거는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=209', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 사용하는 실내 운동기구는 고철, 고무, 플라스틱이 혼합된 복합재질 제품이며, 크기가 커 대형폐기물로 배출하여야 합니다. ·대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱, 전자제품 등으로 선별한 후 처리업체로 이송됩니다. 이 중 전기전자제품은 전자제품 재활용업체로 이송되어 재활용하고 있습니...', '', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('삽', '삽', 'furniture', '· 삽은 땅을 파고 흙을 뜨는데 사용하는 연장으로 금속, 플라스틱, 목재 등 다양한 재질이 혼합된 복합재질 제품입니다. · 금속 함량이 많은 삽은 고철류로 재활용이 가능하나 대부분의 삽은 목재 가 다량함유되거나 합성수지 제품인 경우가 많아 재활용이 어렵습니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로', '["삽은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=210', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 삽은 땅을 파고 흙을 뜨는데 사용하는 연장으로 금속, 플라스틱, 목재 등 다양한 재질이 혼합된 복합재질 제품입니다. · 금속 함량이 많은 삽은 고철류로 재활용이 가능하나 대부분의 삽은 목재 가 다량함유되거나 합성수지 제품인 경우가 많아 재활용이 어렵습니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품,...', '', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('소화기', '소화기', 'furniture', '· 소화기는 화재의 초기 단계에 진압할 수 있는 기구로 화재, 약제에 따라 종류가 다양합니다. · 소화기는 소화기 폭발사고 예방 등을 위하여 전문 처리업체에 위탁하여 처리하여야 합니다. · 가정에서 배출하는 소화기는 대형폐기물로 배출하여야 하며, 대형폐기물로 배출한 소화기는 한데 모아 전문 처리업체로 운반되어 재활용됩니다. ※ 배출방법은 지역별로 차이가 있', '["소화기는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=211', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 소화기는 화재의 초기 단계에 진압할 수 있는 기구로 화재, 약제에 따라 종류가 다양합니다. · 소화기는 소화기 폭발사고 예방 등을 위하여 전문 처리업체에 위탁하여 처리하여야 합니다. · 가정에서 배출하는 소화기는 대형폐기물로 배출하여야 하며, 대형폐기물로 배출한 소화기는 한데 모아 전문 처리업체로 운반되어 재활용됩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서...', '', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('스노보드', '스노보드', 'furniture', '· 스노보드는 눈이 쌓인 비탈을 미끄러지듯 내려갈 수 있도록 제작된 널빤지형 운동기구로 목재, 유리섬유, 고철 등이 혼합된 복합재질 제품입니다. · 복합재질 제품은 재활용이 어려우며, 해당 제품은 크기가 커 대형폐기물로 배출합니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목', '["스노보드는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=212', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 스노보드는 눈이 쌓인 비탈을 미끄러지듯 내려갈 수 있도록 제작된 널빤지형 운동기구로 목재, 유리섬유, 고철 등이 혼합된 복합재질 제품입니다. · 복합재질 제품은 재활용이 어려우며, 해당 제품은 크기가 커 대형폐기물로 배출합니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱, 전자제품 등으로...', '· 대형폐기물 배출 시 보행자에게 불편을 주지 않도록 주의하여 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('전기장판', '전기장판', 'furniture', '· 전기장판 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다.', '["전기장판은 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다.", "크기가 커 수거함 배출이 어렵거나 무상수거 서비스를 이용하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=213', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 전기장판 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다.', '· 크기가 커 배출하실 때에는 보행자에게 불편을 주지 않도록 끈으로 묶어서 부피를 최대한 줄여서 배출 · 옥장판은 무상수거서비스 수거 불가 품목', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('가스레인지', '가스레인지', 'furniture', '· 가스레인지는 가스를 이용한 취사도구로 대형폐기물로 배출합니다.', '["가스레인지는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=214', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가스레인지는 가스를 이용한 취사도구로 대형폐기물로 배출합니다.', '· 무상방문수거서비스를 통한 배출 불가', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('안마의자', '안마의자', 'furniture', '· 안마의자는 크기가 커 대형폐기물로 배출합니다.', '["안마의자는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=215', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 안마의자는 크기가 커 대형폐기물로 배출합니다.', '· 무상방문수거서비스를 통한 배출 불가', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('피아노', '피아노', 'furniture', '· 피아노는 크기가 커 대형폐기물로 배출합니다.', '["피아노는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=216', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 피아노는 크기가 커 대형폐기물로 배출합니다.', '· 무상방문수거서비스를 통한 배출 불가', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('미끄럼틀', '미끄럼틀', 'furniture', '· 실내용 장난감인 미끄럼틀은 대부분 플라스틱 재질이나 크기가 커 대형폐기물로 배출합니다.', '["미끄럼틀은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=217', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 실내용 장난감인 미끄럼틀은 대부분 플라스틱 재질이나 크기가 커 대형폐기물로 배출합니다.', '· 크기가 큰 플라스틱 제품은 합성수지 재질이어도 대형폐기물로 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('카시트', '카시트', 'furniture', '· 카시트는 플라스틱, 섬유, 폼 등이 혼합된 복합재질 제품으로 재활용이 어려우며, 해당 제품은 크기가 커 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다', '["카시트는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=218', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 카시트는 플라스틱, 섬유, 폼 등이 혼합된 복합재질 제품으로 재활용이 어려우며, 해당 제품은 크기가 커 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배...', '', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('체중계(전자식)', '체중계(전자식)', 'electronics', '· 체중계는 플라스틱, 금속, 유리 등이 혼합된 복합재질 제품으로 재활용이 어려우며, 해당 제품은 대형폐기물로 배출합니다. · 전자식 체중계(디지털, 스마트)는 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품은 가까운 소형가전제품 수거함으로 배출하여 주시거나 별도 수거함이 마련되지 않은 경우에는 대형폐기물로 배출하', '["체중계(전자식)은 소형전기전제품 전용수거함으로 배출합니다.", "체중계는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=219', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 체중계는 플라스틱, 금속, 유리 등이 혼합된 복합재질 제품으로 재활용이 어려우며, 해당 제품은 대형폐기물로 배출합니다. · 전자식 체중계(디지털, 스마트)는 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품은 가까운 소형가전제품 수거함으로 배출하여 주시거나 별도 수거함이 마련되지 않은 경우에는 대형폐기물로 배출하여 주시기 바랍니다. · 또한, 지자...', '', '2026-05-18', 0, '["대형폐기물", "재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('실링팬', '실링팬', 'furniture', '· 실링팬은 금속, 플라스틱, 목재 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 대부분의 실링팬은 크기가 커 대형폐기물로 배출합니다. · 실링팬에 조명이 포함된 경우 형광등, LED 조명은 제거한 후 형광등수거함으로 배출합니다.', '["실링팬은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=220', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 실링팬은 금속, 플라스틱, 목재 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 대부분의 실링팬은 크기가 커 대형폐기물로 배출합니다. · 실링팬에 조명이 포함된 경우 형광등, LED 조명은 제거한 후 형광등수거함으로 배출합니다.', '· 내장된 조명제품(LED, 형광등)을 제거한 후 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('장난감피아노', '장난감피아노', 'furniture', '· 장난감은 일반 PP, PS, PE 등과 같은 단일재질로 되어 있지 않고 복합재질로 구성되어 있어서 재활용이 되지 않습니다. · 장난감피아노는 대부분 크기가 커 대형폐기물로 배출합니다. · 장난감에 내장된 전지를 제거한 후 전지는 가까운 폐건전지 수거함으로 배출합니다.', '["장난감피아노는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=221', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 장난감은 일반 PP, PS, PE 등과 같은 단일재질로 되어 있지 않고 복합재질로 구성되어 있어서 재활용이 되지 않습니다. · 장난감피아노는 대부분 크기가 커 대형폐기물로 배출합니다. · 장난감에 내장된 전지를 제거한 후 전지는 가까운 폐건전지 수거함으로 배출합니다.', '· 내장된 전지 제거 후 배출', '2026-05-18', 0, '["대형폐기물"]');
