INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('변기', '변기', 'general', '· 변기, 세면대 등은 대부분 세라믹 재질로 불연성폐기물이나 대부분 크기가 커 대형폐기물로 배출합니다. · 인테리어 공사 등에서 발생한 폐기물은 불연성 마대 또는 대형폐기물로 배출할 수 있으며, 다량으로 배출될 시 지자체에 문의하여 공사장생활폐기물 전문 수거업체에 연락하여 처리할 수 있습니다 ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체', '["변기는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=225', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 변기, 세면대 등은 대부분 세라믹 재질로 불연성폐기물이나 대부분 크기가 커 대형폐기물로 배출합니다. · 인테리어 공사 등에서 발생한 폐기물은 불연성 마대 또는 대형폐기물로 배출할 수 있으며, 다량으로 배출될 시 지자체에 문의하여 공사장생활폐기물 전문 수거업체에 연락하여 처리할 수 있습니다 ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해...', '', '2026-05-18', 0, '["대형폐기물", "공사장 생활폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('금고', '금고', 'furniture', '· 금고는 내부는 콘크리트, 외부는 플라스틱, 금속재질로 이루어진 제품입니다. 금고 대부분이 크고 무거우므로 대형폐기물로 배출합니다.', '["금고는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=226', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 금고는 내부는 콘크리트, 외부는 플라스틱, 금속재질로 이루어진 제품입니다. 금고 대부분이 크고 무거우므로 대형폐기물로 배출합니다.', '· 고철로 배출 불가', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('항아리', '항아리', 'furniture', '· 항아리는 물건이나 음식을 담아 저장하는 오지그릇으로 재활용이 어렵고 불에 타지않는 폐기물로 불연성폐기물에 해당됩니다. · 항아리는 대부분 크기가 크거나 무거우므로 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해', '["항아리는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=227', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 항아리는 물건이나 음식을 담아 저장하는 오지그릇으로 재활용이 어렵고 불에 타지않는 폐기물로 불연성폐기물에 해당됩니다. · 항아리는 대부분 크기가 크거나 무거우므로 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소...', '', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('오디오세트', '오디오세트', 'electronics', '· 오디오세트는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장', '["오디오세트는 폐가전제품 무상방문수거서비스(1599-0903)을 이용하여 배출합니다.", "무상수거 서비스를 이용하기 어려운 경우에는 대형폐기물로 배출합니다.", "신제품 구매시 생산, 판매업체의 역회수 서비스를 이용하여 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=228', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 오디오세트는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도 대상품목으로는 냉장고, 세탁기,...', '· 폐가전제품 무상방문서비스 문의 후 배출', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
