INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('공기청정기', '공기청정기', 'electronics', '· 공기청정기는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장', '["공기청정기는 폐가전제품 무상방문수거서비스(1599-0903)을 이용하여 배출합니다.", "무상수거 서비스를 이용하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=231', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 폐가전제품 무상방문서비스 문의 후 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('선풍기', '선풍기', 'electronics', '· 선풍기는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도', '["선풍기는 소형전기전제품 전용수거함으로 배출합니다.", "선풍기와 함께 4가지 이상의 전기전자제품을 배출하기 원하는 경우에는 폐가전제품 무상방문수거서비스(1599-0903)을 이용하여 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=232', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 소형전기전자제품은 전용수거함으로 배출하거나 5개 이상 모아 폐가전제품 무상방문수거서비스를 이용하여 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('족욕기', '족욕기', 'electronics', '· 족욕기는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도', '["족욕기는 소형전기전제품 전용수거함으로 배출합니다.", "족욕기와 함께 4가지 이상의 전기전자제품을 배출하기 원하는 경우에는 폐가전제품 무상방문수거서비스(1599-0903)을 이용하여 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=233', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 족욕기는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도 대상품목으로는 냉장고, 세탁기, 다...', '· 소형전기전자제품은 전용수거함으로 배출하거나 5개 이상 모아 폐가전제품 무상방문수거서비스를 이용하여 배출', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
