INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('전자사전', '전자사전', 'electronics', '· 전자사전 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출방법', '["전자사전은 소형전기전제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=235', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 전자사전 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니,...', '', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('전기면도기', '전기면도기', 'electronics', '· 전기면도기 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다.', '["전기면도기는 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=236', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 전기면도기 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다.', '· 면도기의 칼날과 같이 날카롭고 위험한 폐기물을 배출할 때에는 날카로운 부분이 외부로 노출되어 사람이 찔리거나 베이지 않도록 용기에 담거나 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('전선', '전선', 'electronics', '· 전선은 금속, 고무, 플라스틱이 혼합된 복합재질제품입니다. · 전선 속에 있는 구리는 재활용이 가능하나 전선의 고무 또는 플라스틱 재질의 피복이 재활용이 되지 않기 때문에 분리작업이 필요합니다. 소형전기전자제품 재활용 사업장에서 분리작업을 하고 있기 때문에 소형전기전자제품 수거함에 배출하면 됩니다.', '["전선은 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=237', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 전선은 금속, 고무, 플라스틱이 혼합된 복합재질제품입니다. · 전선 속에 있는 구리는 재활용이 가능하나 전선의 고무 또는 플라스틱 재질의 피복이 재활용이 되지 않기 때문에 분리작업이 필요합니다. 소형전기전자제품 재활용 사업장에서 분리작업을 하고 있기 때문에 소형전기전자제품 수거함에 배출하면 됩니다.', '· 고철로 배출 불가능', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('고데기', '고데기', 'electronics', '· 고데기 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출방법은', '["고데기는 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=238', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 고데기 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니,...', '', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('내비게이션', '내비게이션', 'electronics', '· 내비게이션은 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장', '["내비게이션은 소형전기전자제품 전용수거함으로 배출합니다.", "내비게이션과 함께 4가지 이상의 전기전자제품을 배출하기 원하는 경우에는 폐가전제품 무상방문수거서비스(1599-0903)을 이용하여 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=239', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 내비게이션은 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도 대상품목으로는 냉장고, 세탁기,...', '· 소형전기전자제품은 전용수거함으로 배출하거나 5개 이상 모아 폐가전제품 무상방문수거서비스를 이용하여 배출', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('냉장고', '냉장고', 'electronics', '· 냉장고는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도', '["냉장고는 폐가전제품 무상방문수거서비스(1599-0903)을 이용하여 배출합니다.", "무상수거 서비스를 이용하기 어려운 경우에는 대형폐기물로 배출합니다.", "신제품 구매시 생산, 판매업체의 역회수 서비스를 이용하여 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=240', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 냉장고는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도 대상품목으로는 냉장고, 세탁기, 다...', '· 폐가전제품 무상방문서비스 문의 후 배출', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('노트북', '노트북', 'electronics', '· 노트북은 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도', '["노트북은 소형전기전자제품 전용수거함으로 배출합니다.", "노트북과 함께 4가지 이상의 전기전자제품을 배출하기 원하는 경우에는 폐가전제품 무상방문수거서비스(1599-0903)을 이용하여 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=241', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 소형전기전자제품은 전용수거함으로 배출하거나 5개 이상 모아 폐가전제품 무상방문수거서비스를 이용하여 배출', '2026-05-18', 0, NULL);
