INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('에어컨', '에어컨', 'electronics', '· 에어컨는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. · 환경성보장제도에', '["에어컨은 폐가전제품 무상방문수거서비스(1599-0903)을 이용하여 배출합니다.", "무상수거 서비스를 이용하기 어려운 경우에는 대형폐기물로 배출합니다.", "신제품 구매시 생산, 판매업체의 역회수 서비스를 이용하여 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=252', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 에어컨는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. · 환경성보장제도에 포함되는 전기전자제품은 E-순환거버...', '·폐가전제품 무상방문서비스 문의 후 배출', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('모니터', '모니터', 'electronics', '· 모니터는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도', '["모니터는 소형전기전자제품 전용수거함으로 배출합니다.", "모니터와 함께 4가지 이상의 전기전자제품을 배출하기 원하는 경우에는 폐가전제품 무상방문수거서비스(1599-0903)을 이용하여 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=253', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 모니터는 전용수거함으로 배출하거나 5개 이상 모아 폐가전제품 무상방문수거서비스를 이용하여 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('무전기', '무전기', 'electronics', '· 무선기는 플라스틱, 고철, 각종 회로 등이 포함된 복합재질 제품으로 재활용이 어렵습니다. · 무전기 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에', '["무전기는 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=254', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 무선기는 플라스틱, 고철, 각종 회로 등이 포함된 복합재질 제품으로 재활용이 어렵습니다. · 무전기 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도...', '', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('프린터기', '프린터기', 'electronics', '· 프린터기는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제', '["프린터기는 소형전기전자제품 전용수거함으로 배출합니다.", "프린터기와 함께 4가지 이상의 전기전자제품을 배출하기 원하는 경우에는 폐가전제품 무상방문수거서비스(1599-0903)을 이용하여 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=255', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 프린터기는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도 대상품목으로는 냉장고, 세탁기,...', '· 소형전기전자제품은 전용수거함으로 배출하거나 5개 이상 모아 폐가전제품 무상방문수거서비스를 이용하여 배출', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
