INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('에그쿠커', '에그쿠커', 'electronics', '· 에그쿠커 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출', '["에그쿠커는 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=285', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 에그쿠커 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으...', '', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
