INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('청소기 배터리', '청소기 배터리', 'electronics', '· 청소기 배터리는 전지 수거함으로 배출하거나 소형전기전자제품으로 배출합니다. · 배터리 서비스센터를 통해 반납하실 수도 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다', '["청소기 배터리는 전지 수거함 또는 소형전기전자제품으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=292', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 청소기 배터리는 전지 수거함으로 배출하거나 소형전기전자제품으로 배출합니다. · 배터리 서비스센터를 통해 반납하실 수도 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배...', '', '2026-05-18', 0, '["재활용폐기물", "전지류", "전기전자 제품류"]');
