INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('멀티탭(멀티 콘센트)', '멀티탭(멀티 콘센트)', 'electronics', '· 멀티탭은 금속, 플라스틱 등이 혼합된 복합재질제품입니다. · 멀티탭(멀티 콘센트)의 전선 속에 있는 구리는 재활용이 가능하나 전선의 고무 또는 플라스틱 재질의 피복이 재활용이 되지 않기 때문에 분리작업이 필요합니다. · 소형전기전자제품 재활용 사업장에서 분리작업을 하고 있기 때문에 소형전기전자제품 수거함에 배출하면 됩니다. ※ 배출방법은 지역별로 차이가', '["멀티탭(멀티 콘센트)은 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=294', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 멀티탭은 금속, 플라스틱 등이 혼합된 복합재질제품입니다. · 멀티탭(멀티 콘센트)의 전선 속에 있는 구리는 재활용이 가능하나 전선의 고무 또는 플라스틱 재질의 피복이 재활용이 되지 않기 때문에 분리작업이 필요합니다. · 소형전기전자제품 재활용 사업장에서 분리작업을 하고 있기 때문에 소형전기전자제품 수거함에 배출하면 됩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체...', '', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('스탠드 조명', '스탠드 조명', 'furniture', '· 가정에서 사용하는 스탠드 조명은 조명제품(LED 조명, 형광등), 플라스틱, 금속 등이 혼합된 복합재질 제품입니다. · 스탠드 조명 등 일부 가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도', '["스탠드 조명은 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다.", "이때, 테이블 스탠드 내 형광등, LED 조명은 제거한 후 형광등수거함으로 배출합니다.", "크기가 큰 스탠드 조명은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=295', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 사용하는 스탠드 조명은 조명제품(LED 조명, 형광등), 플라스틱, 금속 등이 혼합된 복합재질 제품입니다. · 스탠드 조명 등 일부 가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라...', '', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류", "대형폐기물"]');
