INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('포충기', '포충기', 'electronics', '· 포충기 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출방', '["포충기는 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=302', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 포충기 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니...', '', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('우산', '우산', 'furniture', '· 우산은 고철, 천(섬유), 플라스틱 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 우산에 포함된 뼈대는 고철로 재활용이 가능하므로 타 재질(천, 플라스틱)은 분리하여 배출합니다.', '["우산은 분리가 가능한 경우 분리하여 재질별 수거함에 배출하고 분리가 어려운 경우에는 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=303', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 우산은 고철, 천(섬유), 플라스틱 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 우산에 포함된 뼈대는 고철로 재활용이 가능하므로 타 재질(천, 플라스틱)은 분리하여 배출합니다.', '· 크기가 크거나 길이가 긴 제품은 끈으로 묶은 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('리빙박스(섬유 재질)', '리빙박스(섬유 재질)', 'furniture', '· 리빙박스가 패브릭 제품인 경우에는 섬유, 금속, 플라스틱 등이 혼합된 복합재질 제품입니다. · 복합재질 제품은 재활용이 어려우며, 해당 제품은 크기가 커 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요.', '["리빙박스(섬유 재질)은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=304', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 리빙박스가 패브릭 제품인 경우에는 섬유, 금속, 플라스틱 등이 혼합된 복합재질 제품입니다. · 복합재질 제품은 재활용이 어려우며, 해당 제품은 크기가 커 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('망원경', '망원경', 'furniture', '· 망원경, 쌍안경, 현미경 등은 유리, 플라스틱, 고철 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 망원경의 크기는 사양, 특징, 종류 등에 따라 다르므로 크기가 큰 제품은 대형폐기물로 배출해야 합니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱', '["망원경은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=305', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 망원경, 쌍안경, 현미경 등은 유리, 플라스틱, 고철 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 망원경의 크기는 사양, 특징, 종류 등에 따라 다르므로 크기가 큰 제품은 대형폐기물로 배출해야 합니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱, 전자제품 등으로 선별한 후 처리업...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('가위', '가위', 'general', '· 가위, 칼과 같은 날카로운 제품은 금속재질이더라도 배출자, 수거원 등이 다칠 우려가 있으므로 주의하여 종량제봉투로 배출해야 합니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다.', '["가위는 신문지, 테이프 등을 활용하여 감싼 후 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=306', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가위, 칼과 같은 날카로운 제품은 금속재질이더라도 배출자, 수거원 등이 다칠 우려가 있으므로 주의하여 종량제봉투로 배출해야 합니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다.', '· 가위와 같은 날카롭고 위험한 폐기물을 배출할 때에는 날카로운 부분이 외부로 노출되어 사람이 찔리거나 베이지 않도록 용기에 담거나 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('고무 매트', '고무 매트', 'furniture', '· 가정에서 사용하는 매트는 폴리염화비닐(PVC) 재질 또는 엘라스토머(고무) 재질로 제작됩니다. · PVC비닐은 일반 비닐과 물성이 달라서 비닐류 배출시 재활용이 되지 않습니다. · 가정에서 사용하는 고무 제품은 주로 두 가지 이상 재질이 혼합된 합성 고무재질로 종량제봉투로 배출합니다. · 크기가 큰 고무매트는 대형폐기물로 배출합니다.', '["고무 매트는 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=307', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 사용하는 매트는 폴리염화비닐(PVC) 재질 또는 엘라스토머(고무) 재질로 제작됩니다. · PVC비닐은 일반 비닐과 물성이 달라서 비닐류 배출시 재활용이 되지 않습니다. · 가정에서 사용하는 고무 제품은 주로 두 가지 이상 재질이 혼합된 합성 고무재질로 종량제봉투로 배출합니다. · 크기가 큰 고무매트는 대형폐기물로 배출합니다.', '· 크기가 큰 매트를 배출할 때에는 보행자에게 불편을 주지 않도록 끈으로 묶어서 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('종이테이프', '종이테이프', 'general', '· 주로 라벨, 스티커, 포장 등에 사용하는 종이테이프는 종이(지지체)에 점착제가 도포되어 있어 재활용이 어렵습니다. · 골판지 상자 등에 부착된 종이테이프는 제거하여 배출하여 주시기 바라며, 제거하기 어려운 경우에는 칼 등을 이용하여 접선 부분을 자른 후 접어서 배출합니다.', '["종이테이프는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=308', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 주로 라벨, 스티커, 포장 등에 사용하는 종이테이프는 종이(지지체)에 점착제가 도포되어 있어 재활용이 어렵습니다. · 골판지 상자 등에 부착된 종이테이프는 제거하여 배출하여 주시기 바라며, 제거하기 어려운 경우에는 칼 등을 이용하여 접선 부분을 자른 후 접어서 배출합니다.', '· 제품에 붙은 종이테이프는 제거한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('마커펜', '마커펜', 'general', '· 마커펜은 플라스틱, 잉크 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '["마커펜은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=309', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 마커펜은 플라스틱, 잉크 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '· 제품 그대로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('명함지갑', '명함지갑', 'general', '· 명함지갑은 주로 가죽, 섬유, 금속 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '["명함지갑은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=311', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 명함지갑은 주로 가죽, 섬유, 금속 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '· 가죽제품은 종량제봉투로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('분필', '분필', 'general', '·분필은 철판에 글씨를 쓰기위한 필기구로 탄산 석회, 석고 등으로 제작되고 있으며, 해당 재질은 재활용이 어렵습니다. ·만약 다량으로 배출하는 경우에는 불연성종량제폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요.', '["분필은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=312', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·분필은 철판에 글씨를 쓰기위한 필기구로 탄산 석회, 석고 등으로 제작되고 있으며, 해당 재질은 재활용이 어렵습니다. ·만약 다량으로 배출하는 경우에는 불연성종량제폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('색연필', '색연필', 'general', '· 색연필은 그림을 그릴때 사용하는 그리기 도구 중 하나로 내부에 광물질 물감을 섞어서 여러가지 색이 나게 만드는 연필을 말합니다. · 색연필은 플라스틱, 안료 등이 혼합된 복합재질 제품이며, 크기가 작아 재활용이 어렵습니다.', '["색연필은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=313', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 색연필은 그림을 그릴때 사용하는 그리기 도구 중 하나로 내부에 광물질 물감을 섞어서 여러가지 색이 나게 만드는 연필을 말합니다. · 색연필은 플라스틱, 안료 등이 혼합된 복합재질 제품이며, 크기가 작아 재활용이 어렵습니다.', '· 제품 그대로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('결재판', '결재판', 'general', '· 사무실에서 사용하는 결재판은 PVC, PP 등 플라스틱, 가죽, 금속 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역', '["결재판은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=314', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 사무실에서 사용하는 결재판은 PVC, PP 등 플라스틱, 가죽, 금속 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('압정', '압정', 'general', '· 가위, 칼, 압정과 같은 날카로운 제품은 금속재질이더라도 배출자, 수거원 등이 다칠 우려가 있으므로 주의하여 종량제봉투로 배출해야 합니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다.', '["압정은 신문지, 테이프 등을 활용하여 감싼 후 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=315', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가위, 칼, 압정과 같은 날카로운 제품은 금속재질이더라도 배출자, 수거원 등이 다칠 우려가 있으므로 주의하여 종량제봉투로 배출해야 합니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다.', '· 압정과 같은 날카롭고 위험한 폐기물을 배출할 때에는 날카로운 부분이 외부로 노출되어 사람이 찔리거나 베이지 않도록 용기에 담거나 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('연필', '연필', 'general', '· 연필은 필기도구 중 하나로 내부에 가느다란 흑연심이 포함된 목재제품입니다. · 연필은 목재, 흑연 등이 포함된 복합재질 제품이며, 크기가 작아 재활용이 어렵습니다.', '["연필은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=316', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 연필은 필기도구 중 하나로 내부에 가느다란 흑연심이 포함된 목재제품입니다. · 연필은 목재, 흑연 등이 포함된 복합재질 제품이며, 크기가 작아 재활용이 어렵습니다.', '· 제품 그대로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('연필깍이', '연필깍이', 'general', '· 연필깍이는 금속, 플라스틱, 고무 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 연필깍이의 금속 칼날은 분리하게 되면 고철로 배출할 수 있으나, 분리가 어렵기 때문에 일반쓰레기로 배출해야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리', '["연필깍이는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=317', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 연필깍이는 금속, 플라스틱, 고무 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 연필깍이의 금속 칼날은 분리하게 되면 고철로 배출할 수 있으나, 분리가 어렵기 때문에 일반쓰레기로 배출해야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('양면테이프', '양면테이프', 'general', '· 양면테이프는 필름이나 폼에 점착제가 붙어있는 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현', '["양면테이프는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=318', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 양면테이프는 필름이나 폼에 점착제가 붙어있는 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분리배출...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('우드락', '우드락', 'general', '· 우드락은 스티로폼(발포폴리스티렌, EPS)을 고압축한 후 나무처럼 만든 판재로 색상을 인쇄하거나 스티커 등을 접착한 제품을 말합니다. · 폼보드는 우드락 원단에 종이필름을 붙인 것을 말합니다. · 우드락 제품은 일반 스티로폼과 물성이 달라 일반 스티로폼 제품과 함께 재활용할 시 재활용 제품(잉고트 제품) 품질에 영향을 미칩니다. ※ 배출방법은 지역별로', '["우드락은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=319', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 우드락은 스티로폼(발포폴리스티렌, EPS)을 고압축한 후 나무처럼 만든 판재로 색상을 인쇄하거나 스티커 등을 접착한 제품을 말합니다. · 폼보드는 우드락 원단에 종이필름을 붙인 것을 말합니다. · 우드락 제품은 일반 스티로폼과 물성이 달라 일반 스티로폼 제품과 함께 재활용할 시 재활용 제품(잉고트 제품) 품질에 영향을 미칩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('한지제품', '한지제품', 'general', '· 신문지, 백상지 등 종이류는 일반 종이류로 재활용이 가능합니다. 다만, 한지, 창호지 등은 일반 종이와 함께 배출하면 재질이 달라 재활용 제품 품질에 영향을 미칩니다.', '["한지제품은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=320', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 신문지, 백상지 등 종이류는 일반 종이류로 재활용이 가능합니다. 다만, 한지, 창호지 등은 일반 종이와 함께 배출하면 재질이 달라 재활용 제품 품질에 영향을 미칩니다.', '· 한지류는 종이로 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('접착제', '접착제', 'hazardous', '· 폐접착제는 제품에 포함된 유해물질로 인하여 폐기물관리법 시행규칙 및 환경부 고시로 정하고 있는 생활계유해폐기물에 해당됩니다. * 생활계유해폐기물이란 폐농약, 폐의약품 등 인간의 건광과 주변환경에 피해를 유발할 수 있는 폐기물을 말합니다. · 접착제는 고철재질의 스프레이 용기와 플라스틱의 스프레이 용기가 있습니다. · 고철재질의 스프레이 용기는 구멍을 뚫', '["접착제는 파손으로 인하여 내용물이 유출되지 않도록 밀봉한 후 전용수거함으로 배출합니다.", "용기가 완전히 밀봉되지 않아 외부로 유출될 우려가 있는 경우에는 더 큰 용기(비닐, 플라스틱 용기 등)에 담아 배출합니다.", "인근에 전용수거함이 없는 경우에는 용기를 밀봉한 후 종량제봉투 등 지자체 조례에 따라 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=321', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 딱풀, 본드, 실리콘 등의 제품은 재활용이 어렵습니다. · 내용물을 모두 사용하더라도 내부에 이물질이 남아 있어 재활용이 어렵습니다.', '· 내용물이 남아있는 경우 외부로 유출되지 않도록 완전히 밀봉한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('줄자', '줄자', 'general', '· 줄자는 플라스틱, 금속 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 줄자를 분해할 경우 금속의 긴 줄을 고철로 배출하기가 곤란하기 때문에 일반쓰레기로 안전하게 배출하는 것이 좋습니다.', '["줄자는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=322', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 줄자는 플라스틱, 금속 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 줄자를 분해할 경우 금속의 긴 줄을 고철로 배출하기가 곤란하기 때문에 일반쓰레기로 안전하게 배출하는 것이 좋습니다.', '· 제품을 분해하지 않고 그대로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('지로명세서', '지로명세서', 'general', '· 지로명세서는 종이재질로 재활용이 가능합니다. · 다만, 지로명세서에는 이름, 주소 등 개인 정보가 기재되어 있어 개인정보 보호를 위하여 찢은 후 종량제봉투로 배출하는 것이 좋습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요', '["지로명세서는 종이류로 배출하여야 하나, 개인정보 유출 등이 우려될 경우 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=323', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 지로명세서는 종이재질로 재활용이 가능합니다. · 다만, 지로명세서에는 이름, 주소 등 개인 정보가 기재되어 있어 개인정보 보호를 위하여 찢은 후 종량제봉투로 배출하는 것이 좋습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('지우개', '지우개', 'general', '· 지우개는 글씨나 그림을 지우기 위해 사용하는 제품으로 합성고무에 화학물질을 첨가하여 제조됩니다. · 가정에서 사용하는 고무 제품은 주로 두 가지 이상 재질이 혼합된 합성 고무재질로 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리', '["지우개는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=325', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 지우개는 글씨나 그림을 지우기 위해 사용하는 제품으로 합성고무에 화학물질을 첨가하여 제조됩니다. · 가정에서 사용하는 고무 제품은 주로 두 가지 이상 재질이 혼합된 합성 고무재질로 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('마우스패드', '마우스패드', 'general', '· 마우스패드는 고무, 천, 플라스틱 등 다양한 재질이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 크기가 큰 데스크패드와 장패드는 말아서 끈으로 묶은후 종량제봉투로 배출합니다.', '["마우스패드는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=326', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 마우스패드는 고무, 천, 플라스틱 등 다양한 재질이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 크기가 큰 데스크패드와 장패드는 말아서 끈으로 묶은후 종량제봉투로 배출합니다.', '· 크기가 크거나 길이가 긴 제품은 끈으로 묶은 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('털 귀마개', '털 귀마개', 'general', '· 털 귀마개는 섬유, 고무, 플라스틱, 고무 등이 혼합된 복합재질제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배', '["털 귀마개는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=327', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 털 귀마개는 섬유, 고무, 플라스틱, 고무 등이 혼합된 복합재질제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('파쇄지', '파쇄지', 'paper', '· 사무실에서 주요 문서를 버릴 때 파쇄기를 이용하여 파쇄하는 경우가 많습니다. · 파쇄지는 비밀 유지를 위하여 매우 작은 종이 조각 형태로 파쇄하기 때문에 일반 종이와 함께 배출하면 배출, 수거, 선별 각 과정에서 흩날려 수거, 선별이 어렵습니다. · 또한, 재활용업체에서 파쇄지와 일반 종이가 함께 재활용할 시 비중이 낮아 물 위에 뜨며, 교반기에 붙어', '["파쇄지는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=328', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 사무실에서 주요 문서를 버릴 때 파쇄기를 이용하여 파쇄하는 경우가 많습니다. · 파쇄지는 비밀 유지를 위하여 매우 작은 종이 조각 형태로 파쇄하기 때문에 일반 종이와 함께 배출하면 배출, 수거, 선별 각 과정에서 흩날려 수거, 선별이 어렵습니다. · 또한, 재활용업체에서 파쇄지와 일반 종이가 함께 재활용할 시 비중이 낮아 물 위에 뜨며, 교반기에 붙어 오히려 재활용 공정을 방해할 수 있습...', '· 전문업체에서 다량의 파쇄지를 수거하는 경우에는 재활용 가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('필통의 재질', '필통의 재질', 'plastic', '· 필통은 플라스틱, 목재, 가죽, 금속 등 재질이 다양합니다. · 플라스틱, 금속 등 단일재질 제품은 재활용이 가능하므로 전용수거함으로 배출하여 주시기 바랍니다. · 목재류, 가죽, 섬유 제품은 재활용이 어려우므로 종량제봉투로 배출해야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에', '["필통의 재질이 재질에 맞게 고철 수거함, 플라스틱 수거함 등으로 배출합니다.", "제품이 목재, 가죽, 섬유 등의 재질이거나 2개 이상의 재질이 혼합된 복합재질인 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=329', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 필통은 플라스틱, 목재, 가죽, 금속 등 재질이 다양합니다. · 플라스틱, 금속 등 단일재질 제품은 재활용이 가능하므로 전용수거함으로 배출하여 주시기 바랍니다. · 목재류, 가죽, 섬유 제품은 재활용이 어려우므로 종량제봉투로 배출해야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('고무대야', '고무대야', 'furniture', '· 대부분의 고무 대야는 PVC 재질로 제작됩니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다.', '["고무대야는 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=330', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 대부분의 고무 대야는 PVC 재질로 제작됩니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다.', '· PVC 제품은 재활용이 어려워 종량제봉투 또는 대형폐기물로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('일회용 면도기', '일회용 면도기', 'general', '· 일회용 면도기는 플라스틱, 금속이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '["일회용 면도기는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=331', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 일회용 면도기는 플라스틱, 금속이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '· 면도기의 칼날과 같이 날카롭고 위험한 폐기물을 배출할 때에는 날카로운 부분이 외부로 노출되어 사람이 찔리거나 베이지 않도록 용기에 담거나 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('연수필터', '연수필터', 'general', '· 연수기, 정수기, 공기청정기 등에 사용되는 필터는 플라스틱, 합성섬유, 활성탄 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 일부 제품의 경우 외부 케이스(플라스틱)를 분리할 수 있도록 되어 있으며, 배출하실 때에는 케이스를 분리한 후 플라스틱 수거함으로 배출하여 주시면 재활용이 가능합니다.', '["연수필터는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=332', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 연수기, 정수기, 공기청정기 등에 사용되는 필터는 플라스틱, 합성섬유, 활성탄 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 일부 제품의 경우 외부 케이스(플라스틱)를 분리할 수 있도록 되어 있으며, 배출하실 때에는 케이스를 분리한 후 플라스틱 수거함으로 배출하여 주시면 재활용이 가능합니다.', '· 플라스틱 케이스를 분리할 수 있는 경우에는 분리한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('욕실화', '욕실화', 'general', '· 욕실화는 주로 EVA, PVC 등의 재질로 제작하고 있습니다. · 가정에서 사용하는 EVA는 주로 샌달, 구두창 등의 제품으로 사용하고 있으며, 주로 소량으로 발생되어 재활용이 어렵습니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다.', '["욕실화는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=333', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 욕실화는 주로 EVA, PVC 등의 재질로 제작하고 있습니다. · 가정에서 사용하는 EVA는 주로 샌달, 구두창 등의 제품으로 사용하고 있으며, 주로 소량으로 발생되어 재활용이 어렵습니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다.', '· 의류수거함에 배출 불가', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('CD', 'CD', 'general', '· CD는 폴리카보네이트(PC)재질의 플라스틱 표면 위에 알루미늄 막과 염료를 입힌 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보', '["CD는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=336', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· CD는 폴리카보네이트(PC)재질의 플라스틱 표면 위에 알루미늄 막과 염료를 입힌 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('골프망', '골프망', 'general', '· 골프망은 PE, 나일론 등의 재질이며, 골프망과 같이 그물형태로 되어 있는 것은 수거과정과 선별과정에서 방해가 되기 때문에 종량제봉투로 배출합니다.', '["골프망은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=337', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 골프망은 PE, 나일론 등의 재질이며, 골프망과 같이 그물형태로 되어 있는 것은 수거과정과 선별과정에서 방해가 되기 때문에 종량제봉투로 배출합니다.', '· 골프망은 재활용이 어려우므로 수거함으로 배출하지 말것', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('축구공', '축구공', 'general', '· 공은 고무, 플라스틱 등으로 제작되어 있으며, 접착제와 섬유재질이 혼합된 복합재질제품으로 재활용이 어렵습니다. · 공의 내부는 공기로 채워져 있어 배출, 수거하기에 어려움이 있으므로 가급적 제거한 후 배출하는 것이 좋습니다.', '["축구공은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=338', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 공은 고무, 플라스틱 등으로 제작되어 있으며, 접착제와 섬유재질이 혼합된 복합재질제품으로 재활용이 어렵습니다. · 공의 내부는 공기로 채워져 있어 배출, 수거하기에 어려움이 있으므로 가급적 제거한 후 배출하는 것이 좋습니다.', '· 공기를 제거한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('PVC 비닐', 'PVC 비닐', 'general', '· 배달음식, 마트에서 사용하는 포장용 랩은 PVC로 재활용이 어렵습니다. · 폴리염화비닐(PVC)는 일반 비닐과 물성이 달라서 비닐로 배출시 재활용이 되지 않습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가', '["PVC 비닐은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=339', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 배달음식, 마트에서 사용하는 포장용 랩은 PVC로 재활용이 어렵습니다. · 폴리염화비닐(PVC)는 일반 비닐과 물성이 달라서 비닐로 배출시 재활용이 되지 않습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('가발', '가발', 'general', '· 가발은 인모, 합성섬유, 플라스틱 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소', '["가발은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=340', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가발은 인모, 합성섬유, 플라스틱 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('가스토치', '가스토치', 'general', '· 가스토치는 가스를 연소시켜 불꽃을 만드는 기구로 주로 소재를 절단하거나 용접하는 데 사용합니다. 최근에는 요리용으로 사용하고 있습니다. · 토치는 고철, 플라스틱 등이 혼합된 복합재질제품으로 재활용이 어렵습니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다', '["가스토치는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=341', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가스토치는 가스를 연소시켜 불꽃을 만드는 기구로 주로 소재를 절단하거나 용접하는 데 사용합니다. 최근에는 요리용으로 사용하고 있습니다. · 토치는 고철, 플라스틱 등이 혼합된 복합재질제품으로 재활용이 어렵습니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다.', '· 열기로 인하여 화상 입지 않도록 완전히 식힌 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('걸레', '걸레', 'general', '· 걸레는 주로 이물질을 제거하기 위하여 사용하는 도구로 주로 헝겊, 행주, 수건 등의 섬유류로 사용합니다. · 걸레의 표면에 이물질이 묻어있거나 찢어지는 등 타인이 다시 사용하기 어려워 종량제봉투로 배출하여야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다.', '["걸레는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=342', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 걸레는 주로 이물질을 제거하기 위하여 사용하는 도구로 주로 헝겊, 행주, 수건 등의 섬유류로 사용합니다. · 걸레의 표면에 이물질이 묻어있거나 찢어지는 등 타인이 다시 사용하기 어려워 종량제봉투로 배출하여야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요....', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('계란껍질(달걀껍질)', '계란껍질(달걀껍질)', 'general', '· 닭, 오리, 메추리알 등의 껍데기는 종량제봉투로 배출합니다. · 음식물류폐기물의 경우 지역별로 처리하는 방법이 다르므로 정확한 배출방법은 해당 지자체로 문의하여 배출하여 주시기 바랍니다.', '["계란껍질(달걀껍질)은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=343', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 닭, 오리, 메추리알 등의 껍데기는 종량제봉투로 배출합니다. · 음식물류폐기물의 경우 지역별로 처리하는 방법이 다르므로 정확한 배출방법은 해당 지자체로 문의하여 배출하여 주시기 바랍니다.', '· 알의 껍데기는 종량제봉투로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('돼지기름', '돼지기름', 'general', '· 조리에 사용하는 기름은 식용유, 참기름 등 식물성 기름과 돼지 기름, 오리 기름 등 동물성 기름이 있습니다. · 식물성 기름은 전용수거함으로 배출하여야 하며, 전용수거함으로 배출한 기름은 바이오디젤로 재활용하고 있습니다. · 고추 기름의 경우 재활용 업체에 따라 재활용이 어려울 수 있으므로 해당 기름류를 배출하실 때에는 수거함 외부에 표기된 수거업체로', '["돼지기름은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=345', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 조리에 사용하는 기름은 식용유, 참기름 등 식물성 기름과 돼지 기름, 오리 기름 등 동물성 기름이 있습니다. · 식물성 기름은 전용수거함으로 배출하여야 하며, 전용수거함으로 배출한 기름은 바이오디젤로 재활용하고 있습니다. · 고추 기름의 경우 재활용 업체에 따라 재활용이 어려울 수 있으므로 해당 기름류를 배출하실 때에는 수거함 외부에 표기된 수거업체로 문의하여 주시기 바랍니다. · 동물성...', '·동물성 기름은 폐식용유전용수거함으로 배출 불가', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('감자칩 용기', '감자칩 용기', 'general', '· 감자칩 용기는 종이, 고철 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 프링글스 용기와 같이 재질별로 분리하기 어려운 과자용기는 제품그대로 종량제봉투로 배출하여 주시기 바랍니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다.', '["감자칩 용기는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=346', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 감자칩 용기는 종이, 고철 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 프링글스 용기와 같이 재질별로 분리하기 어려운 과자용기는 제품그대로 종량제봉투로 배출하여 주시기 바랍니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다.', '· 재질별로 분리하기 어려운 경우에는 제품그대로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('교복', '교복', 'general', '· 교복, 군복, 경찰복 등 타인이 사용하기 부적합한 의류는 가위로 절단하여 종량제봉투로 배출합니다.', '["교복은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=347', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 의류수거함에 배출 불가', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('군복', '군복', 'general', '· 교복, 군복, 경찰복 등 타인이 사용하기 부적합한 의류는 가위로 절단하여 종량제봉투로 배출합니다. · 군복무를 마친 후 버려지는 군복은 외국으로 불법 유출될 시 테러 등 국가 안보에 위협이 될 수 있으므로 주의가 필요합니다. · 불용 군복류 처리지침에 따라 간부의 경우 부대 군수계통으로 반납해야하며, 일반 병사는 군복의 원단을 자른 후 배출해야 합니다.', '["군복은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=348', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 군복은 외국에 유통될 시 테러 등 국가 안보에 위협이 될 수 있으므로 반드시 종량제봉투로 배출 · 의류수거함에 배출 불가', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('스마트폰 액세서리', '스마트폰 액세서리', 'general', '· 스마트폰 액세서리는 고철, 합성수지재질 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출', '["스마트폰 액세서리는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=349', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 스마트폰 액세서리는 고철, 합성수지재질 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('기름종이', '기름종이', 'general', '· 기름종이는 주로 얼굴 또는 식품에 남아있는 기름을 제거하기 위하여 사용하는 제품으로 내수성, 내유성 등이 있도록 표면에 별도 공정을 거친 종이를 말합니다. · 기름종이는 내수성으로 인하여 일반 종이와 해리시간에 차이가 있어 별도로 모아 배출해야 하나 가정에서는 주로 소량으로 배출하는 경우가 많아 재활용하기에 어려움이 있습니다. · 또한, 음식물, 기름', '["기름종이는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=350', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 기름종이는 주로 얼굴 또는 식품에 남아있는 기름을 제거하기 위하여 사용하는 제품으로 내수성, 내유성 등이 있도록 표면에 별도 공정을 거친 종이를 말합니다. · 기름종이는 내수성으로 인하여 일반 종이와 해리시간에 차이가 있어 별도로 모아 배출해야 하나 가정에서는 주로 소량으로 배출하는 경우가 많아 재활용하기에 어려움이 있습니다. · 또한, 음식물, 기름 등 이물질이 남아있는 기름종이는 재활...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
