INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('나뭇가지', '나뭇가지', 'general', '· 나뭇가지는 재활용이 어려우므로 종량제봉투로 배출합니다. · 다만, 가지치기로 인하여 크기가 큰 나뭇가지는 대형폐기물로 배출합니다.', '["나뭇가지는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=353', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 나뭇가지는 재활용이 어려우므로 종량제봉투로 배출합니다. · 다만, 가지치기로 인하여 크기가 큰 나뭇가지는 대형폐기물로 배출합니다.', '· 나뭇가지, 낙엽 등은 종량제봉투로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('자기 나침반', '자기 나침반', 'general', '· 나침반은 고철, 플라스틱 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기', '["자기 나침반은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=354', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 나침반은 고철, 플라스틱 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분리배...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('낙엽', '낙엽', 'general', '· 가정에서 발생한 소량의 낙엽은 종량제봉투로 배출합니다. · 학교나 아파트 단지 등에서 대량으로 발생한 낙엽은 종량제봉투로 배출하거나 전문처리업체에 위탁하여 처리합니다. · 골목 청소로 인해 발생한 낙엽은 이물질이 혼입되지 않도록 비닐 또는 마대에 담아 주민센터에 수거요청을 하시기 바랍니다.', '["낙엽은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=355', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 발생한 소량의 낙엽은 종량제봉투로 배출합니다. · 학교나 아파트 단지 등에서 대량으로 발생한 낙엽은 종량제봉투로 배출하거나 전문처리업체에 위탁하여 처리합니다. · 골목 청소로 인해 발생한 낙엽은 이물질이 혼입되지 않도록 비닐 또는 마대에 담아 주민센터에 수거요청을 하시기 바랍니다.', '· 나뭇가지, 낙엽 등은 종량제봉투로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('낚시대', '낚시대', 'furniture', '· 낚시대는 고철, 고무, 합성수지 섬유 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장', '["낚시대는 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=356', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 낚시대는 고철, 고무, 합성수지 섬유 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('플라스틱 노끈', '플라스틱 노끈', 'general', '· 노끈은 주로 제품을 보관할 때 활용하는 것으로 플라스틱, 비닐, 종이 등 다양한 재질이 있습니다. · 노끈은 가정에서 주로 소량으로 발생하며 안료가 혼합된 경우가 많고 이물질 등이 묻어있는 경우가 많아 재활용이 어렵습니다. · 플라스틱 노끈은 PP용기와는 그 성상이 다르기 때문에 선별장에서 이물질로 분리하게 됩니다. ※ 배출방법은 지역별로 차이가 있을', '["플라스틱 노끈은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=357', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 노끈은 주로 제품을 보관할 때 활용하는 것으로 플라스틱, 비닐, 종이 등 다양한 재질이 있습니다. · 노끈은 가정에서 주로 소량으로 발생하며 안료가 혼합된 경우가 많고 이물질 등이 묻어있는 경우가 많아 재활용이 어렵습니다. · 플라스틱 노끈은 PP용기와는 그 성상이 다르기 때문에 선별장에서 이물질로 분리하게 됩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('비닐 노끈', '비닐 노끈', 'general', '· 노끈은 주로 제품을 보관할 때 활용하는 것으로 플라스틱, 비닐, 종이 등 다양한 재질이 있습니다. · 노끈은 가정에서 주로 소량으로 발생하며 안료가 혼합된 경우가 많고 이물질 등이 묻어있는 경우가 많아 재활용이 어렵습니다. · 비닐 노끈은 일반 비닐과는 그 성상이 다르기 때문에 선별장에서 이물질로 분리하게 됩니다.', '["비닐 노끈은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=358', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 노끈은 주로 제품을 보관할 때 활용하는 것으로 플라스틱, 비닐, 종이 등 다양한 재질이 있습니다. · 노끈은 가정에서 주로 소량으로 발생하며 안료가 혼합된 경우가 많고 이물질 등이 묻어있는 경우가 많아 재활용이 어렵습니다. · 비닐 노끈은 일반 비닐과는 그 성상이 다르기 때문에 선별장에서 이물질로 분리하게 됩니다.', '· 지자체에 따라 비닐 노끈을 분리배출하는 하는 경우도 있으니 지자체내 분리배출 지침 참고', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('목재제품인 경우에', '목재제품인 경우에', 'general', '· 단소는 대부분 대나무로 만들어지며, 최근 보급을 위하여 플라스틱재질의 단소도 제작하고 있습니다. · 단소가 합성수지 단일재질인 경우에는 재활용이 가능합니다. · 다만, 목재 또는 합성수지, 금속 등이 혼합된 복합재질 제품인 경우에는 재활용이 어렵습니다.', '["목재제품인 경우에는 종량제봉투로 배출합니다.", "단소가 목재재질인 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=359', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 단소는 대부분 대나무로 만들어지며, 최근 보급을 위하여 플라스틱재질의 단소도 제작하고 있습니다. · 단소가 합성수지 단일재질인 경우에는 재활용이 가능합니다. · 다만, 목재 또는 합성수지, 금속 등이 혼합된 복합재질 제품인 경우에는 재활용이 어렵습니다.', '· 목재제품은 재활용이 어려우므로 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('리코더', '리코더', 'general', '· 리코더는 종류에 따라 플라스틱 재질의 플라스틱 리코더와 목재재질의 목관리코더가 있습니다. · 리코더가 합성수지 단일재질인 경우에는 재활용이 가능합니다. · 목재 또는 합성수지, 금속 등이 혼합된 복합재질 제품인 경우에는 재활용이 어렵습니다.', '["리코더가 플라스틱 단일재질인 경우에는 플라스틱 수거함으로 배출합니다.", "리코더가 목재재질인 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=360', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 리코더는 종류에 따라 플라스틱 재질의 플라스틱 리코더와 목재재질의 목관리코더가 있습니다. · 리코더가 합성수지 단일재질인 경우에는 재활용이 가능합니다. · 목재 또는 합성수지, 금속 등이 혼합된 복합재질 제품인 경우에는 재활용이 어렵습니다.', '· 목재제품은 재활용이 어려우므로 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('원목도마', '원목도마', 'general', '· 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리하고 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다.', '["원목도마는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=361', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리하고 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다.', '· 목재제품은 재활용이 어려우므로 종량제봉투로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('돗자리', '돗자리', 'general', '· 가정에서 사용하는 돗자리는 플라스틱 또는 은박지 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '["돗자리는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=362', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 사용하는 돗자리는 플라스틱 또는 은박지 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '· 크기가 큰 돗자리를 배출할 때에는 보행자에게 불편을 주지 않도록 끈으로 묶어서 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('등산스틱', '등산스틱', 'general', '· 등산스틱은 고무, 플라스틱, 고철 등이 혼합된 복합재질 제품으로 일반쓰레기로 배출합니다. · 크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에', '["등산스틱은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=363', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 등산스틱은 고무, 플라스틱, 고철 등이 혼합된 복합재질 제품으로 일반쓰레기로 배출합니다. · 크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('일회용 라이터', '일회용 라이터', 'general', '· 라이터는 주로 담배, 초 등 불을 피울 때 사용하는 기구로 인화성 물질을 포함하고 있습니다. · 라이터의 가스가 소량 남은 경우에는 소각로 연소실에서 폭팔위험이 적으나 가스가 많이 남은 경우에는 내부에 포함된 인화성물질로 인하여 화재가 발생하지 않도록 통풍이 잘되는 장소에서 내용물(가스)을 완전히 제거한 후 종량제봉투로 배출합니다. · 종량제봉투가 태양', '["일회용 라이터는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=364', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 라이터는 주로 담배, 초 등 불을 피울 때 사용하는 기구로 인화성 물질을 포함하고 있습니다. · 라이터의 가스가 소량 남은 경우에는 소각로 연소실에서 폭팔위험이 적으나 가스가 많이 남은 경우에는 내부에 포함된 인화성물질로 인하여 화재가 발생하지 않도록 통풍이 잘되는 장소에서 내용물(가스)을 완전히 제거한 후 종량제봉투로 배출합니다. · 종량제봉투가 태양에 노출되면 라이터로 화재가 발생할...', '· 내용물(가스)을 완전히 제거한 후 배출 · 햇빛에 노출되지 않도록 종이상자에 넣어서 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('배드민턴 라켓', '배드민턴 라켓', 'furniture', '· 라켓은 목재, 고무, 플라스틱 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 종량제봉투로 배출하거나 봉투에 담기 어려운 경우에는 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까', '["배드민턴 라켓은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=365', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 라켓은 목재, 고무, 플라스틱 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 종량제봉투로 배출하거나 봉투에 담기 어려운 경우에는 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('라텍스 장갑', '라텍스 장갑', 'general', '· 합성고무, 실리콘 재질의 위생장갑은 재활용이 어려우므로 일반쓰레기로 배출합니다. · 가정에서 사용하는 고무 제품은 주로 두 가지 이상 재질이 혼합된 합성 고무재질로 재활용이 불가능하지는 않으나 발생량이 적고 재활용시 경제적인 가치가 낮아 현실적으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이', '["라텍스 장갑은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=366', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 합성고무, 실리콘 재질의 위생장갑은 재활용이 어려우므로 일반쓰레기로 배출합니다. · 가정에서 사용하는 고무 제품은 주로 두 가지 이상 재질이 혼합된 합성 고무재질로 재활용이 불가능하지는 않으나 발생량이 적고 재활용시 경제적인 가치가 낮아 현실적으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 렌즈케이스', '깨끗한 렌즈케이스', 'plastic', '· 렌즈케이스는 단일 재질(PP)의 플라스틱이므로 재활용이 가능합니다. · 렌즈케이스와 같이 크기가 작은 플라스틱은 이물질이 묻어 있지 않은 경우에는 플라스틱으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위', '["깨끗한 렌즈케이스는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=367', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 렌즈케이스는 단일 재질(PP)의 플라스틱이므로 재활용이 가능합니다. · 렌즈케이스와 같이 크기가 작은 플라스틱은 이물질이 묻어 있지 않은 경우에는 플라스틱으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('로또용지', '로또용지', 'general', '· 로또 용지, 영수증 등과 같이 종이표면에 화학물질을 발라 열을 가해 색을 나타내는 종이는 감열지라고 불립니다. 감열지를 재활용할 시 표면에 남아있는 화학물질로 인하여 재활용제품에 얼룩이 생길 수 있어 일반폐기물로 배출하셔야 합니다.', '["로또용지는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=368', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 로또 용지, 영수증 등과 같이 종이표면에 화학물질을 발라 열을 가해 색을 나타내는 종이는 감열지라고 불립니다. 감열지를 재활용할 시 표면에 남아있는 화학물질로 인하여 재활용제품에 얼룩이 생길 수 있어 일반폐기물로 배출하셔야 합니다.', '· 감열지는 재활용이 어려우므로 종량제봉투로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('일회용 마스크', '일회용 마스크', 'general', '· 마스크는 미세입자나 비말 등을 차단하기 위해 사용하는 제품으로 보건용 마스크, 덴탈 마스크, 면 마스크 등이 있습니다. · 사용한 마스크는 재질에 상관없이 병원균, 미세먼지 등이 남아있어 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운', '["일회용 마스크는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=369', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 마스크는 미세입자나 비말 등을 차단하기 위해 사용하는 제품으로 보건용 마스크, 덴탈 마스크, 면 마스크 등이 있습니다. · 사용한 마스크는 재질에 상관없이 병원균, 미세먼지 등이 남아있어 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('머리끈', '머리끈', 'general', '· 머리끈은 섬유, 고무가 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도', '["머리끈은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=370', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 머리끈은 섬유, 고무가 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분리배출 장소...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('목베개', '목베개', 'furniture', '· 대부분의 상태가 좋은 의류 및 섬유제품은 의류수거함으로 배출하여 국내 또는 국외로 판매하여 재사용하고 있습니다. · 다만, 솜이불, 베개, 방석 등 일부 의류수거함으로 배출하기 어려운 품목이 있으며 해당 품목들은 일반폐기물, 대형폐기물, 재활용폐기물 배출방법에 의거하여 배출합니다.', '["목베개는 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=371', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 대부분의 상태가 좋은 의류 및 섬유제품은 의류수거함으로 배출하여 국내 또는 국외로 판매하여 재사용하고 있습니다. · 다만, 솜이불, 베개, 방석 등 일부 의류수거함으로 배출하기 어려운 품목이 있으며 해당 품목들은 일반폐기물, 대형폐기물, 재활용폐기물 배출방법에 의거하여 배출합니다.', '· 의류수거함으로 배출할 수 있는 제품은 정해져 있으므로 배출가능 대상 품목을 확인한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('모기장', '모기장', 'furniture', '· 모기장은 주로 폴리에스터(폴리에스테르) 재질의 합성섬유로 제작됩니다. · 모기장과 같이 섬유류는 재활용이 어려우므로 종량제봉투로 배출합니다. · 만약 크기가 커서 종량제봉투에 담기 어려운 경우에는 대형폐기물로 배출합니다.', '["모기장은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=372', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 모기장은 주로 폴리에스터(폴리에스테르) 재질의 합성섬유로 제작됩니다. · 모기장과 같이 섬유류는 재활용이 어려우므로 종량제봉투로 배출합니다. · 만약 크기가 커서 종량제봉투에 담기 어려운 경우에는 대형폐기물로 배출합니다.', '· 크기가 크거나 길이가 긴 제품은 끈으로 묶은 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('수채화 물감', '수채화 물감', 'general', '· 물감의 용기는 플라스틱, 알루미늄 재질입니다. · 물감은 작은 튜브 형태의 용기로 내용물을 깨끗하게 제거하기 어렵고 안료로 염색되어 있어 재활용이 어려우므로 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요', '["수채화 물감은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=373', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 물감의 용기는 플라스틱, 알루미늄 재질입니다. · 물감은 작은 튜브 형태의 용기로 내용물을 깨끗하게 제거하기 어렵고 안료로 염색되어 있어 재활용이 어려우므로 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('튜브', '튜브', 'furniture', '· 튜브는 대부분 PVC, EVA재질로 재활용이 어렵습니다. · PVC비닐은 일반 비닐과 물성이 달라서 비닐류 배출시 재활용이 되지 않습니다.', '["튜브는 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=374', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 튜브는 대부분 PVC, EVA재질로 재활용이 어렵습니다. · PVC비닐은 일반 비닐과 물성이 달라서 비닐류 배출시 재활용이 되지 않습니다.', '· PVC 제품은 재활용이 어려워 종량제봉투 또는 대형폐기물로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('물티슈', '물티슈', 'general', '· 물티슈는 폴리에스터(폴리에스테르), 부직포 등으로 제작되며 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보', '["물티슈는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=375', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 물티슈는 폴리에스터(폴리에스테르), 부직포 등으로 제작되며 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('밀짚모자', '밀짚모자', 'general', '· 밀짚 모자는 밀짚으로 제작되며 재활용이 어렵습니다.', '["밀짚모자는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=376', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 밀짚 모자는 밀짚으로 제작되며 재활용이 어렵습니다.', '· 재사용이 어려운 제품으로 종량제봉투로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('바둑판', '바둑판', 'furniture', '· 바둑판은 주로 목재로 제작하거나 플라스틱(PVC)과 자석 등을 혼합하여 제작하고 있습니다. · 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리하고 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다.', '["바둑판은 종량제봉투로 배출합니다.", "크기가 크거나 무게가 무거운 제품은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=377', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 바둑판은 주로 목재로 제작하거나 플라스틱(PVC)과 자석 등을 혼합하여 제작하고 있습니다. · 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리하고 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다.', '· 목재제품은 재활용이 어려우므로 종량제봉투로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 바세린 용기', '깨끗한 바세린 용기', 'plastic', '· 바세린, 핸드크림 등의 화장품(내용물)은 재활용이 어렵습니다. · 내용물을 모두 사용한 용기는 물로 헹구는 등 이물질을 제거한 후 플라스틱 수거함으로 배출하여 주시면 재활용에 용이합니다. · 화장품의 내용물이 남아 있어서 제거하기 곤란한 경우에는 종량제봉투에 배출합니다.', '["깨끗한 바세린 용기는 플라스틱 수거함으로 배출합니다.", "내용물 제거가 어려운 경우 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=378', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 바세린, 핸드크림 등의 화장품(내용물)은 재활용이 어렵습니다. · 내용물을 모두 사용한 용기는 물로 헹구는 등 이물질을 제거한 후 플라스틱 수거함으로 배출하여 주시면 재활용에 용이합니다. · 화장품의 내용물이 남아 있어서 제거하기 곤란한 경우에는 종량제봉투에 배출합니다.', '· 이물질을 제거한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('베개커버', '베개커버', 'general', '· 대부분의 상태가 좋은 의류 및 섬유제품은 의류수거함으로 배출하여 국내 또는 국외로 판매하여 재사용하고 있습니다. · 다만, 솜이불, 베개, 방석, 베개 커버 등 일부 의류수거함으로 배출하기 어려운 품목이 있으며 해당 품목들은 일반폐기물, 대형폐기물, 재활용폐기물 배출방법에 의거하여 배출하여 주셔야 합니다.', '["베개커버는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=379', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 대부분의 상태가 좋은 의류 및 섬유제품은 의류수거함으로 배출하여 국내 또는 국외로 판매하여 재사용하고 있습니다. · 다만, 솜이불, 베개, 방석, 베개 커버 등 일부 의류수거함으로 배출하기 어려운 품목이 있으며 해당 품목들은 일반폐기물, 대형폐기물, 재활용폐기물 배출방법에 의거하여 배출하여 주셔야 합니다.', '· 의류수거함으로 배출할 수 있는 제품은 정해져 있으므로 배출가능 대상 품목을 확인한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('배변패드', '배변패드', 'general', '· 배변패드는 애완동물의 오물을 흡수하기 위하여 사용하는 제품으로 부직포, 흡수체, 펄프 등이 혼합된 복합재질 제품입니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을', '["배변패드는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=380', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 배변패드는 애완동물의 오물을 흡수하기 위하여 사용하는 제품으로 부직포, 흡수체, 펄프 등이 혼합된 복합재질 제품입니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('보냉가방', '보냉가방', 'general', '· 보냉가방은 온도를 유지하여 내용물을 신선하게 보호하기 위하여 제작한 가방으로 외부는 합성섬유로 제작하고 있으며, 내부는 은박지, 타포린, PEVA 소재 등으로 제작하고 있습니다. · 보냉가방은 다양한 재질이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류', '["보냉가방은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=381', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 보냉가방은 온도를 유지하여 내용물을 신선하게 보호하기 위하여 제작한 가방으로 외부는 합성섬유로 제작하고 있으며, 내부는 은박지, 타포린, PEVA 소재 등으로 제작하고 있습니다. · 보냉가방은 다양한 재질이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('플라스틱 재질의 머리빗', '플라스틱 재질의 머리빗', 'general', '· 빗은 용도에 따라 브러쉬 빗, 롤 브러쉬, 도끼 빗 등 다양한 종류가 있으며, 플라스틱, 고무 등 다양한 재질이 혼합된 복합재질 제품입니다. · 복합재질 제품은 재활용이 어려우므로 종량제봉투로 배출하여 주셔야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다.', '["플라스틱 재질의 머리빗은 플라스틱 수거함에 배출하여 주시고, 그 외 재질은 재질별 수거함에 배출합니다.", "복합재질의 머리빗은 재활용이 어려우므로 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=382', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 빗은 용도에 따라 브러쉬 빗, 롤 브러쉬, 도끼 빗 등 다양한 종류가 있으며, 플라스틱, 고무 등 다양한 재질이 혼합된 복합재질 제품입니다. · 복합재질 제품은 재활용이 어려우므로 종량제봉투로 배출하여 주셔야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('빗자루', '빗자루', 'furniture', '· 빗자루는 크기가 다양하며, 종류에 따라 다양한 재질이 혼합된 경우가 많습니다. · 복합재질 제품은 재활용이 어려우므로 종량제봉투로 배출하여 주셔야 합니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수료에 준하여 책정하고 있습니다. ※ 배출방법은 지역별로 차이가', '["빗자루는 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=383', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 빗자루는 크기가 다양하며, 종류에 따라 다양한 재질이 혼합된 경우가 많습니다. · 복합재질 제품은 재활용이 어려우므로 종량제봉투로 배출하여 주셔야 합니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수료에 준하여 책정하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('빨대', '빨대', 'can', '· 빨대는 음료를 마실 때 사용하는 제품으로 고철(스테인리스) 또는 합성수지 단일재질(PP)로 제작하고 있습니다. · 빨대와 같이 크기가 작은 플라스틱은 이물질이 묻어 있지 않은 경우에는 플라스틱으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운', '["빨대는 재질에 맞게 플라스틱류 수거함, 고철수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=384', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 빨대는 음료를 마실 때 사용하는 제품으로 고철(스테인리스) 또는 합성수지 단일재질(PP)로 제작하고 있습니다. · 빨대와 같이 크기가 작은 플라스틱은 이물질이 묻어 있지 않은 경우에는 플라스틱으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('돼지뼈', '돼지뼈', 'general', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. · 동물의 뼈와 같이 딱딱한 물질이 처리시설에 반입되면 분쇄시 설비 고장을 일으킬 수 있으므로 종량제봉투로 배출하여야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍', '["돼지뼈는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=385', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. · 동물의 뼈와 같이 딱딱한 물질이 처리시설에 반입되면 분쇄시 설비 고장을 일으킬 수 있으므로 종량제봉투로 배출하여야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('사진', '사진', 'general', '· 사진을 인화할 때 사용하는 종이는 인화지라고 불리며, 종이에 감광 유제를 바른 제품을 말합니다. · 인화지는 표면에 약품이 묻어있어 재활용이 어려우므로 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현', '["사진은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=386', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 사진을 인화할 때 사용하는 종이는 인화지라고 불리며, 종이에 감광 유제를 바른 제품을 말합니다. · 인화지는 표면에 약품이 묻어있어 재활용이 어려우므로 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
