INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('구명조끼', '구명조끼', 'general', '· 구명조끼에는 부력을 지닌 폼 등의 소재가 포함되어 있습니다. · 구명조끼는 겉면을 잘라 스티로폼만 분리해서 배출하고 나머지는 종량제봉투로 배출합니다.', '["구명조끼는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=388', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 구명조끼에는 부력을 지닌 폼 등의 소재가 포함되어 있습니다. · 구명조끼는 겉면을 잘라 스티로폼만 분리해서 배출하고 나머지는 종량제봉투로 배출합니다.', '· 스티로폼 제거후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('생리대', '생리대', 'general', '· 생리대는 섬유, 흡수제, 테이프 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전', '["생리대는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=389', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 생리대는 섬유, 흡수제, 테이프 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('부직포 가방', '부직포 가방', 'general', '· 부직포란 섬유를 배열한 후 합성수지 접착제로 결합하여 펠트 모양으로 만든 제품으로 현재 대부분의 부직포는 합성섬유로 제작됩니다. · 합성섬유로 만든 부직포가방은 재활용이 어려우므로 종량제봉투로 배출합니다.', '["부직포 가방은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=390', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 부직포란 섬유를 배열한 후 합성수지 접착제로 결합하여 펠트 모양으로 만든 제품으로 현재 대부분의 부직포는 합성섬유로 제작됩니다. · 합성섬유로 만든 부직포가방은 재활용이 어려우므로 종량제봉투로 배출합니다.', '· 의류수거함에 배출 불가', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('속옷', '속옷', 'clothes', '· 속옷은 의류로 재사용이 가능하나 대부분 오물이 묻어있거나 훼손되는 경우가 많아 종량제봉투로 배출합니다.', '["속옷은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=391', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 의류수거함으로 배출할 수 있는 제품은 정해져 있으므로 배출가능 대상 품목을 확인한 후 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('손난로', '손난로', 'general', '· 겨울철 보온을 위하여 사용하는 손난로는 주로 철가루가 포함된 가루 손난로와 젤 형태의 액체형 손난로가 있습니다. · 가루 손난로는 철가루가 포함되어 있으나 금속으로 재활용하기 어려우므로 종량제봉투로 배출합니다. · 액체형 손난로는 플라스틱의 포장재와 젤 형태의 액상이 들어있어 재활용이 어려우므로 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있', '["손난로는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=392', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 겨울철 보온을 위하여 사용하는 손난로는 주로 철가루가 포함된 가루 손난로와 젤 형태의 액체형 손난로가 있습니다. · 가루 손난로는 철가루가 포함되어 있으나 금속으로 재활용하기 어려우므로 종량제봉투로 배출합니다. · 액체형 손난로는 플라스틱의 포장재와 젤 형태의 액상이 들어있어 재활용이 어려우므로 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('수영가방', '수영가방', 'general', '· 수영 가방은 크기가 다양하며, PVC, 타포린, PU, EVA 등 다양한 재질로 제작됩니다. · 가정에서 발생하는 PVC, 타포린, EVA 재질의 제품은 주로 소량으로 발생하며, 재활용이 어렵습니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다.', '["수영가방은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=393', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 수영 가방은 크기가 다양하며, PVC, 타포린, PU, EVA 등 다양한 재질로 제작됩니다. · 가정에서 발생하는 PVC, 타포린, EVA 재질의 제품은 주로 소량으로 발생하며, 재활용이 어렵습니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다.', '·PVC 제품은 재활용이 어려워 종량제봉투 또는 대형폐기물로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('볼펜', '볼펜', 'general', '· 볼펜은 플라스틱, 금속(스프링), 기타(잉크) 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '["볼펜은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=394', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 볼펜은 플라스틱, 금속(스프링), 기타(잉크) 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '· 재질별로 분리하기 어려운 경우에는 제품 그대로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('샤워기', '샤워기', 'general', '· 샤워기는 플라스틱, 고무, 스테인리스(금속) 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '["샤워기는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=395', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 샤워기는 플라스틱, 고무, 스테인리스(금속) 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '· 샤워기 호스는 감아서 묶어 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('배수구트랩', '배수구트랩', 'general', '· 배수구 트랩은 주로 하수구에서 올라오는 악취와 벌레를 차단하기 위해 사용하는 제품으로 주로 PVC, 스테인리스(금속) 등이 혼합된 복합재질 제품이며 크기가 작아 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요', '["배수구트랩은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=396', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 배수구 트랩은 주로 하수구에서 올라오는 악취와 벌레를 차단하기 위해 사용하는 제품으로 주로 PVC, 스테인리스(금속) 등이 혼합된 복합재질 제품이며 크기가 작아 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('샤워캡', '샤워캡', 'plastic', '· 샤워캡은 섬유, 고무, 비닐 등이 혼합된 복합재질 제품입니다. · 샤워캡이 비닐 단일재질인 경우에는 비닐류수거함으로 배출하여 주시면 재활용이 가능합니다. · 그 밖에 섬유, 고무 등이 혼합된 경우에는 재활용이 어려우므로 종량제봉투로 배출하여야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당', '["샤워캡은 재질에 따라 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=397', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 샤워캡은 섬유, 고무, 비닐 등이 혼합된 복합재질 제품입니다. · 샤워캡이 비닐 단일재질인 경우에는 비닐류수거함으로 배출하여 주시면 재활용이 가능합니다. · 그 밖에 섬유, 고무 등이 혼합된 경우에는 재활용이 어려우므로 종량제봉투로 배출하여야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다....', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "재활용폐기물", "합성수지 비닐류", "PET, PP, PS, PE, OTHER"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('샤워커튼', '샤워커튼', 'general', '· 샤워커튼은 면, 폴리에스테르, PVC, PEVA, 폴리에스터 등 다양한 재질이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · PVC비닐은 일반 비닐과 물성이 달라서 비닐류 배출시 재활용이 되지 않습니다.', '["샤워커튼은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=398', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 샤워커튼은 면, 폴리에스테르, PVC, PEVA, 폴리에스터 등 다양한 재질이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · PVC비닐은 일반 비닐과 물성이 달라서 비닐류 배출시 재활용이 되지 않습니다.', '· 접어서 부피를 줄여서 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('가루세제', '가루세제', 'general', '· 가루로 된 세제는 하수로 배출하지 않고 종량제봉투로 배출해야 합니다.가정에서 배출하시는 세제의 양이 많아 무거워서 종량제봉투가 찢어질 우려가 있으시다면 나누어 담아 배출하시는 것이 좋습니다. · 가루세제 포장재는 비닐로 배출합니다.', '["가루세제는 흩날리지 않게 비닐에 담아서 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=399', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가루로 된 세제는 하수로 배출하지 않고 종량제봉투로 배출해야 합니다.가정에서 배출하시는 세제의 양이 많아 무거워서 종량제봉투가 찢어질 우려가 있으시다면 나누어 담아 배출하시는 것이 좋습니다. · 가루세제 포장재는 비닐로 배출합니다.', '· 가루가 흩날리지 않도록 봉투에 담아 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('알약 포장재', '알약 포장재', 'general', '· 알약포장재는 플라스틱(윗면)과 알루미늄(아랫면)이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치', '["알약 포장재는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=400', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 알약포장재는 플라스틱(윗면)과 알루미늄(아랫면)이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('주사기', '주사기', 'general', '· 가정에서 발생하는 주사기는 폐의약품에 해당하지 않으며 의료폐기물에도 해당하지 않습니다. · 주사기는 주사기의 바늘이 외부로 노출되지 않도록 안전하게 밀봉한 후 배출합니다.', '["주사기는 충분히 감싼 후 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=401', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 발생하는 주사기는 폐의약품에 해당하지 않으며 의료폐기물에도 해당하지 않습니다. · 주사기는 주사기의 바늘이 외부로 노출되지 않도록 안전하게 밀봉한 후 배출합니다.', '· 주사기의 날카로운 부분이 외부로 노출되어 사람이 찔리거나 베이지 않도록 용기에 담거나 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "생활계 유해폐기물", "기타"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('영양제', '영양제', 'general', '· 비타민 등 영양제는 의약외품, 건강기능식품이 있습니다. · 의약외품과 건강기능식품은 의약품에 해당하지 않으며 일반쓰레기로 배출합니다.', '["영양제는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=402', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 비타민 등 영양제는 의약외품, 건강기능식품이 있습니다. · 의약외품과 건강기능식품은 의약품에 해당하지 않으며 일반쓰레기로 배출합니다.', '· 영양제가 의약품인 경우 폐의약품 수거함으로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 염색약 용기', '깨끗한 염색약 용기', 'general', '· 염색약의 튜브 용기 및 캡은 내용물을 비우고 물로 헹군 후 플라스틱으로 배출합니다. · 염색약의 내용물은 재활용이 어렵습니다. · 염색약의 내용물이 소량으로 남아있는 경우에는 휴지, 키친타월 등으로 흡수시킨 후 일반쓰레기로 배출합니다. · 다량의 내용물이 남아 있어 휴지로 흡수시켜 내용물 제거가 어려운 경우 제품 그대로 일반쓰레기로 배출합니다. · 염색', '["깨끗한 염색약 용기는 플라스틱 수거함으로 배출합니다.", "내용물이 제거가 어려운 경우 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=403', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 염색약의 튜브 용기 및 캡은 내용물을 비우고 물로 헹군 후 플라스틱으로 배출합니다. · 염색약의 내용물은 재활용이 어렵습니다. · 염색약의 내용물이 소량으로 남아있는 경우에는 휴지, 키친타월 등으로 흡수시킨 후 일반쓰레기로 배출합니다. · 다량의 내용물이 남아 있어 휴지로 흡수시켜 내용물 제거가 어려운 경우 제품 그대로 일반쓰레기로 배출합니다. · 염색약을 미용실 등 대량 배출하는 경우에...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('단백질 가루', '단백질 가루', 'general', '· 가루 형태의 건강보조 식품은 음식물류폐기물과 의약품에 해당하지 않으며 일반쓰레기로 배출합니다.', '["단백질 가루는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=404', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가루 형태의 건강보조 식품은 음식물류폐기물과 의약품에 해당하지 않으며 일반쓰레기로 배출합니다.', '· 가루가 흘러나오지 않도록 밀봉하여 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('규조토 발매트', '규조토 발매트', 'general', '· 규조토 발매트는 불에 타지 않은 재질이므로 불연성폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도', '["규조토 발매트는 불연성종량제봉투(특수규격마대)에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=405', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 규조토 발매트는 불에 타지 않은 재질이므로 불연성폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분리배출 장소...', '', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('선글라스', '선글라스', 'general', '· 선글라스는 유리, 플라스틱, 금속 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소', '["선글라스는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=407', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 선글라스는 유리, 플라스틱, 금속 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
