INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('개껌', '개껌', 'general', '·개껌은 대부분 뼈나 가죽을 가공하여 만든 제품입니다. ·개껌은 음식물류폐기물에 해당하지 않으므로 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을', '["개껌은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=411', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·개껌은 대부분 뼈나 가죽을 가공하여 만든 제품입니다. ·개껌은 음식물류폐기물에 해당하지 않으므로 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('잉크나 토너', '잉크나 토너', 'plastic', '· 프린터 잉크는 세척공정을 거쳐 카트리지로 재사용하고 있습니다. · 카트리지는 프린터 구입업체 또는 카트리지 재활용전문업체를 통해 배출합니다. · 가정에서 직접 배출시에는 프린터 잉크가 외부로 유출되지 않도록 비닐 봉투 등에 담아 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해', '["잉크나 토너가 깨끗하게 분리될 경우 플라스틱 수거함에 배출합니다.", "분리가 어려울 경우 잉크나 토너가 흘러내리지 않도록 밀봉한 후 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=412', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 프린터 잉크는 세척공정을 거쳐 카트리지로 재사용하고 있습니다. · 카트리지는 프린터 구입업체 또는 카트리지 재활용전문업체를 통해 배출합니다. · 가정에서 직접 배출시에는 프린터 잉크가 외부로 유출되지 않도록 비닐 봉투 등에 담아 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다....', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('인라인 스케이트', '인라인 스케이트', 'furniture', '· 인라인 스케이트는 플라스틱과 섬유 등 다양한 재질이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '["인라인 스케이트는 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=413', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 인라인 스케이트는 플라스틱과 섬유 등 다양한 재질이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '· 의류수거함에 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('다 쓴 매니큐어 용기', '다 쓴 매니큐어 용기', 'general', '· 내용물을 모두 사용한 화장품 용기는 EPR 대상에 해당하므로 물로 헹구는 등 이물질을 제거한 후 재질에 따라 플라스틱이나 유리로 배출합니다. · 매니큐어는 합성수지, 색소, 가소제, 용제(아세톤, 알코올 등)으로 만든 제품으로 매니큐어의 내용물은 재활용이 어렵습니다. · 내용물이 남아 있거나 굳어 있어 제거하기 곤란한 경우에는 제품 그대로 종량제봉투에', '["다 쓴 매니큐어 용기는 재질에 맞게 유리병 수거함 또는 플라스틱 수거함으로 배출합니다.", "용기의 내용물 제거가 어려운 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=414', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 내용물을 모두 사용한 화장품 용기는 EPR 대상에 해당하므로 물로 헹구는 등 이물질을 제거한 후 재질에 따라 플라스틱이나 유리로 배출합니다. · 매니큐어는 합성수지, 색소, 가소제, 용제(아세톤, 알코올 등)으로 만든 제품으로 매니큐어의 내용물은 재활용이 어렵습니다. · 내용물이 남아 있거나 굳어 있어 제거하기 곤란한 경우에는 제품 그대로 종량제봉투에 담아 배출합니다. ※ 배출방법은 지역...', '', '2026-05-18', 0, '["재활용폐기물", "유리병", "합성수지 용기류", "일반폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('워터댐', '워터댐', 'general', '· 워터댐은 물을 흡수하고 팽창하는 고흡수성수지가 내장되어 있고 이것을 폐기할때 고흡수성수지를 하수로 배출하면 하수관로의 흐름에 장애가 되기 때문에 고흡수성수지가 내장되어 있는 것을 배출할 때에는 건조하여 배출하거나 그대로 배출합니다. · 워터댐을 배출할 때 가정에서 소량 배출하는 경우에는 종량제봉투에 담아 배출하시고, 만약 다량으로 배출하는 경우에는 해당', '["워터댐은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=415', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 워터댐은 물을 흡수하고 팽창하는 고흡수성수지가 내장되어 있고 이것을 폐기할때 고흡수성수지를 하수로 배출하면 하수관로의 흐름에 장애가 되기 때문에 고흡수성수지가 내장되어 있는 것을 배출할 때에는 건조하여 배출하거나 그대로 배출합니다. · 워터댐을 배출할 때 가정에서 소량 배출하는 경우에는 종량제봉투에 담아 배출하시고, 만약 다량으로 배출하는 경우에는 해당 지자체에 문의하여 배출하시기 바랍니...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 아이스크림 숟가락', '깨끗한 아이스크림 숟가락', 'plastic', '· 아이스크림 숟가락와 같이 크기가 작은 플라스틱은 이물질이 묻어 있지 않은 경우 플라스틱으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요.', '["깨끗한 아이스크림 숟가락은 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=416', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 아이스크림 숟가락와 같이 크기가 작은 플라스틱은 이물질이 묻어 있지 않은 경우 플라스틱으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
