INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('다리미판', '다리미판', 'furniture', '· 다리미판은 나무, 섬유, 플라스틱, 고철 등 다양한 재질이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요.', '["다리미판은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=418', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 다리미판은 나무, 섬유, 플라스틱, 고철 등 다양한 재질이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('녹차잎', '녹차잎', 'general', '· 녹차잎 등 차류 및 한약의 찌꺼기는 영양성분이 거의 남아있지 않아 재활용품(사료, 퇴비)의 가치가 떨어지므로 일반쓰레기로 배출합니다.', '["녹차잎은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=420', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 녹차잎 등 차류 및 한약의 찌꺼기는 영양성분이 거의 남아있지 않아 재활용품(사료, 퇴비)의 가치가 떨어지므로 일반쓰레기로 배출합니다.', '· 음식물류폐기물로 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('팬캡', '팬캡', 'general', '· 과일을 포장할 때 사용하는 팬캡, 그물망은 EPE 재질로 된 발포합성수지입니다. · EPE는 재활용업체수가 적고 EPS와 분리하여 수집과 선별하기가 어려워서 가정에서 소량으로 발생하는 경우에는 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다.', '["팬캡은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=421', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 과일을 포장할 때 사용하는 팬캡, 그물망은 EPE 재질로 된 발포합성수지입니다. · EPE는 재활용업체수가 적고 EPS와 분리하여 수집과 선별하기가 어려워서 가정에서 소량으로 발생하는 경우에는 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('옥수수대', '옥수수대', 'general', '· 옥수수대는 기계고장의 원인이 될 수 있고, 동물의 사료로 적합하지 않기 때문에 일반쓰레기로 배출합니다.', '["옥수수대는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=422', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 옥수수대는 기계고장의 원인이 될 수 있고, 동물의 사료로 적합하지 않기 때문에 일반쓰레기로 배출합니다.', '·음식물류폐기물로 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('신용카드', '신용카드', 'general', '· 신용카드는 PVC 등 재활용이 어려운 종류의 플라스틱 재질로 되어 있고 마그네틱 전자장치 등이 삽입된 복합재질로 재활용이 어려워 일반쓰레기로 배출합니다.', '["신용카드는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=424', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 신용카드는 PVC 등 재활용이 어려운 종류의 플라스틱 재질로 되어 있고 마그네틱 전자장치 등이 삽입된 복합재질로 재활용이 어려워 일반쓰레기로 배출합니다.', '· 카드번호 등 개인정보가 외부 유출되지 않도록 가위 등을 활용하여 자른 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('조개 껍데기', '조개 껍데기', 'general', '· 조개류 껍데기는 기계고장의 원인이 될 수 있고, 동물의 사료로 적합하지 않기 때문에 일반쓰레기로 배출합니다.', '["조개 껍데기는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=425', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 조개류 껍데기는 기계고장의 원인이 될 수 있고, 동물의 사료로 적합하지 않기 때문에 일반쓰레기로 배출합니다.', '· 음식물류폐기물로 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('게 껍데기', '게 껍데기', 'general', '· 게, 가재 등 갑각류 껍데기는 기계고장의 원인이 될 수 있고, 동물의 사료로 적합하지 않기 때문에 일반쓰레기로 배출합니다.', '["게 껍데기는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=426', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 게, 가재 등 갑각류 껍데기는 기계고장의 원인이 될 수 있고, 동물의 사료로 적합하지 않기 때문에 일반쓰레기로 배출합니다.', '· 음식물류폐기물로 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('커튼', '커튼', 'furniture', '· 커튼은 부속품(고철 등)을 제거한 후 일반쓰레기로 배출하며, 크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다. · 지자체에 따라 손상이 심하지 않은 커튼은 의류수거함으로 배출하는 경우도 있으니 확인하신 후 배출하여 주시기 바랍니다.', '["커튼은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다.", "상태가 좋은 커튼은 의류수거함으로 배출할 수 있으므로 지자체에 문의하여 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=427', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 커튼은 부속품(고철 등)을 제거한 후 일반쓰레기로 배출하며, 크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다. · 지자체에 따라 손상이 심하지 않은 커튼은 의류수거함으로 배출하는 경우도 있으니 확인하신 후 배출하여 주시기 바랍니다.', '· 의류수거함으로 배출할 수 있는 제품은 정해져 있으므로 배출가능 대상 품목을 확인한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "재활용폐기물", "의류 및 원단", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('카펫', '카펫', 'furniture', '· 카펫은 면, 울, 합성섬유, 나일론 등 다양한 섬유재질로 제작됩니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱, 전자제품 등으로 선별한 후 처리업체로 이송되어 처리하고 있습니다.', '["카펫은 종량제봉투로 배출합니다.", "종량제봉투에 담기 어려운 경우에는 대형폐기물로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=428', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 카펫은 면, 울, 합성섬유, 나일론 등 다양한 섬유재질로 제작됩니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱, 전자제품 등으로 선별한 후 처리업체로 이송되어 처리하고 있습니다.', '·크기가 큰 카펫을 배출할 때에는 보행자에게 불편을 주지 않도록 끈으로 묶어서 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
