INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('화초', '화초', 'general', '· 화초는 최대한 흙을 털어낸 후 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소', '["화초는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=430', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 화초는 최대한 흙을 털어낸 후 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분리배출 장소 선택 배출장소...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
