INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('석고 방향제', '석고 방향제', 'general', '· 석고 제품은 재활용이 되지 않으므로 일반쓰레기로 배출합니다. · 만약 다량으로 배출하는 경우에는 불연성종량제폐기물로 배출합니다.', '["석고 방향제는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=435', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 석고 제품은 재활용이 되지 않으므로 일반쓰레기로 배출합니다. · 만약 다량으로 배출하는 경우에는 불연성종량제폐기물로 배출합니다.', '· 배출양에 따라 종량제봉투 또는 불연성종량제봉투(특수규격마대)에 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('고무장화', '고무장화', 'general', '· 고무장화는 대부분 EVA, PVC 재질의 제품입니다. · 가정에서 사용하는 EVA는 주로 샌달, 구두창 등의 제품으로 사용하고 있으며, 주로 소량으로 발생되어 재활용이 어렵습니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다.', '["고무장화는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=436', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 고무장화는 대부분 EVA, PVC 재질의 제품입니다. · 가정에서 사용하는 EVA는 주로 샌달, 구두창 등의 제품으로 사용하고 있으며, 주로 소량으로 발생되어 재활용이 어렵습니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다.', '· 의류수거함에 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('고무신발', '고무신발', 'general', '· 고무신발은 대부분 EVA 재질의 제품입니다. · 가정에서 사용하는 EVA는 주로 샌달, 구두창 등의 제품으로 사용하고 있으며, 주로 소량으로 발생되어 재활용이 어렵습니다.', '["고무신발은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=437', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 고무신발은 대부분 EVA 재질의 제품입니다. · 가정에서 사용하는 EVA는 주로 샌달, 구두창 등의 제품으로 사용하고 있으며, 주로 소량으로 발생되어 재활용이 어렵습니다.', '· 의류수거함에 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('우비', '우비', 'general', '· 우비는 대부분 EVA, PVC 재질의 제품으로 발수, 방수코팅이 되어 있어 재활용이 어려우므로 일반쓰레기로 배출합니다. · 가정에서 사용하는 EVA는 주로 샌달, 구두창 등의 제품으로 사용하고 있으며, 주로 소량으로 발생되어 재활용이 어렵습니다. · PVC비닐은 일반 비닐과 물성이 달라서 비닐류 배출시 재활용이 되지 않습니다.', '["우비는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=439', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 우비는 대부분 EVA, PVC 재질의 제품으로 발수, 방수코팅이 되어 있어 재활용이 어려우므로 일반쓰레기로 배출합니다. · 가정에서 사용하는 EVA는 주로 샌달, 구두창 등의 제품으로 사용하고 있으며, 주로 소량으로 발생되어 재활용이 어렵습니다. · PVC비닐은 일반 비닐과 물성이 달라서 비닐류 배출시 재활용이 되지 않습니다.', '· 의류수거함에 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('아크릴판', '아크릴판', 'general', '· 아크릴(PMMA) 재질의 플라스틱은 재활용선별장에서 선별이 용이하지 않고 재활용이 어렵기 때문에 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역', '["아크릴판은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=440', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 아크릴(PMMA) 재질의 플라스틱은 재활용선별장에서 선별이 용이하지 않고 재활용이 어렵기 때문에 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('녹말이쑤시개', '녹말이쑤시개', 'general', '· 녹말 이쑤시개는 녹말과 소르비톨, 색소 등을 혼합하여 제조한 위생용품이며, 일정한 조건에서 미생물이나 효소에 의해 분해되는 생분해성수지제품입니다. · 생분해성수지 제품은 일반 플라스틱과는 성질이 달라 플라스틱으로 배출 시 재활용을 저해하므로 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는', '["녹말이쑤시개는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=441', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 녹말 이쑤시개는 녹말과 소르비톨, 색소 등을 혼합하여 제조한 위생용품이며, 일정한 조건에서 미생물이나 효소에 의해 분해되는 생분해성수지제품입니다. · 생분해성수지 제품은 일반 플라스틱과는 성질이 달라 플라스틱으로 배출 시 재활용을 저해하므로 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('유산지', '유산지', 'general', '· 유산지는 종이에 내수성, 내유성 등이 있도록 코팅이 되어 있어 일반 종이와 해리시간이 차이가 있어 별도로 모아 배출해야 재활용이 가능합니다. · 가정에서는 소량으로 배출되는 경우가 많아 재활용이 어렵습니다. · 포장지에 기름이나 음식물이 묻어 있는 경우에는 재활용이 어려우므로 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당', '["유산지는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=442', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 유산지는 종이에 내수성, 내유성 등이 있도록 코팅이 되어 있어 일반 종이와 해리시간이 차이가 있어 별도로 모아 배출해야 재활용이 가능합니다. · 가정에서는 소량으로 배출되는 경우가 많아 재활용이 어렵습니다. · 포장지에 기름이나 음식물이 묻어 있는 경우에는 재활용이 어려우므로 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('아쿠아덤벨', '아쿠아덤벨', 'general', '· 아쿠아덤벨은 대부분 EVA 재질로 된 제품으로 재활용이 어려우므로 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출', '["아쿠아덤벨은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=443', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 아쿠아덤벨은 대부분 EVA 재질로 된 제품으로 재활용이 어려우므로 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('실리콘 주걱', '실리콘 주걱', 'general', '· 실리콘 수지는 열에 잘 변형되지 않는 열경화성 수지 제품으로 주로 조리도구, 유아용품 등에 사용됩니다. · 합성수지 제품(플라스틱 제품)은 선별압축-파쇄-세척-용융압출 등의 과정을 거쳐 재활용하고 있습니다. · 열경화성 수지 제품의 경우 열에 쉽게 변형되지 않아 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서', '["실리콘 주걱은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=444', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 실리콘 수지는 열에 잘 변형되지 않는 열경화성 수지 제품으로 주로 조리도구, 유아용품 등에 사용됩니다. · 합성수지 제품(플라스틱 제품)은 선별압축-파쇄-세척-용융압출 등의 과정을 거쳐 재활용하고 있습니다. · 열경화성 수지 제품의 경우 열에 쉽게 변형되지 않아 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('잠자리채', '잠자리채', 'general', '· 잠자리채는 플라스틱, 섬유, 금속 등이 혼합된 복합재질로 구성되어 있기 때문에 재활용이 어려우므로 일반쓰레기로 배출합니다. 금속을 분리할 수 있다면 금속은 고철수거함으로 배출합니다.', '["잠자리채는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=445', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 잠자리채는 플라스틱, 섬유, 금속 등이 혼합된 복합재질로 구성되어 있기 때문에 재활용이 어려우므로 일반쓰레기로 배출합니다. 금속을 분리할 수 있다면 금속은 고철수거함으로 배출합니다.', '· 금속을 분리할 수 있는 경우에는 분리한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('pvc배관', 'pvc배관', 'furniture', '· 폴리염화비닐(PCV) 재질로 된 관은 EPR 대상 품목으로 지정되어 재활용이 됩니다. · 사업장에서 발생하는 경우 PVC재활용업체에 위탁하여 처리합니다. 가정에서 배출하는 경우에는 수거와 선별이 곤란하기 때문에 종량제봉투 또는 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당', '["pvc배관은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=446', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 폴리염화비닐(PCV) 재질로 된 관은 EPR 대상 품목으로 지정되어 재활용이 됩니다. · 사업장에서 발생하는 경우 PVC재활용업체에 위탁하여 처리합니다. 가정에서 배출하는 경우에는 수거와 선별이 곤란하기 때문에 종량제봉투 또는 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다....', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
