INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 손소독제 용기', '깨끗한 손소독제 용기', 'plastic', '· 손소독제는 에탄올 등 성분으로 손이나 피부의 살균소소독을 목적으로 사용하는 의약외품입니다. · 내용물을 모두 사용한 용기는 물로 헹구는 등 이물질을 제거한 후 플라스틱 수거함으로 배출하며, 펌프는 일반쓰레기로 배출합니다. · 소독제 내용물이 소량으로 남아있는 경우에는 휴지, 키친타월 등으로 흡수시킨 후 종량제봉투로 배출합니다. · 다량의 양이 남아 있어', '["깨끗한 손소독제 용기는 플라스틱 수거함으로 배출합니다.", "내용물 제거가 어려운 경우 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=448', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 손소독제는 에탄올 등 성분으로 손이나 피부의 살균소소독을 목적으로 사용하는 의약외품입니다. · 내용물을 모두 사용한 용기는 물로 헹구는 등 이물질을 제거한 후 플라스틱 수거함으로 배출하며, 펌프는 일반쓰레기로 배출합니다. · 소독제 내용물이 소량으로 남아있는 경우에는 휴지, 키친타월 등으로 흡수시킨 후 종량제봉투로 배출합니다. · 다량의 양이 남아 있어 휴지로 흡수시키기 어려운 경우에는...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "재활용폐기물", "합성수지 용기류"]');
