INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('액자 프레임', '액자 프레임', 'can', '· 액자 프레임이 금속(알루미늄)인 경우에는 고철 수거함으로 배출합니다. · 액자 프레임이 나무 재질로 되어 있거나 나무, 플라스틱 등 다른 재질이 포함되어 있는 경우에는 일반쓰레기로 배출합니다. · 종량제봉투로 배출하기 어려운 대형액자는 대형폐기물로 배출합니다. · 액자 유리는 불에 타지 않는 폐기물로 불연성 종량제 마대로 배출합니다.', '["액자 프레임이 금속 재질인 경우에는 고철수거함으로 배출합니다.", "목재제품이거나 복합재질인 경우에는 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=450', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 액자 프레임이 금속(알루미늄)인 경우에는 고철 수거함으로 배출합니다. · 액자 프레임이 나무 재질로 되어 있거나 나무, 플라스틱 등 다른 재질이 포함되어 있는 경우에는 일반쓰레기로 배출합니다. · 종량제봉투로 배출하기 어려운 대형액자는 대형폐기물로 배출합니다. · 액자 유리는 불에 타지 않는 폐기물로 불연성 종량제 마대로 배출합니다.', '· 재질에 맞게 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('태블릿 케이스', '태블릿 케이스', 'general', '· 태블릿 케이스는 가죽, 섬유, 플라스틱, 실리콘 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현', '["태블릿 케이스는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=451', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 태블릿 케이스는 가죽, 섬유, 플라스틱, 실리콘 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('폭죽', '폭죽', 'general', '· 유효기간이 지나거나 미사용한 폭죽은 수거 과정에서 화재 위험을 예방하기 위해 물에 충분히 담가서 적신 후 일반쓰레기로 배출합니다. · 종량제봉투에 배출하여 소각로에 투입되면 폭죽에 의한 위험은 발생하지 않습니다.', '["폭죽은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=452', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 유효기간이 지나거나 미사용한 폭죽은 수거 과정에서 화재 위험을 예방하기 위해 물에 충분히 담가서 적신 후 일반쓰레기로 배출합니다. · 종량제봉투에 배출하여 소각로에 투입되면 폭죽에 의한 위험은 발생하지 않습니다.', '· 물에 적신 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('고무볼', '고무볼', 'general', '· 고무볼은 팩의 재료를 믹스할때 사용하는 용기로 고무, 실리콘 재질로 재활용이 어려워 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세', '["고무볼은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=453', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 고무볼은 팩의 재료를 믹스할때 사용하는 용기로 고무, 실리콘 재질로 재활용이 어려워 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
