INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('방습제', '방습제', 'general', '· 방습제는 식품용 제습제로 주로 사용됩니다. 실리카겔, 비닐, 부직포 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을', '["방습제는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=457', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 방습제는 식품용 제습제로 주로 사용됩니다. 실리카겔, 비닐, 부직포 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('액정보호 필름', '액정보호 필름', 'general', '· 액정보호필름은 휴대용 전자제품의 화면에 부착하여 화면을 보호하는 용도로 사용되며 주로 유리, 우레탄 재질로 재활용이 어려워 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가', '["액정보호 필름은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=458', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 액정보호필름은 휴대용 전자제품의 화면에 부착하여 화면을 보호하는 용도로 사용되며 주로 유리, 우레탄 재질로 재활용이 어려워 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('빵끈', '빵끈', 'general', '· 빵끈은 철심을 종이나 비닐로 깜싼 것으로 빵 봉지 등 봉지와 같은 용기의 입구를 묶는 데 사용됩니다. · 빵끈은 크기가 작고 금속과 분리하는데 어려움이 있기 때문에 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인', '["빵끈은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=459', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 빵끈은 철심을 종이나 비닐로 깜싼 것으로 빵 봉지 등 봉지와 같은 용기의 입구를 묶는 데 사용됩니다. · 빵끈은 크기가 작고 금속과 분리하는데 어려움이 있기 때문에 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('짐볼', '짐볼', 'general', '· 짐볼은 주로 PVC(폴리염화비닐) 재질입니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다.', '["짐볼은 내용물(공기)를 제거하여 부피를 줄여 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=460', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 짐볼은 주로 PVC(폴리염화비닐) 재질입니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다.', '· 공기를 제거하여 최대한 부피를 줄인 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('밸런스볼', '밸런스볼', 'furniture', '· 밸런스볼은 주로 PVC, ABS 재질이며, 가정에서 배출하는 PVC, ABS 재질은 주로 소량으로 배출되어 재활용하기에 어려움이 있습니다. · 폴리염화비닐(PVC)은 다른 합성수지와 혼합되어 재활용될 경우 재활용제품의 강도가 떨어지고 재활용과정에서 염화수소와 같은 유해화학물질이 발생하는 등 다양한 문제를 일으키고 있어 재활용이 어렵습니다.', '["밸런스볼은 내용물(공기)를 제거한 후 종량제봉투로 배출합니다.", "크기가 큰 밸런스볼는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=461', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 밸런스볼은 주로 PVC, ABS 재질이며, 가정에서 배출하는 PVC, ABS 재질은 주로 소량으로 배출되어 재활용하기에 어려움이 있습니다. · 폴리염화비닐(PVC)은 다른 합성수지와 혼합되어 재활용될 경우 재활용제품의 강도가 떨어지고 재활용과정에서 염화수소와 같은 유해화학물질이 발생하는 등 다양한 문제를 일으키고 있어 재활용이 어렵습니다.', '· 공기를 제거하여 최대한 부피를 줄인 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('전자시계', '전자시계', 'electronics', '· 전자시계 등 시계류는 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다', '["전자시계는 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=462', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 전자시계 등 시계류는 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다 ※ 배출방법은 지역별로 차이가 있을...', '', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('합지벽지', '합지벽지', 'general', '· 합지벽지는 여러겹의 종이를 붙여 제작하므로 종이로 재활용이 가능하며, 다른 종이와 섞이지 않게 묶어서 배출합니다. · 다만 이물질(접착제, 곰팡이 등)이 묻어 있는 경우에는 재활용이 어려우므로 종량제봉투로 배출합니다. · 실크벽지는 종이 위에 PVC코팅이 되어 있어 재활용이 어려우므로 일반쓰레기로 배출합니다. · 인테리어 공사 등에서 발생한 폐기물은 공', '["합지벽지는 종이류로 배출합니다.", "실크벽지는 종량제봉투로 배출합니다.", "다량으로 배출할 때에는 지자체에 문의하여 공사장생활폐기물 전문 처리업체에 위탁하여 처리합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=463', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 합지벽지는 여러겹의 종이를 붙여 제작하므로 종이로 재활용이 가능하며, 다른 종이와 섞이지 않게 묶어서 배출합니다. · 다만 이물질(접착제, 곰팡이 등)이 묻어 있는 경우에는 재활용이 어려우므로 종량제봉투로 배출합니다. · 실크벽지는 종이 위에 PVC코팅이 되어 있어 재활용이 어려우므로 일반쓰레기로 배출합니다. · 인테리어 공사 등에서 발생한 폐기물은 공사장생활폐기물에 해당되며, 폐기물 특...', '· 리모델링, 인테리어 공사 등 일련의 공사 또는 작업 등으로 전체 기간 동안 발생하는 5톤 미만의 폐기물은 공사장생활폐기물에 해당되며, 올바른 배출방법은 해당 지자체에 문의', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "재활용폐기물", "종이", "공사장 생활폐기물"]');
