INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('투명 가림막', '투명 가림막', 'furniture', '· 투명 가림막은 아크릴, PC(폴리카보네이트), PET, 혼합플라스틱 등이 있으며 대부분 아크릴 재질입니다. · 가정에서 배출하는 경우에는 가림막의 재질별로 수거와 선별이 곤란하기 때문에 종량제봉투 또는 대형폐기물로 배출합니다. · 학교, 사무실, 식당 등 사업소에서 배출하는 경우에는 합성수지 전문 재활용업체에 위탁처리해야 합니다. ※ 배출방법은 지역별로', '["투명 가림막은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=471', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 투명 가림막은 아크릴, PC(폴리카보네이트), PET, 혼합플라스틱 등이 있으며 대부분 아크릴 재질입니다. · 가정에서 배출하는 경우에는 가림막의 재질별로 수거와 선별이 곤란하기 때문에 종량제봉투 또는 대형폐기물로 배출합니다. · 학교, 사무실, 식당 등 사업소에서 배출하는 경우에는 합성수지 전문 재활용업체에 위탁처리해야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
