INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 물엿 용기', '깨끗한 물엿 용기', 'plastic', '· 물엿, 꿀 등은 물로 헹구어 하수로 배출합니다. · 라벨은 제거하여 비닐류로 배출하며, 용기는 플라스틱 수거함으로 배출합니다. · 내용물(물엿, 꿀 등) 제거가 어려운 경우에는 뚜껑을 닫아 제품 그대로 종량제봉투로 배출하여 주시기 바랍니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따', '["깨끗한 물엿 용기는 플라스틱으로 배출합니다.", "내용물 제거가 어려운 경우 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=475', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 물엿, 꿀 등은 물로 헹구어 하수로 배출합니다. · 라벨은 제거하여 비닐류로 배출하며, 용기는 플라스틱 수거함으로 배출합니다. · 내용물(물엿, 꿀 등) 제거가 어려운 경우에는 뚜껑을 닫아 제품 그대로 종량제봉투로 배출하여 주시기 바랍니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('키보드 스킨', '키보드 스킨', 'general', '· 키보드 스킨은 주로 실리콘 재질로 재활용이 어려우므로 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기', '["키보드 스킨은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=476', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 키보드 스킨은 주로 실리콘 재질로 재활용이 어려우므로 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분리...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('화이트보드', '화이트보드', 'furniture', '· 화이트보드는 프레임은 나무, 알루미늄 재질이며 보드는 법랑(세라믹 코팅), 유리재질입니다. · 화이트 보드의 재질별로 분리하기 어렵거나 혼합재질인 경우에는 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요.', '["화이트보드는 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=477', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 화이트보드는 프레임은 나무, 알루미늄 재질이며 보드는 법랑(세라믹 코팅), 유리재질입니다. · 화이트 보드의 재질별로 분리하기 어렵거나 혼합재질인 경우에는 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('자석교구', '자석교구', 'general', '· 자석교구는 플라스틱, 자석 등이 혼합된 복합재질입니다. · 자석교구의 재질별로 분리하기 어렵거나 혼합재질인 혼합재질인 경우에는 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소', '["자석교구는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=478', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 자석교구는 플라스틱, 자석 등이 혼합된 복합재질입니다. · 자석교구의 재질별로 분리하기 어렵거나 혼합재질인 혼합재질인 경우에는 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('옥수수식기', '옥수수식기', 'general', '· 옥수수 식기(숟가락, 포크, 칼, 빨대 등)는 생분해성수지제품입니다. · 생분해성수지 제품은 일반 플라스틱과는 성질이 달라 플라스틱으로 배출 시 재활용을 저해하므로 종량제봉투로 배출합니다. · 생분해성수지제품(PLA)는 일정한 조건에서 미생물이나 효소에 의해 분해되는 플라스틱 또는 비닐로 환경표지 인증을 받은 제품입니다.', '["옥수수식기는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=479', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 옥수수 식기(숟가락, 포크, 칼, 빨대 등)는 생분해성수지제품입니다. · 생분해성수지 제품은 일반 플라스틱과는 성질이 달라 플라스틱으로 배출 시 재활용을 저해하므로 종량제봉투로 배출합니다. · 생분해성수지제품(PLA)는 일정한 조건에서 미생물이나 효소에 의해 분해되는 플라스틱 또는 비닐로 환경표지 인증을 받은 제품입니다.', '· 플라스틱 수거함으로 배출 불가', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('야구글러브', '야구글러브', 'general', '· 야구글러브는 주로 가죽 재질이며, 가죽제품은 재활용이 어려워 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소', '["야구글러브는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=480', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 야구글러브는 주로 가죽 재질이며, 가죽제품은 재활용이 어려워 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('멜로디언', '멜로디언', 'furniture', '· 멜로디언 본체와 호스는 주로 ABS, PVC 재질입니다. 가정에서 배출하는 PVC, ABS 재질은 주로 소량으로 배출되어 재활용하기에 어려움이 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장', '["멜로디언은 종량제봉투로 배출합니다.", "종량제봉투에 담기 어려운 경우에는 대형폐기물로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=481', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 멜로디언 본체와 호스는 주로 ABS, PVC 재질입니다. 가정에서 배출하는 PVC, ABS 재질은 주로 소량으로 배출되어 재활용하기에 어려움이 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('침낭', '침낭', 'furniture', '· 침낭은 천, 솜 등으로 구성되어져 있습니다. · 솜은 천연섬유, 합성섬유 등 다양한 소재가 있으며, 솜 제품은 사용시 오염이 많아 재사용이 어려워 의류수거함으로 배출하기 어려운 품목이며 일반쓰레기로 배출합니다. · 침낭의 크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다.', '["침낭은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=482', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 침낭은 천, 솜 등으로 구성되어져 있습니다. · 솜은 천연섬유, 합성섬유 등 다양한 소재가 있으며, 솜 제품은 사용시 오염이 많아 재사용이 어려워 의류수거함으로 배출하기 어려운 품목이며 일반쓰레기로 배출합니다. · 침낭의 크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다.', '· 의류수거함에 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('통장', '통장', 'general', '· 통장은 종이재질로 재활용이 가능합니다. · 다만, 통장에는 이름, 계좌정보 등 개인 정보가 기재되어 있어 개인정보 보호를 위하여 찢은 후 종량제봉투로 배출하는 것이 좋습니다.', '["통장은 종이류로 배출하여야 하나, 개인정보 유출 등이 우려될 경우 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=483', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 통장은 종이재질로 재활용이 가능합니다. · 다만, 통장에는 이름, 계좌정보 등 개인 정보가 기재되어 있어 개인정보 보호를 위하여 찢은 후 종량제봉투로 배출하는 것이 좋습니다.', '· 통장은 종이로 재활용이 가능하나 개인정보보호를 위해 안전하게 종량제봉투로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('핸드폰 케이스', '핸드폰 케이스', 'general', '· 핸드폰 케이스는 핸드폰을 보호하는 용도로 사용되며 주로 실리콘, 가죽, 플라스틱 등 다양한 재질이 혼합된 제품으로 재활용이 어려워 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출', '["핸드폰 케이스는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=484', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 핸드폰 케이스는 핸드폰을 보호하는 용도로 사용되며 주로 실리콘, 가죽, 플라스틱 등 다양한 재질이 혼합된 제품으로 재활용이 어려워 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
