INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('인형', '인형', 'furniture', '· 인형은 천, 솜 등으로 구성되어져 있습니다. · 솜은 천연섬유, 합성섬유 등 다양한 소재가 있으며, 솜 제품은 사용시 오염이 많아 재사용이 어려워 의류수거함으로 배출하기 어려운 품목이며 일반쓰레기로 배출합니다. · 인형의 크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다.', '["인형은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=488', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 인형은 천, 솜 등으로 구성되어져 있습니다. · 솜은 천연섬유, 합성섬유 등 다양한 소재가 있으며, 솜 제품은 사용시 오염이 많아 재사용이 어려워 의류수거함으로 배출하기 어려운 품목이며 일반쓰레기로 배출합니다. · 인형의 크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다.', '· 의류수거함에 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('채칼', '채칼', 'general', '· 가위, 칼, 채칼 등과 같은 날카로운 제품은 금속재질이더라도 배출자, 수거원 등이 다칠 우려가 있으므로 주의하여 종량제봉투로 배출해야 합니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다.', '["채칼는 신문지, 테이프 등을 활용하여 충분히 감싼 후 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=489', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가위, 칼, 채칼 등과 같은 날카로운 제품은 금속재질이더라도 배출자, 수거원 등이 다칠 우려가 있으므로 주의하여 종량제봉투로 배출해야 합니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다.', '· 채칼과 같은 날카롭고 위험한 폐기물을 배출할 때에는 날카로운 부분이 외부로 노출되어 사람이 찔리거나 베이지 않도록 용기에 담거나 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('크레파스', '크레파스', 'general', '· 크레파스는 그림을 그릴때 사용하는 그리기 도구 중 하나로 안료와 왁스, 오일을 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의', '["크레파스는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=490', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 크레파스는 그림을 그릴때 사용하는 그리기 도구 중 하나로 안료와 왁스, 오일을 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('수영복', '수영복', 'general', '· 수영복은 폴리우레탄, 폴리에스터, 나일론 등 여러 재질이 혼합되어 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소', '["수영복은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=491', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 수영복은 폴리우레탄, 폴리에스터, 나일론 등 여러 재질이 혼합되어 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('화장지', '화장지', 'general', '· 키친타월, 핸드타월 등 사용한 화장지는 이물질이 묻어있어 재활용이 어려워 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위', '["화장지는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=492', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 키친타월, 핸드타월 등 사용한 화장지는 이물질이 묻어있어 재활용이 어려워 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('보자기', '보자기', 'general', '· 보자기는 실크, 린넨 등의 재질로 물건을 포장하는데 사용하며, 가정에서 주로 소량으로 발생되어 일반쓰레기로 배출합니다.', '["보자기는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=493', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 보자기는 실크, 린넨 등의 재질로 물건을 포장하는데 사용하며, 가정에서 주로 소량으로 발생되어 일반쓰레기로 배출합니다.', '· 의류수거함에 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('눈썹칼', '눈썹칼', 'general', '· 눈썹칼은 플라스틱과 금속재질이 혼합된 복합재질 제품으로재질별 분리가 어려우므로 일반쓰레기로 배출합니다. · 가위, 칼과 같은 날카로운 제품은 금속재질이더라도 배출자, 수거원 등이 다칠 우려가 있으므로 주의하여 종량제봉투로 배출해야 합니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및', '["눈썹칼은 신문지, 테이프 등을 활용하여 충분히 감싼 후 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=494', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 눈썹칼은 플라스틱과 금속재질이 혼합된 복합재질 제품으로재질별 분리가 어려우므로 일반쓰레기로 배출합니다. · 가위, 칼과 같은 날카로운 제품은 금속재질이더라도 배출자, 수거원 등이 다칠 우려가 있으므로 주의하여 종량제봉투로 배출해야 합니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다.', '· 칼과 같은 날카롭고 위험한 폐기물을 배출할 때에는 날카로운 부분이 외부로 노출되어 사람이 찔리거나 베이지 않도록 용기에 담거나 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('레진', '레진', 'general', '· 레진아트 재료인 레진(2액형 레진, UV레진 등)은 폴리우레탄 수지로 재활용이 어렵습니다. · 액체 레진은 고체로 굳히거나, 내용물을 휴지 등으로 흡수시킨 후 종량제봉투로 배출합니다.', '["레진은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=495', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 레진아트 재료인 레진(2액형 레진, UV레진 등)은 폴리우레탄 수지로 재활용이 어렵습니다. · 액체 레진은 고체로 굳히거나, 내용물을 휴지 등으로 흡수시킨 후 종량제봉투로 배출합니다.', '· 내용물을 하수구로 배출 불가', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('유리창', '유리창', 'general', '· 유리창과 같은 유리제품은 재활용이 어렵습니다. · 재활용이 어렵고 불에 타지 않는 불연성폐기물은 수거 후 매립장으로 운반되어 매립하고 있습니다. · 인테리어 공사 등에서 발생한 폐기물은 공사장생활폐기물에 해당되며, 폐기물 특성에 따라 종량제봉투, 불연성 마대, 재활용품 또는 대형폐기물로 배출하여야 합니다. 공사장생활폐기물을 다량으로 배출할 시 지자체에', '["유리창은 불연성종량제봉투(마대)로 배출합니다.", "크기가 크거나 무게가 무거운 제품은 대형폐기물로 배출합니다.", "다량으로 배출할 때에는 지자체에 문의하여 공사장생활폐기물 전문 처리업체에 위탁하여 처리합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=496', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 유리창과 같은 유리제품은 재활용이 어렵습니다. · 재활용이 어렵고 불에 타지 않는 불연성폐기물은 수거 후 매립장으로 운반되어 매립하고 있습니다. · 인테리어 공사 등에서 발생한 폐기물은 공사장생활폐기물에 해당되며, 폐기물 특성에 따라 종량제봉투, 불연성 마대, 재활용품 또는 대형폐기물로 배출하여야 합니다. 공사장생활폐기물을 다량으로 배출할 시 지자체에 문의하여 공사장생활폐기물 전문 수거업...', '· 유리 제품은 배출, 운반과정에서 깨질 우려가 있으므로 가능한 주의하여 배출 · 깨진 유리는 날카로워 외부로 누출될 시 사람이 다칠 우려가 있으므로 베이지 않도록 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출 · 리모델링, 인테리어 공사 등 일련의 공사 또는 작...', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물", "대형폐기물", "공사장 생활폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('계량컵의 재질', '계량컵의 재질', 'can', '· 계량컵은 조리시 식재료의 계량을 위해 사용하는 제품으로 내열유리, 금속, 플라스틱 등 다양한 재질로 제작됩니다. · 플라스틱, 금속 등 단일재질 제품은 재활용이 가능하므로 전용수거함으로 배출합니다. · 내열유리로 만들어진 제품은 재활용이 어려우며 불에 타지 않는 불연성 폐기물로 전용봉투(마대)에 담아 배출합니다. · 재활용이 어렵고 불에 타지 않는 불연', '["계량컵의 재질에 맞게 고철수거함, 플라스틱 수거함 등으로 배출합니다.", "계량컵의 재질이 유리 재질인 경우에는 불연성 종량제봉투(마대)로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=497', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 계량컵은 조리시 식재료의 계량을 위해 사용하는 제품으로 내열유리, 금속, 플라스틱 등 다양한 재질로 제작됩니다. · 플라스틱, 금속 등 단일재질 제품은 재활용이 가능하므로 전용수거함으로 배출합니다. · 내열유리로 만들어진 제품은 재활용이 어려우며 불에 타지 않는 불연성 폐기물로 전용봉투(마대)에 담아 배출합니다. · 재활용이 어렵고 불에 타지 않는 불연성종량제폐기물은 수거 후 매립장으로...', '· 재질에 맞게 배출', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물", "재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨진유리', '깨진유리', 'general', '· 깨진 유리는 재활용이 어려우며 불에타지 않는 폐기물로 불연성폐기물에 해당됩니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. · 가정에서 발생한 소량의 유리는 신문지, 테이프 등으로 감싼 후 종량제봉투로 배출하셔도 괜찮습니다.', '["깨진유리는 불연성 종량제 마대로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=498', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 깨진 유리는 재활용이 어려우며 불에타지 않는 폐기물로 불연성폐기물에 해당됩니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. · 가정에서 발생한 소량의 유리는 신문지, 테이프 등으로 감싼 후 종량제봉투로 배출하셔도 괜찮습니다.', '· 깨진 유리는 날카로워 외부로 누출될 시 사람이 다칠 우려가 있으므로 베이지 않도록 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('내열식기', '내열식기', 'general', '· 내열유리란 일반 유리와 달리 내열성이 강하고 급격한 온도변화에도 견딜 수 있는 유리를 말합니다. · 내열유리로 만들어진 제품은 재활용이 어려우며 불에 타지 않는 불연성 폐기물로 전용봉투(마대)에 담아 배출하여야 합니다. · 재활용이 어렵고 불에 타지 않는 불연성폐기물은 수거 후 매립장으로 운반되어 매립하고 있습니다. ※ 배출방법은 지역별로 차이가 있을', '["내열식기는 불연성 종량제봉투(마대)로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=499', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 내열유리란 일반 유리와 달리 내열성이 강하고 급격한 온도변화에도 견딜 수 있는 유리를 말합니다. · 내열유리로 만들어진 제품은 재활용이 어려우며 불에 타지 않는 불연성 폐기물로 전용봉투(마대)에 담아 배출하여야 합니다. · 재활용이 어렵고 불에 타지 않는 불연성폐기물은 수거 후 매립장으로 운반되어 매립하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정...', '', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('내열냄비', '내열냄비', 'general', '· 내열유리란 일반 유리와 달리 내열성이 강하고 급격한 온도변화에도 견딜 수 있는 유리를 말합니다. · 내열유리로 만들어진 제품은 재활용이 어려우며 불에 타지 않는 불연성 폐기물로 전용봉투(마대)에 담아 배출하여야 합니다. · 재활용이 어렵고 불에 타지 않는 불연성폐기물은 수거 후 매립장으로 운반되어 매립하고 있습니다. ※ 배출방법은 지역별로 차이가 있을', '["내열냄비는 불연성 종량제봉투(마대)로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=500', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 내열유리란 일반 유리와 달리 내열성이 강하고 급격한 온도변화에도 견딜 수 있는 유리를 말합니다. · 내열유리로 만들어진 제품은 재활용이 어려우며 불에 타지 않는 불연성 폐기물로 전용봉투(마대)에 담아 배출하여야 합니다. · 재활용이 어렵고 불에 타지 않는 불연성폐기물은 수거 후 매립장으로 운반되어 매립하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정...', '', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('뚝배기', '뚝배기', 'general', '· 뚝배기는 찌개를 끓이거나 국을 담을 때 사용하는 오지그릇으로 재활용이 어렵고 불에 타지않는 폐기물로 불연성폐기물에 해당됩니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니', '["뚝배기는 불연성 종량제봉투(마대)로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=501', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 뚝배기는 찌개를 끓이거나 국을 담을 때 사용하는 오지그릇으로 재활용이 어렵고 불에 타지않는 폐기물로 불연성폐기물에 해당됩니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보...', '', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('머그잔', '머그잔', 'general', '· 머그잔은 주로 가정에서 사용하는 잔으로 주로 사기 또는 도자기 재질로 되어있습니다. · 도자기, 사기재질의 제품은 재활용이 어렵고 불에 타지 않는 폐기물로 불연성폐기물에 해당됩니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는', '["머그잔은 불연성 종량제봉투(마대)로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=502', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 머그잔은 주로 가정에서 사용하는 잔으로 주로 사기 또는 도자기 재질로 되어있습니다. · 도자기, 사기재질의 제품은 재활용이 어렵고 불에 타지 않는 폐기물로 불연성폐기물에 해당됩니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따...', '', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('유리잔', '유리잔', 'general', '· 소주잔, 맥주잔과 같은 유리컵은 재활용이 어렵고 불에 타지 않는 폐기물로 불연성폐기물에 해당됩니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. ·소량의 유리잔을 배출하실 때에는 제품이 깨지지 않도록 주의하여 종량제봉투로 배출하며, 유리잔이 깨진 경우에는 작업자, 수거원 등이 다치지 않도록 신문지, 테이', '["유리잔은 불연성 종량제봉투(마대)로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=503', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 소주잔, 맥주잔과 같은 유리컵은 재활용이 어렵고 불에 타지 않는 폐기물로 불연성폐기물에 해당됩니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. ·소량의 유리잔을 배출하실 때에는 제품이 깨지지 않도록 주의하여 종량제봉투로 배출하며, 유리잔이 깨진 경우에는 작업자, 수거원 등이 다치지 않도록 신문지, 테이프 등을 활용하여 충분히 감싼 후 배...', '· 깨진 유리는 날카로워 외부로 누출될 시 사람이 다칠 우려가 있으므로 베이지 않도록 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('크리스탈 재질의 메달', '크리스탈 재질의 메달', 'general', '· 메달(크리스탈)은 재활용이 어렵고 불에 타지 않는 폐기물로 불연성폐기물에 해당됩니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요.', '["크리스탈 재질의 메달은 불연성 종량제봉투(마대)로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=504', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 메달(크리스탈)은 재활용이 어렵고 불에 타지 않는 폐기물로 불연성폐기물에 해당됩니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습...', '', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('메트로놈', '메트로놈', 'general', '· 메트로놈은 태엽을 감는 아날로그 방식과 전지가 포함된 디지털 방식이 있습니다. · 메트로놈은 플라스틱, 고철, 목재 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 디지털 방식의 메트로놈을 배출하실 때에는 제품에 포함된 전지를 제거한 후 배출합니다.', '["메트로놈은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=505', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 메트로놈은 태엽을 감는 아날로그 방식과 전지가 포함된 디지털 방식이 있습니다. · 메트로놈은 플라스틱, 고철, 목재 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 디지털 방식의 메트로놈을 배출하실 때에는 제품에 포함된 전지를 제거한 후 배출합니다.', '· 내장된 전지가 분리가 가능한 경우에는 제거 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('멜라민 그릇', '멜라민 그릇', 'general', '· 멜라민 수지는 열에 잘 변형되지 않는 열경화성 수지 제품으로 주로 고급 기계나 식기류, 건축용 장식판에 사용됩니다. · 합성수지 제품(플라스틱 제품)은 선별압축-파쇄-세척-용융압출 등의 과정을 거쳐 재활용하고 있습니다. · 열경화성 수지 제품의 경우 열에 쉽게 변형되지 않아 재활용이 어렵습니다. · 열경화성 수지에는 페놀수지, 실리콘수지, 에폭시 수지', '["멜라민 그릇은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=506', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 멜라민 수지는 열에 잘 변형되지 않는 열경화성 수지 제품으로 주로 고급 기계나 식기류, 건축용 장식판에 사용됩니다. · 합성수지 제품(플라스틱 제품)은 선별압축-파쇄-세척-용융압출 등의 과정을 거쳐 재활용하고 있습니다. · 열경화성 수지 제품의 경우 열에 쉽게 변형되지 않아 재활용이 어렵습니다. · 열경화성 수지에는 페놀수지, 실리콘수지, 에폭시 수지 등이 있습니다.', '· 열경화성 수지 제품은 재활용이 어렵습니다.', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('벤토나이트 모래', '벤토나이트 모래', 'general', '· 고양이 배변모래로 주로 사용하는 제품으로 두부 모래, 벤토나이트 모래 등이있습니다. · 벤토나이트 모래는 재활용이 어렵고 불에 타지 않는 불연성폐기물에 해당됩니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다.', '["벤토나이트 모래는 불연성종량제봉투(마대)로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=507', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 고양이 배변모래로 주로 사용하는 제품으로 두부 모래, 벤토나이트 모래 등이있습니다. · 벤토나이트 모래는 재활용이 어렵고 불에 타지 않는 불연성폐기물에 해당됩니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다.', '· 하수관이 막힐수 있으므로 변기, 하수구에 배출 금지', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('벽돌', '벽돌', 'general', '· 벽돌은 진흙과 모래를 반죽한 후 구워 만든 건축재료로 시멘트, 콘크리트 등 종류가 다양합니다. · 벽돌은 재활용이 어렵고 불에타지 않은 폐기물로 불연성종량제봉투(마대)로 배출하여야 합니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. · 인테리어 공사 등에서 발생한 폐기물은 공사장생활폐기물에 해당되며,', '["벽돌은 불연성종량제봉투(마대)로 배출합니다.", "다량으로 배출할 때에는 지자체에 문의하여 공사장생활폐기물 전문 처리업체에 위탁하여 처리합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=508', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 벽돌은 진흙과 모래를 반죽한 후 구워 만든 건축재료로 시멘트, 콘크리트 등 종류가 다양합니다. · 벽돌은 재활용이 어렵고 불에타지 않은 폐기물로 불연성종량제봉투(마대)로 배출하여야 합니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. · 인테리어 공사 등에서 발생한 폐기물은 공사장생활폐기물에 해당되며, 폐기물 특성에 따라 종량제봉투, 불연...', '· 리모델링, 인테리어 공사 등 일련의 공사 또는 작업 등으로 전체 기간 동안 발생하는 5톤 미만의 폐기물은 공사장생활폐기물에 해당되며, 올바른 배출방법은 해당 지자체에 문의', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물", "공사장 생활폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('사기 그릇', '사기 그릇', 'general', '· 사기 그릇은 고령토, 석영 등으로 빚어서 만든 흰 그릇으로 재활용이 어렵고 불에 타지 않은 불연성폐기물에 해당됩니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까', '["사기 그릇은 불연성 종량제봉투(마대)로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=509', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 사기 그릇은 고령토, 석영 등으로 빚어서 만든 흰 그릇으로 재활용이 어렵고 불에 타지 않은 불연성폐기물에 해당됩니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현...', '', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('와인병', '와인병', 'glass', '· 유리병은 3색(무색, 녹색, 갈색)으로 분류한 후 파쇄∙분쇄, 용융과정을 거쳐 재활용하고 있습니다. · 이 과정에서 와인병과 같은 이색(파란색, 검정색, 자주색 등) 유리병은 혼색 유리병으로 분류 및 분쇄 후 건설자재 등으로 재활용되고 있으므로 유리병으로 배출합니다.', '["와인병은 유리병 수거함에 배출합니다"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '·깨지지 않도록 주의', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('화분 흙', '화분 흙', 'general', '· 흙은 불에 타지 않는 폐기물로 불연성폐기물에 해당됩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장', '["화분 흙은 불연성 종량제봉투(특수규격마대)로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=512', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 흙은 불에 타지 않는 폐기물로 불연성폐기물에 해당됩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분리배출 장소 선택 배출장...', '', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('어항', '어항', 'furniture', '· 어항은 대부분 유리제품으로 불에 타지 않은 재질이므로 불연성폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보', '["어항은 불연성종량제봉투(특수규격마대)에 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=513', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 어항은 대부분 유리제품으로 불에 타지 않은 재질이므로 불연성폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분...', '', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('타일', '타일', 'general', '·타일은 대리석 등 재질로 불에 타지 않은 재질이므로 불연성폐기물로 배출합니다. · 인테리어 공사 등에서 발생한 폐기물은 공사장생활폐기물에 해당되며, 폐기물 특성에 따라 종량제봉투, 불연성 마대, 재활용품 또는 대형폐기물로 배출하여야 합니다. 공사장생활폐기물을 다량으로 배출할 시 지자체에 문의하여 공사장생활폐기물 전문 수거업체에 연락하여 처리할 수 있습니다', '["타일은 불연성종량제봉투(특수규격마대)에 배출합니다.", "다량으로 배출할 때에는 지자체에 문의하여 공사장생활폐기물 전문 처리업체에 위탁하여 처리합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=514', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·타일은 대리석 등 재질로 불에 타지 않은 재질이므로 불연성폐기물로 배출합니다. · 인테리어 공사 등에서 발생한 폐기물은 공사장생활폐기물에 해당되며, 폐기물 특성에 따라 종량제봉투, 불연성 마대, 재활용품 또는 대형폐기물로 배출하여야 합니다. 공사장생활폐기물을 다량으로 배출할 시 지자체에 문의하여 공사장생활폐기물 전문 수거업체에 연락하여 처리할 수 있습니다.', '· 리모델링, 인테리어 공사 등 일련의 공사 또는 작업 등으로 전체 기간 동안 발생하는 5톤 미만의 폐기물은 공사장생활폐기물에 해당되며, 올바른 배출방법은 해당 지자체에 문의', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물", "공사장 생활폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('MP3', 'MP3', 'electronics', '· MP3 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출방', '["MP3는 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=516', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· MP3 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니...', '', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('붓', '붓', 'general', '· 붓은 글씨를 쓰거나 그림을 그릴 때 사용하는 도구로 주로 나무로된 자루 끝에 짐승의 털을 꽂아서 먹이나 물감을 찍어 사용합니다. · 붓은 나무와 털이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '["붓은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=517', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 붓은 글씨를 쓰거나 그림을 그릴 때 사용하는 도구로 주로 나무로된 자루 끝에 짐승의 털을 꽂아서 먹이나 물감을 찍어 사용합니다. · 붓은 나무와 털이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '· 목재제품은 재활용이 어려우므로 종량제봉투로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('캣타워', '캣타워', 'furniture', '· 캣타워는 나무, 섬유 등 복합재질로 재활용이 어려워 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기', '["캣타워는 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=518', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 캣타워는 나무, 섬유 등 복합재질로 재활용이 어려워 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분리배...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('약통 용기', '약통 용기', 'plastic', '· 약통 용기는 플라스틱(PE) 재질로 플라스틱 수거함으로 배출합니다. · 내용물인 약은 폐의약품이므로 가까운 약국이나 보건소, 주민센터 등에 비치된 폐의약품전용수거함으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요.', '["약통 용기는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=521', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 약통 용기는 플라스틱(PE) 재질로 플라스틱 수거함으로 배출합니다. · 내용물인 약은 폐의약품이므로 가까운 약국이나 보건소, 주민센터 등에 비치된 폐의약품전용수거함으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('점착식 메모지', '점착식 메모지', 'general', '· 점착식 메모지는 종이에 점착제가 발려있어 쉽게 떼어낼 수 있는 메모지로 크기가 작고 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요.', '["점착식 메모지는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=522', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 점착식 메모지는 종이에 점착제가 발려있어 쉽게 떼어낼 수 있는 메모지로 크기가 작고 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('보호대', '보호대', 'general', '· 손목, 발목, 무릎 등 보호대는 플라스틱, 폼, 섬유 등 다양한 재질이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을', '["보호대는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=524', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 손목, 발목, 무릎 등 보호대는 플라스틱, 폼, 섬유 등 다양한 재질이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('고무신발 액세서리', '고무신발 액세서리', 'general', '· 고무신발 액세서리는 대부분 PVC재질의 제품입니다. · 가정에서 사용하는 EVA는 주로 샌달, 구두창 등의 제품으로 사용하고 있으며, 주로 소량으로 발생되어 재활용이 어렵습니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이', '["고무신발 액세서리는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=527', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 고무신발 액세서리는 대부분 PVC재질의 제품입니다. · 가정에서 사용하는 EVA는 주로 샌달, 구두창 등의 제품으로 사용하고 있으며, 주로 소량으로 발생되어 재활용이 어렵습니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('일반팩과 멸균팩', '일반팩과 멸균팩', 'paper', '·종이팩은 일반팩(우유팩)과 멸균팩(두유팩, 소주팩, 주스팩)이 있습니다. ·일반팩은 안팎에 PE 필름이 첩합되어 있고, 멸균팩은 알루미늄 호일, PE 등이 첩합되어 있습니다.', '["일반팩과 멸균팩은 구분 없이 배출합니다.", "종이팩 수거함으로 배출하고, 수거함이 없는 경우 다른 종이류와 구분될 수 있도록 끈 등으로 묶어 종이류 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=529', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·종이팩은 일반팩(우유팩)과 멸균팩(두유팩, 소주팩, 주스팩)이 있습니다. ·일반팩은 안팎에 PE 필름이 첩합되어 있고, 멸균팩은 알루미늄 호일, PE 등이 첩합되어 있습니다.', '·내용물, 빨대, 비닐을 제거하고 물로 헹군 후 배출 ·종이팩은 일반 종이와 구분하여 배출', '2026-05-18', 0, '["재활용폐기물", "종이팩", "일반팩"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('합성수지 또', '합성수지 또', 'plastic', '·혼합재질 플라스틱, 열경화성수지 제품, 오염된 용기는 일반종량제폐기물로 배출합니다. ·생분해성수지 제품은 플라스틱에 배출하지 않고 별도 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없', '["합성수지 또는 플라스틱(Plastic)으로 제작된 용기 또는 트레이는 플라스틱 수거함으로 배출합니다. ·내용물과 이물질, 부속품을 제거하고 물로 헹군 후 배출합니다.", "PET, PP, PE, PS 등 재질 구분 없이 배출합니다.", "치약용기와 같이 물로 헹굴수 없는 경우 내용물만 비우고 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=531', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·혼합재질 플라스틱, 열경화성수지 제품, 오염된 용기는 일반종량제폐기물로 배출합니다. ·생분해성수지 제품은 플라스틱에 배출하지 않고 별도 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 발포합성수지 포장용기', '깨끗한 발포합성수지 포장용기', 'styrofoam', '· 발포합성수지는 PP, PE, PS 등의 합성수지를 증기로 부풀린 제품을 말하며, 대부분의 발포합성수지는 EPS이며 일명 스티로폼을 말합니다. · 발포합성수지의 종류로는 식품·과일·전자제품 등 포장용기, 단열재 등이 있습니다.', '["·깨끗한 발포합성수지 포장용기는 스티로폼 수거함으로 배출합니다.", "EPP, EPS, EPE 등 재질과 색상 구분 없이 배출합니다.(유색도 EPR 대상품목)", "TV, 컴퓨터 등 전자제품 구입시 발생한 발포합성수지는 가급적 구입처로 반납합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=533', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 발포합성수지는 PP, PE, PS 등의 합성수지를 증기로 부풀린 제품을 말하며, 대부분의 발포합성수지는 EPS이며 일명 스티로폼을 말합니다. · 발포합성수지의 종류로는 식품·과일·전자제품 등 포장용기, 단열재 등이 있습니다.', '·부착상표, 테이프 등 스티로폼과 다른 재질은 제거한 배출', '2026-05-18', 0, '["재활용폐기물", "발포합성수지(스티로폼 등)"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('금속류', '금속류', 'can', '· 금속류의 종류에는 금속캔, 기타캔류, 고철이 있습니다. - 금속캔: 철캔, 알루미늄캔 - 기타캔류: 부탄가스, 살충제용기 등 - 고철: 철, 알루미늄, 스테인리스 등으로 제작된 금속제품 ·가위, 칼, 송곳 등 날카로운 금속은 종이와 테이프를 이용하여 안전하게 감싼 후 일반종량제 폐기물로 배출합니다. ·우산, 철삽, 스테이플러와 같이 나무, 플라스틱 등', '["금속류는 금속캔 수거함 또는 고철수거함으로 배출합니다. ·부탄가스, 살충제용기 등의 기타캔류는 폭발, 화재 예방을 위해 노즐을 눌러 가스를 제거한 후 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=535', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 금속류의 종류에는 금속캔, 기타캔류, 고철이 있습니다. - 금속캔: 철캔, 알루미늄캔 - 기타캔류: 부탄가스, 살충제용기 등 - 고철: 철, 알루미늄, 스테인리스 등으로 제작된 금속제품 ·가위, 칼, 송곳 등 날카로운 금속은 종이와 테이프를 이용하여 안전하게 감싼 후 일반종량제 폐기물로 배출합니다. ·우산, 철삽, 스테이플러와 같이 나무, 플라스틱 등 재질이 많이 섞인 경우 일반종량제폐기...', '·내용물을 비우고 물로 헹군 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('대형폐기물', '대형폐기물', 'furniture', '· 대형폐기물은 종량제봉투에 담기 어려운 크기의 폐기물(가구, 침구류, 가전제품, 생활용품 등)입니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현', '["대형폐기물은 스티커 발급, 재활용센터 판매, 무상수거서비스를 이용하여 배출합니다. -읍·면·동 주민센터, 인터넷, 모바일 등을 이용하여 대형폐기물 스티커를 구매, 부착하여 배출-재사용이 가능한 제품을 지역 재활용센터에 판매-전기전자제품 대형폐기물의 경우 무상수거서비스(1599-0903) 이용"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=539', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 대형폐기물은 종량제봉투에 담기 어려운 크기의 폐기물(가구, 침구류, 가전제품, 생활용품 등)입니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서...', '', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('음식물류폐기물의 수분', '음식물류폐기물의 수분', 'food', '· 음식물류폐기물은 식재료 및 식품의 생산·유통·조리 등의 과정에서 발생하는 쓰레기와 남겨서 버려지는 음식물입니다. · 음식물류폐기물에는 곡식, 채소, 과일껍질, 상한음식, 남은 음식물이 해당됩니다.', '["음식물류폐기물의 수분을 줄이고 이물질을 제거한 후 음식물종량제 방식으로 배출합니다.", "음식물종량제 방식은 전용봉투, 전용칩, 전용스티커, RFID 방식이 있습니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=541', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 식재료 및 식품의 생산·유통·조리 등의 과정에서 발생하는 쓰레기와 남겨서 버려지는 음식물입니다. · 음식물류폐기물에는 곡식, 채소, 과일껍질, 상한음식, 남은 음식물이 해당됩니다.', '· 동물의 사료에 적합하지 않거나 기계설비의 고장을 일으킬 수 있는 음식물은 일반종량제폐기물로 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('재활용가능한 것', '재활용가능한 것', 'general', '· 일반종량제폐기물은 휴지, 나무제품, 플라스틱 조각, 고무제품 등 재활용이 어렵고 불에 타는 폐기물입니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요.', '["재활용가능한 것을 최대한 분리한 후 일반가연성종량제봉투에 담아 배출합니다.", "봉투에 담기 어려운 폐기물은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=542', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 일반종량제폐기물은 휴지, 나무제품, 플라스틱 조각, 고무제품 등 재활용이 어렵고 불에 타는 폐기물입니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('불연성 특수규격마대', '불연성 특수규격마대', 'furniture', '·불연성종량제폐기물은 유리, 벽돌, 내열식기류, 도자기, 연탄재 등 재활용이 어렵고 불에 타지 않는 폐기물입니다.', '["불연성 특수규격마대에 담아 배출하거나, 대형폐기물로 배출합니다※ 연탄재는 지자체 조례에 따라 정하는 배출방법에 따라 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=543', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·불연성종량제폐기물은 유리, 벽돌, 내열식기류, 도자기, 연탄재 등 재활용이 어렵고 불에 타지 않는 폐기물입니다.', '·특수규격마대는 지자체가 지정한 판매소에서 구매할 수 있음', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('공사장 생활폐기물', '공사장 생활폐기물', 'general', '· 공사장 생활폐기물은 리모델링 작업, 인테리어 공사 등의 과정에서 발생하는 폐기물(건설폐재류, 폐목재, 고철, 가연성폐기물 등으로서 5톤 미만인 경우)입니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배', '["공사장 생활폐기물은 가연성, 불연성, 재활용가능성에 따라 분리합니다.", "성상에 따라 종량제, 대형폐기물, 재활용 등으로 배출합니다.", "종량제봉투나 대형폐기물로 배출하기 곤란한 경우에는 지자체가 지정한 공공선별장 또는 전문업체에 문의하여 수거를 신청하여 배출합니다. -일반종량제폐기물로 배출: 폐벽지, 소량의 폐합성수지 등 불에 타는 폐기물-불연성종량제폐기물 배출: 폐유리, 폐타일, 폐벽돌 등 불에 타지 않는 건설폐재-대형폐기물로 배출: 싱크대, 가구류(소파 등), 폐목재, 세면대, 변기, 장판 등 대형폐기물-재활용품으로 배출 : 고철, 플라스틱, 종이류 등 재활용"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=544', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 공사장 생활폐기물은 리모델링 작업, 인테리어 공사 등의 과정에서 발생하는 폐기물(건설폐재류, 폐목재, 고철, 가연성폐기물 등으로서 5톤 미만인 경우)입니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역...', '', '2026-05-18', 0, '["공사장 생활폐기물", "일반종량제폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('생활계 유해폐기물 전용수거함', '생활계 유해폐기물 전용수거함', 'medicine', '· 생활계 유해폐기물은 폐기물의 배출, 수거 과정에서 외부에 유출되어 사람과 주변환경에 피해를 유발할 수 있는 생활폐기물입니다. ·생활계 유해폐기물은 농약, 페인트, 광택제, 접착제, 의약품, 수은함유폐기물(온도계, 혈압계 등), 천연방사성제품 생활폐기물 등이 해당됩니다.', '["생활계 유해폐기물 전용수거함에 배출합니다. -농약, 페인트,락카, 접착제, 광택제 : 파손으로 인하여 폐기물이 유출되지 않도록 밀봉한 후 전용수거함에 배출-폐의약품 : 약국, 보건소, 주민센터 등 전용수거함에 배출하거나 우정사업본부와 수거계약을 한 지자체는 우체통에 배출(물약 제외)-수은함유폐기물 :", "제품의 파손으로 인하여 수은이 유출되지 않도록 포장한 후 배출-천연방사성생활폐기물 : 생활주변방사선 정보서비스에 문의하여 방사선 측정을 실시하고 지자체에서 정하는 방법에 따라 배출 ·전용수거함이 없는 경우에는 밀봉 등의 조치를 한 후 일반종량제폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=545', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 생활계 유해폐기물은 폐기물의 배출, 수거 과정에서 외부에 유출되어 사람과 주변환경에 피해를 유발할 수 있는 생활폐기물입니다. ·생활계 유해폐기물은 농약, 페인트, 광택제, 접착제, 의약품, 수은함유폐기물(온도계, 혈압계 등), 천연방사성제품 생활폐기물 등이 해당됩니다.', '', '2026-05-18', 0, '["생활계 유해폐기물", "폐농약", "폐의약품"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('영농폐비닐 및 농약용기', '영농폐비닐 및 농약용기', 'general', '·영농폐기물은 영농폐비닐과 농약 용기입니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분리배', '["영농폐비닐 및 농약용기는 지자체 공동집하장에 배출하고 한국환경공단에서 처리합니다. -영농폐비닐은 흙, 자갈, 잡초 등 이물질을 제거한 후 재질별, 색상별로 구분하여 배출 지자체별, 마을별 공동집하장에 배출, 가까운 한국환경공단 운영수거사업소로 운반 가까운 한국환경공단 운영수거사업소로 운반 -농약용기는 농약을 완전히 사용한 후 재질별(유리병, 플라스틱, 비닐, 종이)로 구분하여 그물망 또는 마대 등에 모아 배출 지자체별, 마을별 공동집하장에 배출, 가까운 한국환경공단 운영수거사업소로 운반 농약과 살충제 잔유물은 생활계유해폐기물 배출방법에 따라 처리"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=546', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·영농폐기물은 영농폐비닐과 농약 용기입니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분리배출 장소 선택 배출장소 전체보기 종량...', '', '2026-05-18', 0, '["기타"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('라면 박스', '라면 박스', 'paper', '· 종이의 종류로는 골판지, 백판지, 백상지, 종이팩이 있습니다. · 종이를 배출할 때에는 골판지와 골판지 외 종이류(백판지, 백상지 등)으로 구분하여 배출합니다. · 라면박스는 골판지로 골판지 상자는 별도의 분리배출함(또는 마대)에 배출하거나 끈 등으로 묶어서 배출합니다. · 골판지 상자 등에 부착된 테이프는 제거하여 배출하여 주시기 바라며, 제거하기 어', '["라면 박스는 일반 종이와 구분하여 종이류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=547', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 종이의 종류로는 골판지, 백판지, 백상지, 종이팩이 있습니다. · 종이를 배출할 때에는 골판지와 골판지 외 종이류(백판지, 백상지 등)으로 구분하여 배출합니다. · 라면박스는 골판지로 골판지 상자는 별도의 분리배출함(또는 마대)에 배출하거나 끈 등으로 묶어서 배출합니다. · 골판지 상자 등에 부착된 테이프는 제거하여 배출하여 주시기 바라며, 제거하기 어려운 경우에는 칼 등을 이용하여 접선...', '· 상자에 부착된 테이프는 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('수첩', '수첩', 'paper', '· 종이의 종류로는 골판지, 백판지, 백상지, 종이팩이 있습니다. · 종이를 배출할 때에는 골판지와 골판지 외 종이류(백판지, 백상지 등)으로 구분하여 배출합니다. · 공책,수첩,노트는 색상과 관계없이 신문지, 백상지 등 기타 종이류와 함께 배출하며, 이때, 비닐 코팅된 종이, 공책의 스프링, 비닐포장지 등은 제거 후 배출합니다.', '["수첩은 종이류 수거함으로 배출합니다."]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 코팅종이, 금박지, 은박지, 검은색 먹지 등은 제거하여 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('메모노트', '메모노트', 'paper', '· 크기가 작은 종이는 이물질이 묻어 있지 않은 경우에는 종이류로 배출합니다. · 메모노트와 같이 크기가 작은 종이는 묶음 그대로 배출하거나 낱개로 배출할 때에는 흩날리지 않도록 종이봉투 등에 담거나 신문지 등에 끼워서 종이로 배출할 수 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에', '["메모노트는 종이류 수거함으로 배출합니다."]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '', '2026-05-18', 0, NULL);
