INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('염색된 정도에 따라 색도화지', '염색된 정도에 따라 색도화지', 'general', '· 일반 종이에 색을 들인 색도화지는 종이류로 배출하면 재활용이 가능합니다. · 다만, 검은색 먹지와 같이 종이의 겉면과 내면이 모두 염색된 종이는 재활용 시 제품 품질에 영향을 미치므로 일반폐기물로 배출하여 주시는 것이 좋습니다. · 이때, 염색 여부를 판단하는 기준은 색도화지를 찢었을 때 내면이 색이 입혀진 경우에는 염색된 종이이며, 내면이 하얀 종이인', '["염색된 정도에 따라 색도화지는 종이류 수거함 또는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=552', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 일반 종이에 색을 들인 색도화지는 종이류로 배출하면 재활용이 가능합니다. · 다만, 검은색 먹지와 같이 종이의 겉면과 내면이 모두 염색된 종이는 재활용 시 제품 품질에 영향을 미치므로 일반폐기물로 배출하여 주시는 것이 좋습니다. · 이때, 염색 여부를 판단하는 기준은 색도화지를 찢었을 때 내면이 색이 입혀진 경우에는 염색된 종이이며, 내면이 하얀 종이인 경우에는 염색되지 않은 종이입니다....', '· 겉면과 내면이 모두 염색된 종이는 재활용이 어려우므로 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "종이", "일반폐기물", "일반종량제폐기물"]');
