INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('백과사전', '백과사전', 'paper', '· 종이의 종류로는 골판지, 백판지, 백상지, 종이팩이 있습니다. · 종이를 배출할 때에는 골판지와 골판지 외 종이류(백판지, 백상지 등)으로 구분하여 배출합니다. · 백과사전은 신문지, 백상지 등 기타 종이류와 함께 배출합니다.', '["백과사전은 종이류 수거함으로 배출합니다."]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 책을 다량으로 배출할 때에는 끈 등으로 묶은 후 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('화구통', '화구통', 'plastic', '· 화구통은 도면이나 그림 등을 휴대하기 위해 만들어진 제품입니다. · 플라스틱 화구통은 PP재질로 플라스틱 수거함으로 배출하고 종이 화구통은 크라프트지 재질로 골판지와 함께 배출합니다.', '["화구통은 재질에 맞게 종이류 수거함, 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=556', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 화구통은 도면이나 그림 등을 휴대하기 위해 만들어진 제품입니다. · 플라스틱 화구통은 PP재질로 플라스틱 수거함으로 배출하고 종이 화구통은 크라프트지 재질로 골판지와 함께 배출합니다.', '· 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "종이", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('달력', '달력', 'paper', '· 달력은 종이로 배출하면 재활용이 가능합니다. · 달력의 금속 또는 플라스틱 링은 제거한 후 배출합니다.', '["달력은 종이류 수거함으로 배출합니다."]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 스프링은 제거한 후 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('황화일', '황화일', 'paper', '· 황화일은 종이(크라프트지)로 제작되며 비닐이 코팅되어 있지 않아 재활용이 가능합니다. · 황화일에 문서를 보관할 수 있도록 하는 금속재질의 책철은 제거 후 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에', '["황화일은 종이류 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=558', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 황화일은 종이(크라프트지)로 제작되며 비닐이 코팅되어 있지 않아 재활용이 가능합니다. · 황화일에 문서를 보관할 수 있도록 하는 금속재질의 책철은 제거 후 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의...', '', '2026-05-18', 0, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('키친타올 심', '키친타올 심', 'paper', '· 키친타올 심은 키친타올을 고정하기 위하여 만들어진 제품으로 강도가 높은 크라프트지를 사용하고 있으며, 종이로 재활용이 가능합니다. · 다만, 동그랗고 부피가 크기 때문에 종이로 배출할 때에는 자르거나 압착하여 평평하게 하여 골판지로 배출합니다. · 종이의 종류로는 골판지, 백판지, 백상지, 종이팩이 있습니다. · 종이는 수거하여 종류별로 분류한 후 각각', '["키친타올 심은 종이류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=560', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 키친타올 심은 키친타올을 고정하기 위하여 만들어진 제품으로 강도가 높은 크라프트지를 사용하고 있으며, 종이로 재활용이 가능합니다. · 다만, 동그랗고 부피가 크기 때문에 종이로 배출할 때에는 자르거나 압착하여 평평하게 하여 골판지로 배출합니다. · 종이의 종류로는 골판지, 백판지, 백상지, 종이팩이 있습니다. · 종이는 수거하여 종류별로 분류한 후 각각의 제지공장으로 운반되어 해리, 정선...', '· 평평하게 하여 배출', '2026-05-18', 0, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 치킨박스', '깨끗한 치킨박스', 'paper', '· 종이는 수거하여 종류별로 분류한 후 각각의 제지공장으로 운반되어 해리, 정선, 농축, 고해 과정을 거친 후 펄프와 혼합하여 종이로 재활용하고 있습니다. · 피자박스, 치킨박스 등 음식포장박스는 내용물을 비우고 이물질이 묻지 않았다면 종이류로 배출합니다. · 이물질이 묻은 경우에는 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니,', '["깨끗한 치킨박스는 종이류로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=562', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 종이는 수거하여 종류별로 분류한 후 각각의 제지공장으로 운반되어 해리, 정선, 농축, 고해 과정을 거친 후 펄프와 혼합하여 종이로 재활용하고 있습니다. · 피자박스, 치킨박스 등 음식포장박스는 내용물을 비우고 이물질이 묻지 않았다면 종이류로 배출합니다. · 이물질이 묻은 경우에는 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이...', '', '2026-05-18', 0, '["재활용폐기물", "종이"]');
