INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('프라이팬', '프라이팬', 'can', '· 냄비, 프라이팬 등은 대부분 금속으로 제작되어 있어 고철수거함으로 배출합니다. · 손잡이가 플라스틱 등인 경우 소량이며 제품 대부분이 금속 재질이므로 고철수거함으로 배출하면 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재', '["프라이팬은 고철 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=565', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 냄비, 프라이팬 등은 대부분 금속으로 제작되어 있어 고철수거함으로 배출합니다. · 손잡이가 플라스틱 등인 경우 소량이며 제품 대부분이 금속 재질이므로 고철수거함으로 배출하면 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 고철 외 다른 재질이 섞인 정도에 따라 고철 수거함 또는 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('무쇠 주물냄비', '무쇠 주물냄비', 'can', '· 무쇠 주물냄비는 주로 철(무쇠)로 제작하고 있습니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하', '["무쇠 주물냄비는 고철 수거함으로 배출합니다.", "무쇠 주물냄비의 크기, 무게가 커 고철 수거함으로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=566', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 무쇠 주물냄비는 주로 철(무쇠)로 제작하고 있습니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소...', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('스테인리스 솥', '스테인리스 솥', 'can', '· 스테인리스 솥은 금속 단일재질로 재활용이 가능합니다. · 손잡이가 플라스틱인 경우도 있으나 소량이며 제품 대부분이 금속 재질이므로 고철 수거함으로 배출하면 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["스테인리스 솥은 고철 수거함으로 배출합니다.", "스테인리스 솥의 크기, 무게가 커 고철 수거함으로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=567', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 스테인리스 솥은 금속 단일재질로 재활용이 가능합니다. · 손잡이가 플라스틱인 경우도 있으나 소량이며 제품 대부분이 금속 재질이므로 고철 수거함으로 배출하면 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 고철 외 다른 재질이 섞인 정도에 따라 고철 수거함 또는 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('다량의 더블 클립', '다량의 더블 클립', 'can', '· 더블 클립은 금속 단일재질로 재활용이 가능합니다. · 다만, 더블 클립의 크기가 작아 낱개로 배출할 경우 선별시설에서 선별이 어려워 잔재물로 배출되는 경우가 많습니다. · 크기가 작은 고철제품은 낱개로 배출할 경우 종량제봉투로 배출하는 것이 좋으며, 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분', '["다량의 더블 클립은 고철 수거함으로 배출합니다.", "낱개의 더블 클립은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=568', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 더블 클립은 금속 단일재질로 재활용이 가능합니다. · 다만, 더블 클립의 크기가 작아 낱개로 배출할 경우 선별시설에서 선별이 어려워 잔재물로 배출되는 경우가 많습니다. · 크기가 작은 고철제품은 낱개로 배출할 경우 종량제봉투로 배출하는 것이 좋으며, 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다....', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('다량의 옷핀', '다량의 옷핀', 'can', '· 옷핀은 금속 단일재질로 재활용이 가능합니다. · 다만, 옷핀의 크기가 작아 낱개로 배출할 경우 선별시설에서 선별이 어려워 잔재물로 배출되는 경우가 많습니다. · 크기가 작은 고철제품은 낱개로 배출할 경우 종량제봉투로 배출하는 것이 좋으며, 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별', '["다량의 옷핀은 고철 수거함으로 배출합니다.", "낱개의 옷핀은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=569', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 옷핀은 금속 단일재질로 재활용이 가능합니다. · 다만, 옷핀의 크기가 작아 낱개로 배출할 경우 선별시설에서 선별이 어려워 잔재물로 배출되는 경우가 많습니다. · 크기가 작은 고철제품은 낱개로 배출할 경우 종량제봉투로 배출하는 것이 좋으며, 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다. · 다량으...', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('커튼봉', '커튼봉', 'plastic', '· 커튼봉은 금속, 플라스틱, 목재 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 금속, 플라스틱 등 단일재질로 분리가 가능한 경우에는 각각 분리하여 금속은 고철 수거함에 배출하고, 플라스틱은 재활용품으로, 목재는 일반쓰레기로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 제품인 경우 대형폐기물로 배출합니다.', '["커튼봉은 분리한 후 재질에 맞게 고철 수거함, 플라스틱 수거함 등으로 배출합니다.", "재질별 분리가 어려운 경우에는 종량제봉투로 배출합니다.", "크기가 크거나 무게가 무거운 제품은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=572', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 커튼봉은 금속, 플라스틱, 목재 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 금속, 플라스틱 등 단일재질로 분리가 가능한 경우에는 각각 분리하여 금속은 고철 수거함에 배출하고, 플라스틱은 재활용품으로, 목재는 일반쓰레기로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 제품인 경우 대형폐기물로 배출합니다.', '· 재질별로 분리가 가능하다면 가급적 분리한 후 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('역기', '역기', 'furniture', '· 역기는 역기봉과 바벨로 구성된 제품입니다. · 제품이 대부분 크고 무거우므로 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현', '["역기는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=573', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 역기는 역기봉과 바벨로 구성된 제품입니다. · 제품이 대부분 크고 무거우므로 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서...', '', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('벤치프레스', '벤치프레스', 'furniture', '· 벤치프레스는 의자와 역기로 구성된 제품입니다. · 제품이 대부분 크고 무거우므로 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요.', '["벤치프레스는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=574', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 벤치프레스는 의자와 역기로 구성된 제품입니다. · 제품이 대부분 크고 무거우므로 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도...', '', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('연결관의 재질', '연결관의 재질', 'general', '· 연결관은 스테인리스 강관이나 동관, PVC 등으로 제작하고 있습니다. · 금속재질의 연결관은 가급적 부피를 최소화한 후 이물질을 제거하여 고철수거함으로 배출하여 주시면 재활용이 가능합니다. · 플라스틱 관 또는 다양한 재질이 혼합된 복합재질 제품은 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이', '["연결관의 재질이 금속 단일재질인 경우에는 고철 수거함으로 배출합니다.", "연결관이 플라스틱, 고무 등 다양한 재질이 혼합된 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=575', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 연결관은 스테인리스 강관이나 동관, PVC 등으로 제작하고 있습니다. · 금속재질의 연결관은 가급적 부피를 최소화한 후 이물질을 제거하여 고철수거함으로 배출하여 주시면 재활용이 가능합니다. · 플라스틱 관 또는 다양한 재질이 혼합된 복합재질 제품은 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출...', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('수도꼭지의 재질', '수도꼭지의 재질', 'general', '· 수도꼭지는 금속, 플라스틱, 고무 등이 혼합된 복합재질 제품입니다. · 가급적 재질에 맞게 분리하여 배출하고 분리가 어려운 경우에는 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배', '["수도꼭지의 재질이 금속 단일재질인 경우에는 고철 수거함으로 배출합니다.", "수도꼭지가 플라스틱, 고무 등 다양한 재질이 혼합된 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=576', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 수도꼭지는 금속, 플라스틱, 고무 등이 혼합된 복합재질 제품입니다. · 가급적 재질에 맞게 분리하여 배출하고 분리가 어려운 경우에는 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역...', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('욕실 코너선반', '욕실 코너선반', 'plastic', '· 욕실에 설치하는 코너선반은 플라스틱, 스테인리스 등으로 제작하고 있으며, 종류에 따라 크기가 다양합니다. · 스테인리스 재질의 코너선반은 고철 수거함으로 배출하고 플라스틱 재질은 플라스틱 수거함으로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 제품인 경우 대형폐기물로 배출합니다.', '["욕실 코너선반은 재질에 맞게 분리한 후 전용수거함으로 배출합니다.", "욕실 코너선반이 플라스틱, 목재 등 다양한 재질이 혼합된 경우에는 종량제봉투로 배출합니다.", "크기가 크거나 무게가 무거운 제품은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=577', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 욕실에 설치하는 코너선반은 플라스틱, 스테인리스 등으로 제작하고 있으며, 종류에 따라 크기가 다양합니다. · 스테인리스 재질의 코너선반은 고철 수거함으로 배출하고 플라스틱 재질은 플라스틱 수거함으로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 제품인 경우 대형폐기물로 배출합니다.', '· 단일재질 제품이더라도 크기가 큰 제품은 대형폐기물로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('그릴팬', '그릴팬', 'can', '· 그릴팬은 스테인리스, 무쇠 등으로 제작됩니다. · 손잡이가 플라스틱, 나무 등인 경우 소량이며 제품 대부분이 금속 재질이므로 고철 수거함으로 배출하면 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["그릴팬은 고철 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=578', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 그릴팬은 스테인리스, 무쇠 등으로 제작됩니다. · 손잡이가 플라스틱, 나무 등인 경우 소량이며 제품 대부분이 금속 재질이므로 고철 수거함으로 배출하면 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('안전가드의 재질', '안전가드의 재질', 'furniture', '· 안전가드는 낙상 방지를 위해 침대에 설치하는 제품입니다. · 금속 단일재질로 되어 있는 경우에는 고철 수거함으로 배출합니다. · 크기가 큰 경우에는 대형폐기물로 배출합니다.', '["안전가드의 재질이 금속 단일재질인 경우에는 고철 수거함으로 배출합니다.", "크기가 크거나 무게가 무거운 제품은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=579', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 안전가드는 낙상 방지를 위해 침대에 설치하는 제품입니다. · 금속 단일재질로 되어 있는 경우에는 고철 수거함으로 배출합니다. · 크기가 큰 경우에는 대형폐기물로 배출합니다.', '· 단일재질 제품이더라도 크기가 큰 제품은 대형폐기물로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('네트망', '네트망', 'furniture', '· 네트망은 금속 단일재질로 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품', '["네트망은 고철 수거함으로 배출합니다.", "크기가 커 수거함으로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=580', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 네트망은 금속 단일재질로 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수료에 준하여 책정하고 있습니다...', '· 단일재질 제품이더라도 크기가 큰 제품은 대형폐기물로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('안전문', '안전문', 'furniture', '· 안전문은 금속 단일재질로 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품', '["안전문은 고철 수거함으로 배출합니다.", "크기가 크거나 무게가 무거운 제품은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=581', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 안전문은 금속 단일재질로 재활용이 가능합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수료에 준하여 책정하고 있습니다...', '· 단일재질 제품이더라도 크기가 큰 제품은 대형폐기물로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('디스펜서', '디스펜서', 'furniture', '· 디스펜서의 구성품이 분리가 가능한 경우에는 금속 재질의 부품은 고철 수거함으로 배출합니다. · 분리가 어려운 경우에는 제품 그대로 대형폐기물로 배출합니다.', '["디스펜서는 재질에 맞게 분리한 후 전용수거함으로 배출합니다.", "크기가 큰 제품은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=582', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 디스펜서의 구성품이 분리가 가능한 경우에는 금속 재질의 부품은 고철 수거함으로 배출합니다. · 분리가 어려운 경우에는 제품 그대로 대형폐기물로 배출합니다.', '· 제품 내부에 들어있는 물품은 억지로 제거하지 않고 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('금속 재질의 트로피', '금속 재질의 트로피', 'can', '· 금속 트로피는 청동, 알루미늄 등 금속으로 제작하고 있으며,고철 수거함으로 배출하여 주시면 재활용이 가능합니다. · 다만, 고철 외 타 재질로 제작하였거나, 타 재질의 함량이 높은 경우에는 재활용이 어렵습니다.', '["금속 재질의 트로피는 고철 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=583', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 금속 트로피는 청동, 알루미늄 등 금속으로 제작하고 있으며,고철 수거함으로 배출하여 주시면 재활용이 가능합니다. · 다만, 고철 외 타 재질로 제작하였거나, 타 재질의 함량이 높은 경우에는 재활용이 어렵습니다.', '· 고철 외 다른 재질이 섞인 정도에 따라 고철 수거함 또는 종량제봉투로 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('바인더', '바인더', 'can', '· 바인더는 내지, 바인더링, 커버로 구성되어 있습니다. · 가급적 재질에 맞게 분리하여, 내지는 비닐류 수거함으로 배출하고 바인더링은 고철 수거함으로 배출합니다. · 바인더 커버는 하드보드지에 PVC, PP표지를 접착하여 재활용이 어려우므로 종량제봉투에 배출합니다. · 분리가 어려운 경우에는 제품 그대로 종량제봉투로 배출합니다.', '["바인더는 가급적 재질별로 분리하여 배출하며, 분리하기 어려운 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=584', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 바인더는 내지, 바인더링, 커버로 구성되어 있습니다. · 가급적 재질에 맞게 분리하여, 내지는 비닐류 수거함으로 배출하고 바인더링은 고철 수거함으로 배출합니다. · 바인더 커버는 하드보드지에 PVC, PP표지를 접착하여 재활용이 어려우므로 종량제봉투에 배출합니다. · 분리가 어려운 경우에는 제품 그대로 종량제봉투로 배출합니다.', '· 바인더는 내지와 커버, 바인더링을 분리한 후 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류", "금속류", "고철"]');
