INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('쫄대 화일', '쫄대 화일', 'plastic', '· 쫄대 화일은 종이를 끼워서 쫄대로 고정하여 사용하는 파일로 플라스틱(PP)재질로 재활용이 가능합니다. · 플라스틱 제품 중 부드럽고 무른 성질이 있는 제품은 비닐류로도 배출할 수 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인', '["쫄대 화일은 플라스틱 수거함 또는 비닐류 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=587', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 쫄대 화일은 종이를 끼워서 쫄대로 고정하여 사용하는 파일로 플라스틱(PP)재질로 재활용이 가능합니다. · 플라스틱 제품 중 부드럽고 무른 성질이 있는 제품은 비닐류로도 배출할 수 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('화장품 정리함', '화장품 정리함', 'furniture', '· 화장품 정리함은 주로 플라스틱으로 되어 있으며, 일부 제품은 케이스와 수납함의 재질이 다른 경우가 있습니다. · 화장품 정리함이 단일재질 제품인 경우에는 재질에 맞게 배출하며, 재질이 혼합된 경우 종량제봉투 또는 대형폐기물로 배출합니다.', '["화장품 정리함이 단일재질인 경우 재질에 맞게 배출합니다.", "화장품 정리함이 복합재질인 경우 종량제봉투로 배출합니다.", "크기가 커 수거함 또는 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=588', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 화장품 정리함은 주로 플라스틱으로 되어 있으며, 일부 제품은 케이스와 수납함의 재질이 다른 경우가 있습니다. · 화장품 정리함이 단일재질 제품인 경우에는 재질에 맞게 배출하며, 재질이 혼합된 경우 종량제봉투 또는 대형폐기물로 배출합니다.', '· 재질별로 분리가 가능하다면 가급적 분리한 후 재질에 맞게 배출 · 대형폐기물로 배출하는 경우 수납함이 분리되지 않도록 테이프 등으로 붙여서 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('소품 정리함', '소품 정리함', 'furniture', '· 소품 정리함은 주로 플라스틱으로 되어 있으며, 일부 제품은 케이스와 수납함의 재질이 다른 경우가 있습니다. · 소품 정리함이 단일재질 제품인 경우에는 재질에 맞게 배출하며, 재질이 혼합된 경우 종량제봉투 또는 대형폐기물로 배출합니다.', '["소품 정리함이 단일재질인 경우 재질에 맞게 배출합니다.", "소품 정리함이 복합재질인 경우 종량제봉투로 배출합니다.", "크기가 커 수거함 또는 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=589', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 소품 정리함은 주로 플라스틱으로 되어 있으며, 일부 제품은 케이스와 수납함의 재질이 다른 경우가 있습니다. · 소품 정리함이 단일재질 제품인 경우에는 재질에 맞게 배출하며, 재질이 혼합된 경우 종량제봉투 또는 대형폐기물로 배출합니다.', '· 재질별로 분리가 가능하다면 가급적 분리한 후 재질에 맞게 배출 · 대형폐기물로 배출하는 경우 수납함이 분리되지 않도록 테이프 등으로 붙여서 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('샴푸', '샴푸', 'plastic', '· 샴푸와 같이 가정에서 사용하는 플라스틱의 용기는 대부분 생산자책임재활용제도(EPR) 대상 품목에 해당되며 재활용이 가능합니다. · 일부 제품의 경우 용기 속의 내용물을 쉽게 배출될 수 있도록 펌프를 사용합니다. 펌프는 플라스틱과 고철 등이 혼합된 복합재질 제품으로 재활용이 어려우므로 제거한 후 배출합니다. · 비닐 라벨이 붙어 있는 경우에는 제거하여 비', '["샴푸는 내용물을 비우고 라벨, 펌프 등 이물질을 제거한 후 용기는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=590', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 샴푸와 같이 가정에서 사용하는 플라스틱의 용기는 대부분 생산자책임재활용제도(EPR) 대상 품목에 해당되며 재활용이 가능합니다. · 일부 제품의 경우 용기 속의 내용물을 쉽게 배출될 수 있도록 펌프를 사용합니다. 펌프는 플라스틱과 고철 등이 혼합된 복합재질 제품으로 재활용이 어려우므로 제거한 후 배출합니다. · 비닐 라벨이 붙어 있는 경우에는 제거하여 비닐 수거함에 배출합니다. · 다량의...', '· 용기류를 배출할 때에는 라벨, 펌프를 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
