INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('치약', '치약', 'plastic', '· 치약과 같은 튜브 용기 내용물을 비우고 물로 최대한 헹군 후 플라스틱 수거함으로 배출합니다. · 다만 치약 용기에 분리배출 표시가 도포첩합으로 표기된 제품은 종량제봉투로 배출합니다.', '["치약은 내용물을 제거한 후 물로 헹구는 등 꺠끗한 상태로 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=593', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 치약과 같은 튜브 용기 내용물을 비우고 물로 최대한 헹군 후 플라스틱 수거함으로 배출합니다. · 다만 치약 용기에 분리배출 표시가 도포첩합으로 표기된 제품은 종량제봉투로 배출합니다.', '· 분리배출 표시 확인 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('욕실세정제 용기', '욕실세정제 용기', 'plastic', '·욕실세정제의 용기는 플라스틱(HDPE, PET 등) 재질로 내용물을 제거한 후 플라스틱 수거함으로 배출하여 주시면 재활용이 가능합니다.', '["욕실세정제 용기는 내용물을 완전히 제거한 후 물로 헹구는 등 깨끗한 상태로 플라스틱수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=594', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·욕실세정제의 용기는 플라스틱(HDPE, PET 등) 재질로 내용물을 제거한 후 플라스틱 수거함으로 배출하여 주시면 재활용이 가능합니다.', '· 펌프를 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
