INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('배추망망', '배추망망', 'vinyl', '· 양파, 배추 등을 담은 합성수지 재질의 포장용기(그물망)는 재활용의무대상(EPR) 품목에 해당됩니다. · 해당 제품은 비닐류와 성질이 유사하여 비닐수거함으로 배출하면 됩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재', '["배추망망은 비닐수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=597', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 양파, 배추 등을 담은 합성수지 재질의 포장용기(그물망)는 재활용의무대상(EPR) 품목에 해당됩니다. · 해당 제품은 비닐류와 성질이 유사하여 비닐수거함으로 배출하면 됩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다....', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('식용유 용기', '식용유 용기', 'plastic', '·식용유 용기는 플라스틱(무색페트 등) 재질로 내용물을 제거한 후 플라스틱 수거함으로 배출하여 주시면 재활용이 가능합니다.', '["식용유 용기는 내용물을 비우고 라벨 등 이물질을 제거한 후 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=598', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·식용유 용기는 플라스틱(무색페트 등) 재질로 내용물을 제거한 후 플라스틱 수거함으로 배출하여 주시면 재활용이 가능합니다.', '· 라벨을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('그레이터', '그레이터', 'can', '· 그레이터는 채소나 과일, 치즈 등의 식재료를 문질러 잘게 만드는 주방기구로 대부분 금속으로 제작되어 있어 고철 수거함으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있', '["그레이터는 고철 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=599', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 그레이터는 채소나 과일, 치즈 등의 식재료를 문질러 잘게 만드는 주방기구로 대부분 금속으로 제작되어 있어 고철 수거함으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는...', '', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('젓가락의 재질', '젓가락의 재질', 'general', '· 스테인리스로 된 젓가락은 고철 수거함에 배출합니다. · 나무 재질로 되어 있거나 나무, 플라스틱 손잡이 등 다른 재질이 포함되어 재질별 분리가 어려운 젓가락은 일반쓰레기로 배출합니다.', '["젓가락의 재질이 금속 단일재질인 경우에는 고철수거함으로 배출합니다.", "목재제품인 경우에는 종량제봉투로 배출합니다.", "젓가락이 다양한 재질이 혼합된 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=600', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 스테인리스로 된 젓가락은 고철 수거함에 배출합니다. · 나무 재질로 되어 있거나 나무, 플라스틱 손잡이 등 다른 재질이 포함되어 재질별 분리가 어려운 젓가락은 일반쓰레기로 배출합니다.', '· 재질을 확인한 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('숟가락의 재질', '숟가락의 재질', 'general', '· 스테인리스로 된 숟가락은 고철 수거함에 배출합니다. · 나무 재질로 되어 있거나 나무, 플라스틱 손잡이 등 다른 재질이 포함되어 재질별 분리가 어려운 숟가락은 일반쓰레기로 배출합니다.', '["숟가락의 재질이 금속 단일재질인 경우에는 고철수거함으로 배출합니다.", "목재제품인 경우에는 종량제봉투로 배출합니다.", "숟가락이 다양한 재질이 혼합된 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=601', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 스테인리스로 된 숟가락은 고철 수거함에 배출합니다. · 나무 재질로 되어 있거나 나무, 플라스틱 손잡이 등 다른 재질이 포함되어 재질별 분리가 어려운 숟가락은 일반쓰레기로 배출합니다.', '· 재질을 확인한 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('포크의 재질', '포크의 재질', 'general', '· 스테인리스로 된 포크는 고철 수거함에 배출합니다. · 나무 재질로 되어 있거나 나무, 플라스틱 손잡이 등 다른 재질이 포함되어 재질별 분리가 어려운 포크는 일반쓰레기로 배출합니다.', '["포크의 재질이 금속 단일재질인 경우에는 고철 수거함으로 배출합니다.", "목재제품인 경우에는 종량제봉투로 배출합니다.", "포크가 다양한 재질이 혼합된 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=602', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 스테인리스로 된 포크는 고철 수거함에 배출합니다. · 나무 재질로 되어 있거나 나무, 플라스틱 손잡이 등 다른 재질이 포함되어 재질별 분리가 어려운 포크는 일반쓰레기로 배출합니다.', '· 재질을 확인한 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('보온병', '보온병', 'plastic', '· 보온병의 재질이 금속과 플라스틱 단일재질로 되어 있는 경우에는 금속과 플라스틱으로 각각 배출합니다. · 재질별로 분리하기 어렵거나 혼합재질인 제품은 일반쓰레기로 배출합니다.', '["보온병은 재질에 맞게 분리한 후 전용수거함으로 배출합니다.", "재질별로 분리하기 어려운 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=603', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 보온병의 재질이 금속과 플라스틱 단일재질로 되어 있는 경우에는 금속과 플라스틱으로 각각 배출합니다. · 재질별로 분리하기 어렵거나 혼합재질인 제품은 일반쓰레기로 배출합니다.', '· 재질별로 분리가 가능하다면 가급적 분리한 후 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('헤어 스프레이', '헤어 스프레이', 'can', '· 헤어 스프레이와 같은 스프레이 용기는 내부 가스로 인하여 폭발 위험이 있으므로 환기가 잘되는 장소에서 노즐을 눌러 내용물을 완전히 제거한 후 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["헤어 스프레이는 금속캔 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=604', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 헤어 스프레이와 같은 스프레이 용기는 내부 가스로 인하여 폭발 위험이 있으므로 환기가 잘되는 장소에서 노즐을 눌러 내용물을 완전히 제거한 후 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 내용물(가스)을 완전히 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "기타캔류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('스프레', '스프레', 'can', '· 스프레이 파스와 같은 스프레이 용기는 내부 가스로 인하여 폭발 위험이 있으므로 환기가 잘되는 장소에서 노즐을 눌러 내용물을 완전히 제거한 후 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '["스프레이 파스는 금속캔 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=605', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 스프레이 파스와 같은 스프레이 용기는 내부 가스로 인하여 폭발 위험이 있으므로 환기가 잘되는 장소에서 노즐을 눌러 내용물을 완전히 제거한 후 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 내용물(가스)을 완전히 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "기타캔류"]');
