INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('반려동물 케이지', '반려동물 케이지', 'plastic', '· 반려동물 케이지는 주로 몸체는 금속 재질이며, 배변판은 플라스틱 재질입니다. · 금속, 플라스틱 등 단일재질로 분리가 가능한 경우에는 각각 분리하여 금속은 고철 수거함에 배출하고, 플라스틱은 물로 헹구는 등 이물질을 제거한 후 플라스틱 수거함으로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 반려동물 케이지인 경우 대', '["반려동물 케이지는 재질에 맞게 분리한 후 전용수거함으로 배출합니다.", "재질별로 분리하기 어려운 경우에는 종량제봉투 또는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=618', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 반려동물 케이지는 주로 몸체는 금속 재질이며, 배변판은 플라스틱 재질입니다. · 금속, 플라스틱 등 단일재질로 분리가 가능한 경우에는 각각 분리하여 금속은 고철 수거함에 배출하고, 플라스틱은 물로 헹구는 등 이물질을 제거한 후 플라스틱 수거함으로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 반려동물 케이지인 경우 대형폐기물로 배출합니다.', '· 재질별로 분리가 가능하다면 분리한 후 재질에 맞게 배출', '2026-05-18', 0, '["재활용폐기물", "금속류", "고철", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('오프너', '오프너', 'general', '· 오프너는 플라스틱과 금속재질이 혼합된 복합재질 제품으로재질별 분리가 어려우므로 일반쓰레기로 배출합니다. · 오프너에 칼날이 있는 경우에는 주의하여 종량제봉투로 배출해야 합니다. 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다. ※ 배출방법은 지역별로 차이가 있을', '["오프너는 충분히 감싼 후 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=619', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 오프너는 플라스틱과 금속재질이 혼합된 복합재질 제품으로재질별 분리가 어려우므로 일반쓰레기로 배출합니다. · 오프너에 칼날이 있는 경우에는 주의하여 종량제봉투로 배출해야 합니다. 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('비닐 라벨', '비닐 라벨', 'vinyl', '· 합성수지 비닐과 용기류는 동일한 재질이더라도 물성이 달라 함께 재활용하기 어렵고 플라스틱과 비닐은 재활용 방법이 다르기 때문에 분리하여 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가', '["비닐 라벨은 비닐류로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=620', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 합성수지 비닐과 용기류는 동일한 재질이더라도 물성이 달라 함께 재활용하기 어렵고 플라스틱과 비닐은 재활용 방법이 다르기 때문에 분리하여 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('과일봉지', '과일봉지', 'vinyl', '· 과일, 과자 등을 포장하기 위해 사용하는 대부분의 합성수지 비닐은 생산자책임재활용제도 (EPR)대상 품목에 해당되어 재활용이 가능합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '["과일봉지는 비닐류 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=621', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 과일, 과자 등을 포장하기 위해 사용하는 대부분의 합성수지 비닐은 생산자책임재활용제도 (EPR)대상 품목에 해당되어 재활용이 가능합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '·이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('라면 봉지', '라면 봉지', 'vinyl', '· 라면, 과일, 과자 등을 포장하기 위해 사용하는 대부분의 합성수지 비닐은 생산자책임재활용제도 (EPR)대상 품목에 해당되어 재활용이 가능합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '["라면 봉지는 비닐류 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=622', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 라면, 과일, 과자 등을 포장하기 위해 사용하는 대부분의 합성수지 비닐은 생산자책임재활용제도 (EPR)대상 품목에 해당되어 재활용이 가능합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '·이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('아이스크림 봉지', '아이스크림 봉지', 'vinyl', '· 아이스크림, 과일, 과자 등을 포장하기 위해 사용하는 대부분의 합성수지 비닐은 생산자책임재활용제도 (EPR)대상 품목에 해당되어 재활용이 가능합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '["아이스크림 봉지는 비닐류 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=623', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 아이스크림, 과일, 과자 등을 포장하기 위해 사용하는 대부분의 합성수지 비닐은 생산자책임재활용제도 (EPR)대상 품목에 해당되어 재활용이 가능합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '·이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('유색봉지', '유색봉지', 'vinyl', '· 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '["유색봉지는 비닐류수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=624', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '· 내용물을 비우고 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 플라스틱 위생도마', '깨끗한 플라스틱 위생도마', 'plastic', '· 폴리프로필렌(pp) 재질로 된 밀폐보관용기, 도마, 바구니, 옷걸이 등의 생활용품은 EPR 대상 품목으로 지정되어 재활용이 됩니다. · 위생도마가 플라스틱(PP) 단일 재질인 경우 음식물 등 이물질을 제거한 후 플라스틱 수거함으로 배출합니다. · 다만, 위생도마가 음식물 등 이물질 제거가 어렵거나 오염된 경우에는 일반쓰레기로 배출합니다.', '["깨끗한 플라스틱 위생도마는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=625', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 폴리프로필렌(pp) 재질로 된 밀폐보관용기, 도마, 바구니, 옷걸이 등의 생활용품은 EPR 대상 품목으로 지정되어 재활용이 됩니다. · 위생도마가 플라스틱(PP) 단일 재질인 경우 음식물 등 이물질을 제거한 후 플라스틱 수거함으로 배출합니다. · 다만, 위생도마가 음식물 등 이물질 제거가 어렵거나 오염된 경우에는 일반쓰레기로 배출합니다.', '· 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('사탕봉지', '사탕봉지', 'vinyl', '· 사탕봉지처럼 작은 크기의 비닐봉지는 흩날리지 않도록 투명 또는 반투명봉투에 담아 비닐류 수거함으로 배출합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '["사탕봉지는 비닐류 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=626', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 사탕봉지처럼 작은 크기의 비닐봉지는 흩날리지 않도록 투명 또는 반투명봉투에 담아 비닐류 수거함으로 배출합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '· 내용물을 비우고 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('비닐약봉지', '비닐약봉지', 'vinyl', '· 비닐약봉지처럼 작은 크기의 비닐봉지는 흩날리지 않도록 투명 또는 반투명봉투에 담아 비닐류수거함으로 배출합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '["비닐약봉지는 비닐류 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=627', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 비닐약봉지처럼 작은 크기의 비닐봉지는 흩날리지 않도록 투명 또는 반투명봉투에 담아 비닐류수거함으로 배출합니다. · 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '· 내용물을 비우고 이물질을 제거한 후 배출 · 알약은 폐의약품 배출방법에 따라 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
