INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('음료 파우치 팩', '음료 파우치 팩', 'vinyl', '· 스파우트 파우치는 위생적이고 마시기 쉽도록 입구 부분에 돌림형 마개를 부착한 용기입니다. · 용기의 몸체는 비닐류수거함으로 배출하며, 뚜껑은 플라스틱 수거함으로 배출하여 주시기 바랍니다', '["음료 파우치 팩은 비닐류 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=629', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 스파우트 파우치는 위생적이고 마시기 쉽도록 입구 부분에 돌림형 마개를 부착한 용기입니다. · 용기의 몸체는 비닐류수거함으로 배출하며, 뚜껑은 플라스틱 수거함으로 배출하여 주시기 바랍니다', '· 뚜껑, 캡 제거 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('지퍼백', '지퍼백', 'vinyl', '· 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '["지퍼백은 비닐류 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=630', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 비닐은 재질, 색상과 상관없이 한데 모아 파쇄, 선별, 용융 및 성형과정을 거쳐 플라스틱 배수로, 건축 자재 등으로 재활용하고 있습니다.', '· 내용물을 비우고 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 비닐류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('다 쓴 립스틱', '다 쓴 립스틱', 'general', '· 립스틱을 다 사용하여 내용물이 남아 있지 않은 립스틱 용기는 플라스틱으로 배출합니다. · 화장품의 내용물이 남아 있어서 제거하기 곤란한 경우에는 종량제봉투에 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치', '["다 쓴 립스틱은 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=631', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 립스틱을 다 사용하여 내용물이 남아 있지 않은 립스틱 용기는 플라스틱으로 배출합니다. · 화장품의 내용물이 남아 있어서 제거하기 곤란한 경우에는 종량제봉투에 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('마요네즈 용기', '마요네즈 용기', 'plastic', '·마요네즈 용기는 플라스틱(PE, PET) 재질로 내용물을 비우고 물로 헹구는 등 이물질을 제거한 후 플라스틱 수거함으로 배출합니다.', '["마요네즈 용기는 플라스틱 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=632', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·마요네즈 용기는 플라스틱(PE, PET) 재질로 내용물을 비우고 물로 헹구는 등 이물질을 제거한 후 플라스틱 수거함으로 배출합니다.', '·내용물을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('생수병', '생수병', 'plastic', '· 우리나라는 공동주택은 2020년 12월부터, 단독주택은 2021년 12월부터 무색페트병의 분리배출을 시행하고 있습니다. · 별도 분리배출된 음료, 생수 투명페트병은 품질 좋은 재생원료로 재활용되어, 옷이나 신발, 새로운 페트병(식품용기) 등의 원료가 됩니다. · 유색페트병 또는 여러 재질이 혼합된 플라스틱 제품은 투명 페트병과 혼합 배출될 경우 재활용', '["생수병은 무색페트병 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=633', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 우리나라는 공동주택은 2020년 12월부터, 단독주택은 2021년 12월부터 무색페트병의 분리배출을 시행하고 있습니다. · 별도 분리배출된 음료, 생수 투명페트병은 품질 좋은 재생원료로 재활용되어, 옷이나 신발, 새로운 페트병(식품용기) 등의 원료가 됩니다. · 유색페트병 또는 여러 재질이 혼합된 플라스틱 제품은 투명 페트병과 혼합 배출될 경우 재활용 품질을 낮출 우려가 있기 때문에, 음...', '· 무색페트병은 내용물을 깨끗이 비우고 부착상표(라벨) 등을 제거한 후 가능한 압착하여 뚜껑을 닫아 배출', '2026-05-18', 0, '["재활용폐기물", "무색페트병"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 택배 박스(스티로폼)', '깨끗한 택배 박스(스티로폼)', 'styrofoam', '· 과일, 축산물 등을 담은 스티로폼 포장재는 생산자책임재활용제도(EPR) 대상 품목에 해당되어 재활용이 가능합니다. · 발포합성수지는 PP, PE, PS 등의 합성수지를 증기로 부풀린 제품을 말하며, 가정에서 발생하는 대부분의 발포합성수지는 EPS(스티로폼) 제품입니다. · 발포합성수지 제품은 수거 후 재활용업체에서 분쇄, 감용과정을 거쳐 잉고트를 생산하', '["깨끗한 택배 박스(스티로폼)은 스티로폼 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=636', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 과일, 축산물 등을 담은 스티로폼 포장재는 생산자책임재활용제도(EPR) 대상 품목에 해당되어 재활용이 가능합니다. · 발포합성수지는 PP, PE, PS 등의 합성수지를 증기로 부풀린 제품을 말하며, 가정에서 발생하는 대부분의 발포합성수지는 EPS(스티로폼) 제품입니다. · 발포합성수지 제품은 수거 후 재활용업체에서 분쇄, 감용과정을 거쳐 잉고트를 생산하며 이후 제조업체로 이송하여 액자 또...', '· 택배송장, 테이프 등 이물질 제거 후 배출', '2026-05-18', 0, '["재활용폐기물", "발포합성수지(스티로폼 등)"]');
