INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('유색 스티로폼 용기', '유색 스티로폼 용기', 'styrofoam', '· 수산물, 축산물 등을 담은 스티로폼 포장재는 생산자책임재활용제도(EPR) 대상 품목에 해당되어 재활용이 가능합니다. · 스티로폼 용기는 색상, 무늬와 상관없이 스티로폼 수거함으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확', '["유색 스티로폼 용기는 스티로폼 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=638', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 수산물, 축산물 등을 담은 스티로폼 포장재는 생산자책임재활용제도(EPR) 대상 품목에 해당되어 재활용이 가능합니다. · 스티로폼 용기는 색상, 무늬와 상관없이 스티로폼 수거함으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출...', '', '2026-05-18', 0, '["재활용폐기물", "발포합성수지(스티로폼 등)"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('빈용기보증금 대상 맥주병', '빈용기보증금 대상 맥주병', 'glass', '· 우리나라는 지난 1985년부터 빈용기에 재사용을 활성화하기 위하여 소주병, 맥주병, 청량음료병(ex. 콜라, 사이다 등)에 대하여 보증금을 부과하고 있습니다. · 소비자는 제품을 구매할 때 일정 금액의 보증금을 납부하며 이후 사용한 빈용기를 소매점 등 빈용기반환수집소 또는 무인회수기에 반환하여 보증금을 환급하시기 바랍니다. · 이때, 용기가 깨지거나 참', '["빈용기보증금 대상 맥주병은 가까운 빈용기반환수집소 및 무인회수기에 반환하여 보증금을 환급받으시거나 유리병 수거함에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=639', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 우리나라는 지난 1985년부터 빈용기에 재사용을 활성화하기 위하여 소주병, 맥주병, 청량음료병(ex. 콜라, 사이다 등)에 대하여 보증금을 부과하고 있습니다. · 소비자는 제품을 구매할 때 일정 금액의 보증금을 납부하며 이후 사용한 빈용기를 소매점 등 빈용기반환수집소 또는 무인회수기에 반환하여 보증금을 환급하시기 바랍니다. · 이때, 용기가 깨지거나 참기름, 담뱃재, 곰팡이 등으로 인하여...', '', '2026-05-18', 0, '["재활용폐기물", "유리병", "빈용기보증금 대상 유리병"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('들기름', '들기름', 'general', '· 식물성 기름(참기름, 들기름 등)은 바이오디젤로 재활용이 가능합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도', '["들기름은 폐식용유 수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=640', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 식물성 기름(참기름, 들기름 등)은 바이오디젤로 재활용이 가능합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분리배출 장소...', '', '2026-05-18', 0, '["기타"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('인삼', '인삼', 'food', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 담금주에 사용한 과일, 채소, 약초 등 건더기는 음식물류폐기물로 배출하셔도 괜찮습니다.', '["인삼은 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=641', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 담금주에 사용한 과일, 채소, 약초 등 건더기는 음식물류폐기물로 배출하셔도 괜찮습니다.', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
