INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('오렌지 껍질', '오렌지 껍질', 'food', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 과일껍질은 음식물류폐기물로 배출하면 재활용이 가능합니다. 이때, 껍질을 말리더라도 재활용이 가능합니다.', '["오렌지 껍질은 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=646', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 과일껍질은 음식물류폐기물로 배출하면 재활용이 가능합니다. 이때, 껍질을 말리더라도 재활용이 가능합니다.', '·말린 과일껍질도 음식물류폐기물로 배출 ·해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('유통기한', '유통기한', 'food', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 사료화는 파쇄선별-탈수-건조/살균-분쇄-사료생산 과정을 거쳐 재활용하고 있습니다. · 살균과정은 농림축산식품부의 사료 기준', '["유통기한이 지난 음식은 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=647', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 사료화는 파쇄선별-탈수-건조/살균-분쇄-사료생산 과정을 거쳐 재활용하고 있습니다. · 살균과정은 농림축산식품부의 사료 기준에 따라 100℃에서 30분 이상 가...', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('부침가루', '부침가루', 'food', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 밀가루, 부침가루 등 곡물 가루는 음식물류폐기물로 배출합니다.', '["부침가루는 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=649', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 밀가루, 부침가루 등 곡물 가루는 음식물류폐기물로 배출합니다.', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('감초가루', '감초가루', 'food', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 어성초, 감초 등 약초가루는 기타가공품으로 원료를 제조·가공한 식품으로 음식물류폐기물로 배출합니다.', '["감초가루는 음식물류폐기물로 배출합니다.", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=651', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 어성초, 감초 등 약초가루는 기타가공품으로 원료를 제조·가공한 식품으로 음식물류폐기물로 배출합니다.', '· 해당 지자체의 배출방법에 따라 배출', '2026-05-18', 0, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('PC세트', 'PC세트', 'furniture', '· PC세트는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제', '["PC세트는 폐가전제품 무상방문수거서비스(1599-0903)을 이용하여 배출합니다.", "무상수거 서비스를 이용하기 어려운 경우에는 대형폐기물로 배출합니다.", "신제품 구매시 생산, 판매업체의 역회수 서비스를 이용하여 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=661', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· PC세트는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도 대상품목으로는 냉장고, 세탁기,...', '· 폐가전제품 무상방문서비스 문의 후 배출', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('전축 세트', '전축 세트', 'furniture', '·전축 세트는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제', '["전축 세트는 폐가전제품 무상방문수거서비스(1599-0903)을 이용하여 배출합니다.", "무상수거 서비스를 이용하기 어려운 경우에는 대형폐기물로 배출합니다.", "신제품 구매시 생산, 판매업체의 역회수 서비스를 이용하여 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=662', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·전축 세트는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도 대상품목으로는 냉장고, 세탁기,...', '· 폐가전제품 무상방문서비스 문의 후 배출', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류", "대형폐기물"]');
