INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('착즙기', '착즙기', 'electronics', '· 착즙기는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도', '["착즙기는 소형전기전자제품 전용수거함으로 배출합니다.", "착즙기와 함께 4가지 이상의 전기전자제품을 배출하기 원하는 경우에는 폐가전제품 무상방문수거서비스(1599-0903)을 이용하여 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=676', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 착즙기는 전기전자제품 환경성보장제도 품목에 해당됩니다. * 환경성보장제도는 전기전자제품의 재활용을 촉진하기 위하여 유해물질의 사용을 억제하고 재활용이 쉽도록 제조하며 그 폐기물을 적정하게 재활용하도록 하여 자원을 효율적으로 이용하는 자원순환체계를 구축하여 환경보전과 국민 경제의 건전한 발전에 이바지함을 목적으로 하는 제도를 말합니다. ** 환경성보장제도 대상품목으로는 냉장고, 세탁기, 다...', '· 소형전기전자제품은 전용수거함으로 배출하거나 5개 이상 모아 폐가전제품 무상방문수거서비스를 이용하여 배출', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('공학용 계산기', '공학용 계산기', 'electronics', '· 공학용 계산기, 전자사전 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋', '["공학용 계산기는 가까운 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=677', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 공학용 계산기, 전자사전 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다.', '·내장된 전지가 분리가 가능한 경우에는 제거 후 배출', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('케이블', '케이블', 'electronics', '· 케이블은 금속, 고무, 플라스틱이 혼합된 복합재질제품입니다. · 케이블 속에 있는 구리는 재활용이 가능하나 케이블의 고무 또는 플라스틱 재질의 피복이 재활용이 되지 않기 때문에 분리작업이 필요합니다. · 소형전기전자제품 재활용 사업장에서 분리작업을 하고 있기 때문에 소형전기전자제품 수거함에 배출하면 됩니다.', '["케이블은 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=678', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 고철로 배출 불가능', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('PMP', 'PMP', 'electronics', '· PMP 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출방', '["PMP는 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=679', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· PMP 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니...', '', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('이어폰', '이어폰', 'electronics', '· 이어폰 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출방', '["이어폰은 소형전기전자제품 전용수거함으로 배출합니다.", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=680', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('서랍장', '서랍장', 'furniture', '· 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리되어 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다. · 상태가 좋아 다른 사람이 사용할 수 있는 폐가구는 재활용센터에 판매할 수 있으며, 업체에 따라 무상으로 수거하는 경우도 있습니다. 폐가구를 배출하시기 전 가까운 재활용센터에 문의하여 주시기', '["서랍장은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=681', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리되어 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다. · 상태가 좋아 다른 사람이 사용할 수 있는 폐가구는 재활용센터에 판매할 수 있으며, 업체에 따라 무상으로 수거하는 경우도 있습니다. 폐가구를 배출하시기 전 가까운 재활용센터에 문의하여 주시기 바랍니다.', '· 재사용 가능여부에 따라 재활용센터로 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('장식장', '장식장', 'furniture', '· 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리되어 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다. · 상태가 좋아 다른 사람이 사용할 수 있는 폐가구는 재활용센터에 판매할 수 있으며, 업체에 따라 무상으로 수거하는 경우도 있습니다. 폐가구를 배출하시기 전 가까운 재활용센터에 문의하여 주시기', '["장식장은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=682', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리되어 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다. · 상태가 좋아 다른 사람이 사용할 수 있는 폐가구는 재활용센터에 판매할 수 있으며, 업체에 따라 무상으로 수거하는 경우도 있습니다. 폐가구를 배출하시기 전 가까운 재활용센터에 문의하여 주시기 바랍니다.', '· 재사용 가능여부에 따라 재활용센터로 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('토퍼', '토퍼', 'furniture', '· 토퍼와 같은 침구류는 재활용이 어려워 대형폐기물로 수거한 후 소각됩니다.', '["토퍼는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=684', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 토퍼와 같은 침구류는 재활용이 어려워 대형폐기물로 수거한 후 소각됩니다.', '· 토퍼는 부피, 크기가 커 배출하실 때에는 보행자에게 불편을 주지 않도록 주의하여 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('폴딩카트', '폴딩카트', 'furniture', '· 폴딩카트는 주로 플라스틱(PP) 재질이며, 손잡이는 금속 재질, 바퀴는 우레탄 재질입니다. · 단일재질로 분리가 가능한 경우에는 각각 분리하여 플라스틱 또는 고철로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 제품인 경우 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서', '["폴딩카트는 분리한 후 재질에 맞게 플라스틱 수거함, 고철 수거함 등으로 배출합니다.", "재질별로 분리하기 어려운 경우에는 종량제봉투 또는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=685', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 폴딩카트는 주로 플라스틱(PP) 재질이며, 손잡이는 금속 재질, 바퀴는 우레탄 재질입니다. · 단일재질로 분리가 가능한 경우에는 각각 분리하여 플라스틱 또는 고철로 배출합니다. · 재질별로 분리하기 어려운 제품은 종량제봉투로 배출하거나 크기가 큰 제품인 경우 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('플라스틱 수납장', '플라스틱 수납장', 'furniture', '·단일재질의 플라스틱 용기 또는 제품은 플라스틱수거함으로 배출하면 선별장으로 이송되어 재질별(PE, PP, PET, PS)로 선별하고 있습니다. 이후 선별된 제품은 재질별로 전문 재활용업체로 운반되어 재활용하고 있습니다. ·크기가 큰 플라스틱 제품은 수거한 후 재활용 선별장에서 선별하기가 곤란하여 소각하거나 전문 재활용업체로 위탁하여 처리하고 있습니다.', '["플라스틱 수납장은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=686', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·단일재질의 플라스틱 용기 또는 제품은 플라스틱수거함으로 배출하면 선별장으로 이송되어 재질별(PE, PP, PET, PS)로 선별하고 있습니다. 이후 선별된 제품은 재질별로 전문 재활용업체로 운반되어 재활용하고 있습니다. ·크기가 큰 플라스틱 제품은 수거한 후 재활용 선별장에서 선별하기가 곤란하여 소각하거나 전문 재활용업체로 위탁하여 처리하고 있습니다.', '· 크기가 큰 플라스틱 제품은 합성수지 재질이어도 대형폐기물로 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('의자', '의자', 'furniture', '· 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리되어 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다. · 상태가 좋아 다른 사람이 사용할 수 있는 폐가구는 재활용센터에 판매할 수 있으며, 업체에 따라 무상으로 수거하는 경우도 있습니다. 폐가구를 배출하시기 전 가까운 재활용센터에 문의하여 주시기', '["의자는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=687', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리되어 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다. · 상태가 좋아 다른 사람이 사용할 수 있는 폐가구는 재활용센터에 판매할 수 있으며, 업체에 따라 무상으로 수거하는 경우도 있습니다. 폐가구를 배출하시기 전 가까운 재활용센터에 문의하여 주시기 바랍니다.', '· 대형폐기물 배출 시 보행자에게 불편을 주지 않도록 주의하여 배출 · 재사용 가능여부에 따라 재활용센터로 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('화장대', '화장대', 'furniture', '· 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리되어 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다. · 상태가 좋아 다른 사람이 사용할 수 있는 폐가구는 재활용센터에 판매할 수 있으며, 업체에 따라 무상으로 수거하는 경우도 있습니다. 폐가구를 배출하시기 전 가까운 재활용센터에 문의하여 주시기', '["화장대는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=689', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리되어 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다. · 상태가 좋아 다른 사람이 사용할 수 있는 폐가구는 재활용센터에 판매할 수 있으며, 업체에 따라 무상으로 수거하는 경우도 있습니다. 폐가구를 배출하시기 전 가까운 재활용센터에 문의하여 주시기 바랍니다.', '· 대형폐기물 배출 시 보행자에게 불편을 주지 않도록 주의하여 배출 · 재사용 가능여부에 따라 재활용센터로 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('에어풀장', '에어풀장', 'furniture', '· 에어풀장은 PVC(폴리염화비닐) 또는 TPU(열가소성폴리우레탄)재질로 구성하고 있습니다. · 가정에서 배출하는 PVC, TPU 재질은 주로 소량으로 배출되어 재활용하기에 어려움이 있습니다. · 폴리염화비닐(PVC)은 다른 합성수지와 혼합되어 재활용될 경우 재활용제품의 강도가 떨어지고 재활용과정에서 염화수소와 같은 유해화학물질이 발생하는 등 다양한 문제를', '["에어풀장은 내용물(공기)를 제거한 후 종량제봉투로 배출합니다.", "크기가 큰 에어풀장은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=690', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 에어풀장은 PVC(폴리염화비닐) 또는 TPU(열가소성폴리우레탄)재질로 구성하고 있습니다. · 가정에서 배출하는 PVC, TPU 재질은 주로 소량으로 배출되어 재활용하기에 어려움이 있습니다. · 폴리염화비닐(PVC)은 다른 합성수지와 혼합되어 재활용될 경우 재활용제품의 강도가 떨어지고 재활용과정에서 염화수소와 같은 유해화학물질이 발생하는 등 다양한 문제를 일으키고 있어 재활용이 어렵습니다.', '· 공기를 제거하여 최대한 부피를 줄인 후 끈으로 묶은 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('행거', '행거', 'furniture', '· 행거는 주로 금속재질(스테인리스 재질)로 구성하고 있으며, 그 밖에 플라스틱, 목재재질이 있습니다. · 스테인리스 재질은 고철에 해당되어 재활용이 가능하나 행거의 경우 주로 크기가 커 대형폐기물로 배출해야 합니다. · 행거가 구성별로 분리가 가능한 경우에는 분리한 후 고철수거함으로 배출할 수 있습니다.', '["행거는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=691', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, '· 행거 재질을 확인한 후 배출', '2026-05-18', 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('테이블 프레임', '테이블 프레임', 'furniture', '·테이블의 받침부분인 프레임이 철제로 되어 있어 분리가 가능한 경우에는 고철수거함에 배출하고, 중량과 부피가 큰 제품인 경우 대형폐기물로 배출하여야 합니다.', '["테이블 프레임은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=692', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·테이블의 받침부분인 프레임이 철제로 되어 있어 분리가 가능한 경우에는 고철수거함에 배출하고, 중량과 부피가 큰 제품인 경우 대형폐기물로 배출하여야 합니다.', '·크키가 큰 제품은 재질에 상관없이 대형폐기물로 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('캐리어', '캐리어', 'furniture', '·가방은 가죽, 천, 금속 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ·상태가 좋은 의류 및 섬유제품은 의류수거함으로 배출할 수 있으며, 의류수거함으로 배출한 품목은 전문 업체에서 품목별로 선별한 후 국내 또는 국외로 판매하여 재사용하고 있습니다. ·다만,캐리어는와 같이 크기가 크거나 훼손이 심하여 다른 사람이 재사용하기 어려운 제품은 종량제봉투', '["캐리어는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=693', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·가방은 가죽, 천, 금속 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ·상태가 좋은 의류 및 섬유제품은 의류수거함으로 배출할 수 있으며, 의류수거함으로 배출한 품목은 전문 업체에서 품목별로 선별한 후 국내 또는 국외로 판매하여 재사용하고 있습니다. ·다만,캐리어는와 같이 크기가 크거나 훼손이 심하여 다른 사람이 재사용하기 어려운 제품은 종량제봉투 또는 대형폐기물로 배출하여야 합니다.', '· 의류수거함에 배출 불가', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('지팡이', '지팡이', 'furniture', '· 지팡이는 고철, 섬유, 고무 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보', '["지팡이는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=694', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 지팡이는 고철, 섬유, 고무 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분...', '', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('블라인드', '블라인드', 'furniture', '· 블라인드는 제품의 종류에 따라 플라스틱, 목재, 섬유, 고철 등 재질로 다양한 재질의 부속품이 포함되어 있습니다. · 블라인드는 대부분 크기가 커 대형폐기물로 배출합니다.', '["블라인드는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=695', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 블라인드는 제품의 종류에 따라 플라스틱, 목재, 섬유, 고철 등 재질로 다양한 재질의 부속품이 포함되어 있습니다. · 블라인드는 대부분 크기가 커 대형폐기물로 배출합니다.', '· 크기가 크거나 길이가 긴 제품은 끈으로 묶은 후 배출', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('좌식테이블', '좌식테이블', 'furniture', '· 좌식테이블은 목재, 고철, 플라스틱 등 다양한 재질로 제작됩니다. · 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리하고 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사', '["좌식테이블은 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=696', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 좌식테이블은 목재, 고철, 플라스틱 등 다양한 재질로 제작됩니다. · 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리하고 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다. · 크기가 큰 제품은 대형폐기물로 배출해야 하며, 일부 대형폐기물 품목에 기재되지 않은 물품은 종류 및 규격을 감안하여 유사한 품목 수수료에 준하여 책정하고 있...', '', '2026-05-18', 0, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('스탭퍼', '스탭퍼', 'furniture', '·가정에서 사용하는 실내 운동기구는 고철, 고무, 플라스틱이 혼합된 복합재질 제품이며, 크기가 커 대형폐기물로 배출하여야 합니다. ·대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱, 전자제품 등으로 선별한 후 처리업체로 이송됩니다. 이 중 전기전자제품은 전자제품 재활', '["스탭퍼는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=697', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·가정에서 사용하는 실내 운동기구는 고철, 고무, 플라스틱이 혼합된 복합재질 제품이며, 크기가 커 대형폐기물로 배출하여야 합니다. ·대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱, 전자제품 등으로 선별한 후 처리업체로 이송됩니다. 이 중 전기전자제품은 전자제품 재활용업체로 이송되어 재활용하고 있습니다...', '', '2026-05-18', 0, '["대형폐기물"]');
