INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('디지털 체중계', '디지털 체중계', 'furniture', '· 체중계는 플라스틱, 금속, 유리 등이 혼합된 복합재질 제품으로 재활용이 어려우며, 해당 제품은 대형폐기물로 배출합니다. · 전자식 체중계(디지털, 스마트)는 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품은 가까운 소형가전제품 수거함으로 배출하여 주시거나 별도 수거함이 마련되지 않은 경우에는 대형폐기물로 배출하', '["디지털 체중계는 소형전기전자제품 전용수거함으로 배출합니다.", "디지털 체중계는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=701', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 체중계는 플라스틱, 금속, 유리 등이 혼합된 복합재질 제품으로 재활용이 어려우며, 해당 제품은 대형폐기물로 배출합니다. · 전자식 체중계(디지털, 스마트)는 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품은 가까운 소형가전제품 수거함으로 배출하여 주시거나 별도 수거함이 마련되지 않은 경우에는 대형폐기물로 배출하여 주시기 바랍니다. · 또한, 지자...', '', '2026-05-18', 0, '["재활용폐기물", "전기전자 제품류", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('세면대', '세면대', 'general', '· 변기, 세면대 등은 대부분 세라믹 재질로 불연성폐기물이나 대부분 크기가 커 대형폐기물로 배출합니다. · 인테리어 공사 등에서 발생한 폐기물은 불연성 마대 또는 대형폐기물로 배출할 수 있으며, 다량으로 배출될 시 지자체에 문의하여 공사장생활폐기물 전문 수거업체에 연락하여 처리할 수 있습니다 ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체', '["세면대는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=702', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 변기, 세면대 등은 대부분 세라믹 재질로 불연성폐기물이나 대부분 크기가 커 대형폐기물로 배출합니다. · 인테리어 공사 등에서 발생한 폐기물은 불연성 마대 또는 대형폐기물로 배출할 수 있으며, 다량으로 배출될 시 지자체에 문의하여 공사장생활폐기물 전문 수거업체에 연락하여 처리할 수 있습니다 ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해...', '', '2026-05-18', 0, '["대형폐기물", "공사장 생활폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('안약', '안약', 'medicine', '· 안약은 가까운 약국이나 보건소, 주민센터 등에 비치된 폐의약품전용수거함으로 배출합니다. · 의약품의 경우(물약, 안약 제외) 일부 지자체에 한하여 우정산업본부와 사전협의를 통해 우체통으로 배출하는 경우도 있습니다.', '["안약은 폐의약품수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=703', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 안약은 가까운 약국이나 보건소, 주민센터 등에 비치된 폐의약품전용수거함으로 배출합니다. · 의약품의 경우(물약, 안약 제외) 일부 지자체에 한하여 우정산업본부와 사전협의를 통해 우체통으로 배출하는 경우도 있습니다.', '·제품 포장재 의약품/의약외품 확인 후 배출 ·종이 포장박스는 분리하고 뚜껑은 닫아서 배출', '2026-05-18', 0, '["생활계 유해폐기물", "폐의약품"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('살충제', '살충제', 'hazardous', '· 폐농약은 농작을 해치는 균, 곤충, 잡초 등을 제거하기 위해 사용하는 약품으로 살균제, 살충제, 제초제 등이 있습니다. · 폐농약은 제품에 포함된 유해물질로 인하여 폐기물관리법 시행규칙 및 환경부 고시로 정하고 있는 생활계유해폐기물에 해당됩니다. * 생활계유해폐기물이란 폐농약, 폐의약품 등 인간의 건광과 주변환경에 피해를 유발할 수 있는 폐기물을 말합니', '["살충제는 전용수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=704', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 폐농약은 농작을 해치는 균, 곤충, 잡초 등을 제거하기 위해 사용하는 약품으로 살균제, 살충제, 제초제 등이 있습니다. · 폐농약은 제품에 포함된 유해물질로 인하여 폐기물관리법 시행규칙 및 환경부 고시로 정하고 있는 생활계유해폐기물에 해당됩니다. * 생활계유해폐기물이란 폐농약, 폐의약품 등 인간의 건광과 주변환경에 피해를 유발할 수 있는 폐기물을 말합니다. · 폐농약은 잔류농약이 담긴 용...', '·내용물이 남아있는 경우 외부로 유출되지 않도록 완전히 밀봉한 후 배출', '2026-05-18', 0, '["생활계 유해폐기물", "폐농약"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('살균제', '살균제', 'hazardous', '· 폐농약은 농작을 해치는 균, 곤충, 잡초 등을 제거하기 위해 사용하는 약품으로 살균제, 살충제, 제초제 등이 있습니다. · 폐농약은 제품에 포함된 유해물질로 인하여 폐기물관리법 시행규칙 및 환경부 고시로 정하고 있는 생활계유해폐기물에 해당됩니다. * 생활계유해폐기물이란 폐농약, 폐의약품 등 인간의 건광과 주변환경에 피해를 유발할 수 있는 폐기물을 말합니', '["살균제는 전용수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=706', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 폐농약은 농작을 해치는 균, 곤충, 잡초 등을 제거하기 위해 사용하는 약품으로 살균제, 살충제, 제초제 등이 있습니다. · 폐농약은 제품에 포함된 유해물질로 인하여 폐기물관리법 시행규칙 및 환경부 고시로 정하고 있는 생활계유해폐기물에 해당됩니다. * 생활계유해폐기물이란 폐농약, 폐의약품 등 인간의 건광과 주변환경에 피해를 유발할 수 있는 폐기물을 말합니다. · 폐농약은 잔류농약이 담긴 용...', '·내용물이 남아있는 경우 외부로 유출되지 않도록 완전히 밀봉한 후 배출', '2026-05-18', 0, '["생활계 유해폐기물", "폐농약"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('혈압계', '혈압계', 'hazardous', '· 수은함유폐기물이란 수은과 그 화합물을 함유한 폐기물을 말하며, 혈압계, 온도계, 체온계 등이 있습니다. · 혈압계, 온도계 등에 포함된 수은은 인체에 혼입될 시 발열, 오한, 구토 등의 급성 증상과 구강염증, 기억력 소실, 지적능력 저하 등 만성 증상이 발생할 수 있으며, 환경에 유출될 시 생물 농축, 잔류 등 악영향을 일으킬 수 있습니다. · 수은이', '["혈압계는 전용수거함으로 배출합니다.", "지역 내 전용수거함이 마련되지 않은 경우에는 내용물이 외부로 유출되지 않도록 주의하여 종량제봉투 등으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=707', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 수은함유폐기물이란 수은과 그 화합물을 함유한 폐기물을 말하며, 혈압계, 온도계, 체온계 등이 있습니다. · 혈압계, 온도계 등에 포함된 수은은 인체에 혼입될 시 발열, 오한, 구토 등의 급성 증상과 구강염증, 기억력 소실, 지적능력 저하 등 만성 증상이 발생할 수 있으며, 환경에 유출될 시 생물 농축, 잔류 등 악영향을 일으킬 수 있습니다. · 수은이 함유된 폐기물을 배출할 때에는 분해·...', '· 수은이 외부로 유출될 시 환경 및 인체에 유해하므로 주의하여 배출', '2026-05-18', 0, '["생활계 유해폐기물", "수은함유 폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('소화제', '소화제', 'medicine', '· 가정에서 배출하는 의약품은 약국에서 판매하는 해열제, 감기약 등의 상비약과 의사의 처방이 필요한 전문의약품으로 구분됩니다. · 그 밖에 치약, 가글, 살충제 등 인체에 약하거나 직접적으로 작용하지 않는 의약외품이 있습니다. · 의약품과 의약외품을 구분하는 방법은 처방여부, 포장재 겉면에 표기된 문구를 통해 확인하실 수 있습니다. · 가정에서 배출하는 의', '["소화제는 폐의약품수거함으로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=708', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 배출하는 의약품은 약국에서 판매하는 해열제, 감기약 등의 상비약과 의사의 처방이 필요한 전문의약품으로 구분됩니다. · 그 밖에 치약, 가글, 살충제 등 인체에 약하거나 직접적으로 작용하지 않는 의약외품이 있습니다. · 의약품과 의약외품을 구분하는 방법은 처방여부, 포장재 겉면에 표기된 문구를 통해 확인하실 수 있습니다. · 가정에서 배출하는 의약품은 가까운 약국이나 보건소, 주민...', '· 병원에서 조제한 약은 반드시 폐의약품전용수거함으로 배출', '2026-05-18', 0, '["생활계 유해폐기물", "폐의약품"]');
