INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('현미경', '현미경', 'furniture', '· 망원경, 쌍안경, 현미경 등은 유리, 플라스틱, 고철 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 현미경의 크기는 사양, 특징, 종류 등에 따라 다르므로 크기가 큰 제품은 대형폐기물로 배출해야 합니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱', '["현미경은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=710', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 망원경, 쌍안경, 현미경 등은 유리, 플라스틱, 고철 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 현미경의 크기는 사양, 특징, 종류 등에 따라 다르므로 크기가 큰 제품은 대형폐기물로 배출해야 합니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱, 전자제품 등으로 선별한 후 처리업...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('칼', '칼', 'general', '· 가위, 칼과 같은 날카로운 제품은 금속재질이더라도 배출자, 수거원 등이 다칠 우려가 있으므로 주의하여 종량제봉투로 배출해야 합니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다.', '["칼은 신문지, 테이프 등을 활용하여 감싼 후 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=711', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가위, 칼과 같은 날카로운 제품은 금속재질이더라도 배출자, 수거원 등이 다칠 우려가 있으므로 주의하여 종량제봉투로 배출해야 합니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다.', '· 칼과 같은 날카롭고 위험한 폐기물을 배출할 때에는 날카로운 부분이 외부로 노출되어 사람이 찔리거나 베이지 않도록 용기에 담거나 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('천체망원경', '천체망원경', 'furniture', '· 망원경, 쌍안경, 현미경 등은 유리, 플라스틱, 고철 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 망원경의 크기는 사양, 특징, 종류 등에 따라 다르므로 크기가 큰 제품은 대형폐기물로 배출해야 합니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱', '["천체망원경은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=712', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 망원경, 쌍안경, 현미경 등은 유리, 플라스틱, 고철 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 망원경의 크기는 사양, 특징, 종류 등에 따라 다르므로 크기가 큰 제품은 대형폐기물로 배출해야 합니다. · 대형폐기물은 크기, 부피 등이 커 종량제봉투로 배출하기 어려운 폐기물을 말합니다. 대형폐기물로 배출된 폐기물은 가연성, 목재제품, 플라스틱, 전자제품 등으로 선별한 후 처리업...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('바닥매트', '바닥매트', 'furniture', '· 가정에서 사용하는 매트는 폴리염화비닐(PVC) 재질 또는 엘라스토머(고무) 재질로 제작됩니다. · PVC비닐은 일반 비닐과 물성이 달라서 비닐류 배출시 재활용이 되지 않습니다. · 가정에서 사용하는 고무 제품은 주로 두 가지 이상 재질이 혼합된 합성 고무재질로 종량제봉투로 배출합니다. · 크기가 큰 바닥매트는 대형폐기물로 배출합니다.', '["바닥매트는 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=713', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 사용하는 매트는 폴리염화비닐(PVC) 재질 또는 엘라스토머(고무) 재질로 제작됩니다. · PVC비닐은 일반 비닐과 물성이 달라서 비닐류 배출시 재활용이 되지 않습니다. · 가정에서 사용하는 고무 제품은 주로 두 가지 이상 재질이 혼합된 합성 고무재질로 종량제봉투로 배출합니다. · 크기가 큰 바닥매트는 대형폐기물로 배출합니다.', '· 크기가 큰 매트를 배출할 때에는 보행자에게 불편을 주지 않도록 끈으로 묶어서 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('마스킹테이프', '마스킹테이프', 'general', '· 마스킹테이프는 종이(지지체)에 점착제가 도포되어 있어 재활용이 어렵습니다. · 골판지 상자 등에 부착된 마스킹테이프는 제거하여 배출하여 주시기 바라며, 제거하기 어려운 경우에는 칼 등을 이용하여 접선 부분을 자른 후 접어서 배출합니다.', '["마스킹테이프는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=714', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 마스킹테이프는 종이(지지체)에 점착제가 도포되어 있어 재활용이 어렵습니다. · 골판지 상자 등에 부착된 마스킹테이프는 제거하여 배출하여 주시기 바라며, 제거하기 어려운 경우에는 칼 등을 이용하여 접선 부분을 자른 후 접어서 배출합니다.', '· 제품에 붙은 마스킹테이프는 제거한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('만년필', '만년필', 'general', '· 만년필은 플라스틱, 잉크 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '["만년필은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=715', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 만년필은 플라스틱, 잉크 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '· 제품 그대로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('바늘', '바늘', 'general', '· 바늘, 가위, 칼과 같은 날카로운 제품은 금속재질이더라도 배출자, 수거원 등이 다칠 우려가 있으므로 주의하여 종량제봉투로 배출해야 합니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다.', '["바늘은 신문지, 테이프 등을 활용하여 감싼 후 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=716', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 바늘, 가위, 칼과 같은 날카로운 제품은 금속재질이더라도 배출자, 수거원 등이 다칠 우려가 있으므로 주의하여 종량제봉투로 배출해야 합니다. · 종량제봉투로 배출한 제품은 소각시설로 반입되어 소각처리되며, 이때 반입된 금속성분은 금속분리기에 의해 분리 및 선별되어 고철로 재활용합니다.', '· 바늘과 같은 날카롭고 위험한 폐기물을 배출할 때에는 날카로운 부분이 외부로 노출되어 사람이 찔리거나 베이지 않도록 용기에 담거나 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('폼보드', '폼보드', 'general', '· 폼보드는 우드락 원단에 종이필름을 붙인 것을 말합니다. · 폼보드 제품은 일반 스티로폼과 물성이 달라 일반 스티로폼 제품과 함께 재활용할 시 재활용 제품(잉고트 제품) 품질에 영향을 미칩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를', '["폼보드는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=717', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 폼보드는 우드락 원단에 종이필름을 붙인 것을 말합니다. · 폼보드 제품은 일반 스티로폼과 물성이 달라 일반 스티로폼 제품과 함께 재활용할 시 재활용 제품(잉고트 제품) 품질에 영향을 미칩니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('택배 송장', '택배 송장', 'general', '· 택배 송장은 감열지와 이형지로 제작되며 뒷면에 접착제가 도포되어 있어 재활용이 되지 않으므로 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을', '["택배 송장은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=718', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 택배 송장은 감열지와 이형지로 제작되며 뒷면에 접착제가 도포되어 있어 재활용이 되지 않으므로 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('커팅매트', '커팅매트', 'general', '· 커팅매트는 종이, 시트류 등 재단시 사용하는 제품으로 PVC재질입니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까', '["커팅매트는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=719', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 커팅매트는 종이, 시트류 등 재단시 사용하는 제품으로 PVC재질입니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('연필꽂이의 재질', '연필꽂이의 재질', 'can', '· 연필꽂이는 플라스틱, 목재, 가죽, 금속 등 재질이 다양합니다. · 플라스틱, 금속 등 단일재질 제품은 재활용이 가능하므로 전용수거함으로 배출하여 주시기 바랍니다. · 목재류, 가죽, 섬유 제품은 재활용이 어려우므로 종량제봉투로 배출해야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법', '["연필꽂이의 재질에 맞게 고철 수거함, 플라스틱 수거함 등으로 배출합니다.", "제품이 목재, 가죽, 섬유 등의 재질이거나 2개 이상의 재질이 혼합된 복합재질인 경우에는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=720', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 연필꽂이는 플라스틱, 목재, 가죽, 금속 등 재질이 다양합니다. · 플라스틱, 금속 등 단일재질 제품은 재활용이 가능하므로 전용수거함으로 배출하여 주시기 바랍니다. · 목재류, 가죽, 섬유 제품은 재활용이 어려우므로 종량제봉투로 배출해야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('고무통', '고무통', 'furniture', '· 대부분의 고무통은 PVC 재질로 제작됩니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다.', '["고무통은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=721', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 대부분의 고무통은 PVC 재질로 제작됩니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다.', '· PVC 제품은 재활용이 어려워 종량제봉투 또는 대형폐기물로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('공기청정기 필터', '공기청정기 필터', 'general', '· 연수기, 정수기, 공기청정기 등에 사용되는 필터는 플라스틱, 합성섬유, 활성탄 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 일부 제품의 경우 외부 케이스(플라스틱)를 분리할 수 있도록 되어 있으며, 배출하실 때에는 케이스를 분리한 후 플라스틱 수거함으로 배출하여 주시면 재활용이 가능합니다.', '["공기청정기 필터는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=722', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 연수기, 정수기, 공기청정기 등에 사용되는 필터는 플라스틱, 합성섬유, 활성탄 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. · 일부 제품의 경우 외부 케이스(플라스틱)를 분리할 수 있도록 되어 있으며, 배출하실 때에는 케이스를 분리한 후 플라스틱 수거함으로 배출하여 주시면 재활용이 가능합니다.', '· 플라스틱 케이스를 분리할 수 있는 경우에는 분리한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('슬리퍼', '슬리퍼', 'general', '· 슬리퍼는 주로 EVA, PVC 등의 재질로 제작하고 있습니다. · 가정에서 사용하는 EVA는 주로 샌달, 구두창 등의 제품으로 사용하고 있으며, 주로 소량으로 발생되어 재활용이 어렵습니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하', '["슬리퍼는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=723', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 슬리퍼는 주로 EVA, PVC 등의 재질로 제작하고 있습니다. · 가정에서 사용하는 EVA는 주로 샌달, 구두창 등의 제품으로 사용하고 있으며, 주로 소량으로 발생되어 재활용이 어렵습니다. · PVC제품은 일반 플라스틱과 물성이 달라서 플라스틱으로 배출시 재활용이 되지 않습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('치실', '치실', 'general', '· 치실은 플라스틱 손잡이에 치실이 부착되어 있는 제품으로, 재질별 분리가 어려워 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현', '["치실은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=725', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 치실은 플라스틱 손잡이에 치실이 부착되어 있는 제품으로, 재질별 분리가 어려워 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('농구공', '농구공', 'general', '· 공은 고무, 플라스틱 등으로 제작되어 있으며, 접착제와 섬유재질이 혼합된 복합재질제품으로 재활용이 어렵습니다. · 공의 내부는 공기로 채워져 있어 배출, 수거하기에 어려움이 있으므로 가급적 제거한 후 배출하는 것이 좋습니다.', '["농구공은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=726', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 공은 고무, 플라스틱 등으로 제작되어 있으며, 접착제와 섬유재질이 혼합된 복합재질제품으로 재활용이 어렵습니다. · 공의 내부는 공기로 채워져 있어 배출, 수거하기에 어려움이 있으므로 가급적 제거한 후 배출하는 것이 좋습니다.', '· 공기를 제거한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('배구공', '배구공', 'general', '· 공은 고무, 플라스틱 등으로 제작되어 있으며, 접착제와 섬유재질이 혼합된 복합재질제품으로 재활용이 어렵습니다. · 공의 내부는 공기로 채워져 있어 배출, 수거하기에 어려움이 있으므로 가급적 제거한 후 배출하는 것이 좋습니다.', '["배구공은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=727', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 공은 고무, 플라스틱 등으로 제작되어 있으며, 접착제와 섬유재질이 혼합된 복합재질제품으로 재활용이 어렵습니다. · 공의 내부는 공기로 채워져 있어 배출, 수거하기에 어려움이 있으므로 가급적 제거한 후 배출하는 것이 좋습니다.', '· 공기를 제거한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('행주', '행주', 'general', '· 행주는 주방을 청결하게 청소하는데 사용하는 도구로 주로 면 등 섬유 재질입니다. · 행주의 표면에 이물질이 묻어있거나 찢어지는 등 타인이 다시 사용하기 어려워 종량제봉투로 배출하여야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확', '["행주는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=728', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 행주는 주방을 청결하게 청소하는데 사용하는 도구로 주로 면 등 섬유 재질입니다. · 행주의 표면에 이물질이 묻어있거나 찢어지는 등 타인이 다시 사용하기 어려워 종량제봉투로 배출하여야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('나무 쟁반', '나무 쟁반', 'general', '· 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리하고 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다.', '["나무 쟁반은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=729', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 배출하는 목재제품은 표면에 방부제, 페인트, 오일 등을 처리하고 있어 물질 재활용이 어려워 주로 소각하거나 고형연료제품으로 에너지 재활용하고 있습니다.', '· 목재제품은 재활용이 어려우므로 종량제봉투로 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('쿠션', '쿠션', 'furniture', '· 대부분의 상태가 좋은 의류 및 섬유제품은 의류수거함으로 배출하여 국내 또는 국외로 판매하여 재사용하고 있습니다. · 다만, 솜이불, 베개, 방석, 쿠션 등 일부 의류수거함으로 배출하기 어려운 품목이 있으며 해당 품목들은 일반폐기물, 대형폐기물, 재활용폐기물 배출방법에 의거하여 배출하여 주셔야 합니다.', '["쿠션은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=731', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 대부분의 상태가 좋은 의류 및 섬유제품은 의류수거함으로 배출하여 국내 또는 국외로 판매하여 재사용하고 있습니다. · 다만, 솜이불, 베개, 방석, 쿠션 등 일부 의류수거함으로 배출하기 어려운 품목이 있으며 해당 품목들은 일반폐기물, 대형폐기물, 재활용폐기물 배출방법에 의거하여 배출하여 주셔야 합니다.', '· 의류수거함으로 배출할 수 있는 제품은 정해져 있으므로 배출가능 대상 품목을 확인한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('비치볼', '비치볼', 'furniture', '· 비치볼은 대부분 PVC, EVA재질로 재활용이 어렵습니다. · 폴리염화비닐(PVC)은 다른 합성수지와 혼합되어 재활용될 경우 재활용제품의 강도가 떨어지고 재활용과정에서 염화수소와 같은 유해화학물질이 발생하는 등 다양한 문제를 일으키고 있어 재활용이 어렵습니다. · 공의 내부는 공기로 채워져 있어 배출, 수거하기에 어려움이 있으므로 가급적 제거한 후 배출', '["·비치볼은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=732', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 비치볼은 대부분 PVC, EVA재질로 재활용이 어렵습니다. · 폴리염화비닐(PVC)은 다른 합성수지와 혼합되어 재활용될 경우 재활용제품의 강도가 떨어지고 재활용과정에서 염화수소와 같은 유해화학물질이 발생하는 등 다양한 문제를 일으키고 있어 재활용이 어렵습니다. · 공의 내부는 공기로 채워져 있어 배출, 수거하기에 어려움이 있으므로 가급적 제거한 후 배출하는 것이 좋습니다.', '· PVC 제품은 재활용이 어려워 종량제봉투 또는 대형폐기물로 배출 · 공기를 제거한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('화장솜', '화장솜', 'general', '·화장솜은 면 또는 펄프와 레이온 혼방 재질로 제작되며 재활용이 어럽습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현', '["화장솜은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=733', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·화장솜은 면 또는 펄프와 레이온 혼방 재질로 제작되며 재활용이 어럽습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기 분리배출...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 핸드크림 용기', '깨끗한 핸드크림 용기', 'can', '· 바세린, 핸드크림 등의 화장품(내용물)은 재활용이 어렵습니다. · 내용물을 모두 사용한 용기는 물로 헹구는 등 이물질을 제거한 후 재질에 맞게 금속, 플라스틱으로 배출하여 주시면 재활용에 용이합니다. · 화장품의 내용물이 남아 있어서 제거하기 곤란한 경우에는 종량제봉투에 배출합니다.', '["깨끗한 핸드크림 용기는 재질에 맞게 고철수거함, 플라스틱 수거함으로 배출합니다.", "내용물 제거가 어려운 경우 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=734', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 바세린, 핸드크림 등의 화장품(내용물)은 재활용이 어렵습니다. · 내용물을 모두 사용한 용기는 물로 헹구는 등 이물질을 제거한 후 재질에 맞게 금속, 플라스틱으로 배출하여 주시면 재활용에 용이합니다. · 화장품의 내용물이 남아 있어서 제거하기 곤란한 경우에는 종량제봉투에 배출합니다.', '· 이물질을 제거한 후 배출', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('침대커버', '침대커버', 'general', '· 대부분의 상태가 좋은 의류 및 섬유제품은 의류수거함으로 배출하여 국내 또는 국외로 판매하여 재사용하고 있습니다. · 다만, 솜이불, 베개, 방석, 침대 커버 등 일부 의류수거함으로 배출하기 어려운 품목이 있으며 해당 품목들은 일반폐기물, 대형폐기물, 재활용폐기물 배출방법에 의거하여 배출하여 주셔야 합니다.', '["침대커버는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=735', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 대부분의 상태가 좋은 의류 및 섬유제품은 의류수거함으로 배출하여 국내 또는 국외로 판매하여 재사용하고 있습니다. · 다만, 솜이불, 베개, 방석, 침대 커버 등 일부 의류수거함으로 배출하기 어려운 품목이 있으며 해당 품목들은 일반폐기물, 대형폐기물, 재활용폐기물 배출방법에 의거하여 배출하여 주셔야 합니다.', '· 의류수거함으로 배출할 수 있는 제품은 정해져 있으므로 배출가능 대상 품목을 확인한 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('닭뼈', '닭뼈', 'general', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. · 동물의 뼈와 같이 딱딱한 물질이 처리시설에 반입되면 분쇄시 설비 고장을 일으킬 수 있으므로 종량제봉투로 배출하여야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍', '["닭뼈는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=736', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. · 동물의 뼈와 같이 딱딱한 물질이 처리시설에 반입되면 분쇄시 설비 고장을 일으킬 수 있으므로 종량제봉투로 배출하여야 합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('상장 케이스', '상장 케이스', 'general', '· 상장 케이스는 주로 종이 상장을 보호하기 위하여 사용하는 제품입니다. · 상장 케이스는 벨벳(우단), 금속, 종이 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에', '["상장 케이스는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=737', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 상장 케이스는 주로 종이 상장을 보호하기 위하여 사용하는 제품입니다. · 상장 케이스는 벨벳(우단), 금속, 종이 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('인슐린 주사기', '인슐린 주사기', 'general', '· 가정에서 발생하는 인슐린 주사기는 폐의약품에 해당하지 않으며 의료폐기물에도 해당하지 않습니다. · 주사기는 주사기의 바늘이 외부로 노출되지 않도록 안전하게 밀봉한 후 배출합니다.', '["인슐린 주사기는 충분히 감싼 후 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=738', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가정에서 발생하는 인슐린 주사기는 폐의약품에 해당하지 않으며 의료폐기물에도 해당하지 않습니다. · 주사기는 주사기의 바늘이 외부로 노출되지 않도록 안전하게 밀봉한 후 배출합니다.', '· 주사기의 날카로운 부분이 외부로 노출되어 사람이 찔리거나 베이지 않도록 용기에 담거나 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "생활계 유해폐기물", "기타"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('콜라겐 가루', '콜라겐 가루', 'general', '· 가루 형태의 건강보조 식품은 음식물류폐기물과 의약품에 해당하지 않으며 일반쓰레기로 배출합니다.', '["콜라겐 가루는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=739', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 가루 형태의 건강보조 식품은 음식물류폐기물과 의약품에 해당하지 않으며 일반쓰레기로 배출합니다.', '· 가루가 흘러나오지 않도록 밀봉하여 배출', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('안경', '안경', 'general', '· 안경은 유리, 플라스틱, 금속 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체', '["안경은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=740', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 안경은 유리, 플라스틱, 금속 등이 혼합된 복합재질 제품으로 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서 검색 장소 더보기...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('은박 접시', '은박 접시', 'general', '· 재활용 선별장에서는 알루미늄 캔, 용기, 제품을 선별하나 은박 접시는 선별이 용이하지 않기 때문에 종량제봉투로 배출합니다.', '["은박 접시는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=741', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 재활용 선별장에서는 알루미늄 캔, 용기, 제품을 선별하나 은박 접시는 선별이 용이하지 않기 때문에 종량제봉투로 배출합니다.', '· 금속캔, 고철류로 배출 불가', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('토너', '토너', 'general', '· 토너, 잉크는 프린터기, 복합기 등 탈착식으로 내장된 카트리지에 포함된 물질로 토너는 분말 형태로, 잉크는 액체 형태입니다. · 토너와 잉크는 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에', '["토너는 카트리지에 들어있는 분말가루로 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=742', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 토너, 잉크는 프린터기, 복합기 등 탈착식으로 내장된 카트리지에 포함된 물질로 토너는 분말 형태로, 잉크는 액체 형태입니다. · 토너와 잉크는 종량제봉투로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('스키신발', '스키신발', 'general', '· 스키신발은 플라스틱과 섬유 등 다양한 재질이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '["스키신발은 종량제봉투로 배출합니다.", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=743', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 스키신발은 플라스틱과 섬유 등 다양한 재질이 혼합된 복합재질 제품으로 재활용이 어렵습니다.', '· 의류수거함에 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('육수팩', '육수팩', 'general', '· 육수팩은 멸치, 버섯, 다시마 등을 담아 국물을 우려낼때 사용한 제품으로 재질은 PLA, 부직포 등이 사용되고 있습니다. · 육수팩은 재활용이 어려우므로 일반쓰레기로 배출합니다. · 육수팩의 멸치, 버섯, 다시마 등 내용물은 음식물류폐기물로 배출합니다.', '["육수팩은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=744', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 육수팩은 멸치, 버섯, 다시마 등을 담아 국물을 우려낼때 사용한 제품으로 재질은 PLA, 부직포 등이 사용되고 있습니다. · 육수팩은 재활용이 어려우므로 일반쓰레기로 배출합니다. · 육수팩의 멸치, 버섯, 다시마 등 내용물은 음식물류폐기물로 배출합니다.', '· 음식물류폐기물로 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('한약 찌꺼기', '한약 찌꺼기', 'general', '· 녹차잎 등 차류 및 한약의 찌꺼기는 영양성분이 거의 남아있지 않아 재활용품(사료, 퇴비)의 가치가 떨어지므로 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처', '["한약 찌꺼기는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=745', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 녹차잎 등 차류 및 한약의 찌꺼기는 영양성분이 거의 남아있지 않아 재활용품(사료, 퇴비)의 가치가 떨어지므로 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('과일그물망', '과일그물망', 'general', '', '["과일그물망은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=746', '분리배출.kr (한국폐기물협회·환경부)', 'A', '', '· 과일을 포장할 때 사용하는 팬캡, 그물망은 EPE 재질로 된 발포합성수지입니다. · EPE는 재활용업체수가 적고 EPS와 분리하여 수집과 선별하기가 어려워서 가정에서 소량으로 발생하는 경우에는 일반쓰레기로 배출합니다.', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('옥수수껍질', '옥수수껍질', 'general', '· 옥수수껍질은 기계고장의 원인이 될 수 있고, 동물의 사료로 적합하지 않기 때문에 일반쓰레기로 배출합니다.', '["옥수수껍질은 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=747', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 옥수수껍질은 기계고장의 원인이 될 수 있고, 동물의 사료로 적합하지 않기 때문에 일반쓰레기로 배출합니다.', '·음식물류폐기물로 배출 불가능', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('바이올린', '바이올린', 'furniture', '· 바이올린은 나무재질에 나일론, 카본 등 여러가지 재질로 구성되어 있어 복합재질이므로 재활용이 어렵습니다. · 크기가 큰 기타, 첼로는 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운', '["바이올린은 종량제봉투로 배출합니다.", "종량제봉투에 담기 어려운 경우에는 대형폐기물로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=749', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 바이올린은 나무재질에 나일론, 카본 등 여러가지 재질로 구성되어 있어 복합재질이므로 재활용이 어렵습니다. · 크기가 큰 기타, 첼로는 대형폐기물로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('공갈젖꼭지', '공갈젖꼭지', 'general', '· 실리콘 수지는 열에 잘 변형되지 않는 열경화성 수지 제품으로 주로 조리도구, 유아용품 등에 사용됩니다. · 합성수지 제품(플라스틱 제품)은 선별압축-파쇄-세척-용융압출 등의 과정을 거쳐 재활용하고 있습니다. · 열경화성 수지 제품의 경우 열에 쉽게 변형되지 않아 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서', '["공갈젖꼭지는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=752', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 실리콘 수지는 열에 잘 변형되지 않는 열경화성 수지 제품으로 주로 조리도구, 유아용품 등에 사용됩니다. · 합성수지 제품(플라스틱 제품)은 선별압축-파쇄-세척-용융압출 등의 과정을 거쳐 재활용하고 있습니다. · 열경화성 수지 제품의 경우 열에 쉽게 변형되지 않아 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('아보카도씨', '아보카도씨', 'general', '· 아보카도, 감, 아보카도 등 단단한 씨앗은 분쇄시설의 고장을 유발할 수 있어 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현', '["아보카도씨는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=753', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 아보카도, 감, 아보카도 등 단단한 씨앗은 분쇄시설의 고장을 유발할 수 있어 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('칼라타이', '칼라타이', 'general', '· 칼라타이는 철심을 종이나 비닐로 깜싼 것으로 빵 봉지 등 봉지와 같은 용기의 입구를 묶는 데 사용됩니다. · 칼라타이는 크기가 작고 금속과 분리하는데 어려움이 있기 때문에 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소', '["칼라타이는 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=754', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 칼라타이는 철심을 종이나 비닐로 깜싼 것으로 빵 봉지 등 봉지와 같은 용기의 입구를 묶는 데 사용됩니다. · 칼라타이는 크기가 작고 금속과 분리하는데 어려움이 있기 때문에 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운...', '', '2026-05-18', 0, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('깨끗한 꿀 용기', '깨끗한 꿀 용기', 'glass', '· 물엿, 꿀 등은 물로 헹구어 하수로 배출합니다. · 라벨은 제거하여 비닐류로 배출하며, 용기는 재질에 맞게 유리병 수거함 또는 플라스틱 수거함으로 배출합니다. · 내용물(물엿, 꿀 등) 제거가 어려운 경우에는 뚜껑을 닫아 제품 그대로 종량제봉투로 배출하여 주시기 바랍니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법', '["깨끗한 꿀 용기는 재질에 맞게 유리병 수거함 또는 플라스틱 수거함으로 배출합니다.", "내용물 제거가 어려운 경우 종량제봉투로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=755', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 물엿, 꿀 등은 물로 헹구어 하수로 배출합니다. · 라벨은 제거하여 비닐류로 배출하며, 용기는 재질에 맞게 유리병 수거함 또는 플라스틱 수거함으로 배출합니다. · 내용물(물엿, 꿀 등) 제거가 어려운 경우에는 뚜껑을 닫아 제품 그대로 종량제봉투로 배출하여 주시기 바랍니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라...', '', '2026-05-18', 0, '["재활용폐기물", "합성수지 용기류", "유리병"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('냄비뚜껑(내열)', '냄비뚜껑(내열)', 'general', '· 내열유리란 일반 유리와 달리 내열성이 강하고 급격한 온도변화에도 견딜 수 있는 유리를 말합니다. · 내열유리로 만들어진 제품은 재활용이 어려우며 불에 타지 않는 불연성 폐기물로 전용봉투(마대)에 담아 배출하여야 합니다. · 재활용이 어렵고 불에 타지 않는 불연성폐기물은 수거 후 매립장으로 운반되어 매립하고 있습니다. ※ 배출방법은 지역별로 차이가 있을', '["냄비뚜껑(내열)은 불연성 종량제봉투(마대)로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=757', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 내열유리란 일반 유리와 달리 내열성이 강하고 급격한 온도변화에도 견딜 수 있는 유리를 말합니다. · 내열유리로 만들어진 제품은 재활용이 어려우며 불에 타지 않는 불연성 폐기물로 전용봉투(마대)에 담아 배출하여야 합니다. · 재활용이 어렵고 불에 타지 않는 불연성폐기물은 수거 후 매립장으로 운반되어 매립하고 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정...', '', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('와인잔', '와인잔', 'general', '·와인잔, 소주잔, 맥주잔과 같은 유리잔은 재활용이 어렵고 불에 타지 않는 폐기물로 불연성폐기물에 해당됩니다. ·불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. ·소량의 유리잔을 배출하실 때에는 제품이 깨지지 않도록 주의하여 종량제봉투로 배출하며, 유리잔이 깨진 경우에는 작업자, 수거원 등이 다치지 않도록 신문지,', '["와인잔은 불연성 종량제봉투(마대)로 배출합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=758', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·와인잔, 소주잔, 맥주잔과 같은 유리잔은 재활용이 어렵고 불에 타지 않는 폐기물로 불연성폐기물에 해당됩니다. ·불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. ·소량의 유리잔을 배출하실 때에는 제품이 깨지지 않도록 주의하여 종량제봉투로 배출하며, 유리잔이 깨진 경우에는 작업자, 수거원 등이 다치지 않도록 신문지, 테이프 등을 활용하여 충분히 감싼...', '· 깨진 유리는 날카로워 외부로 누출될 시 사람이 다칠 우려가 있으므로 베이지 않도록 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('수석', '수석', 'general', '· 수석은 재활용이 어렵고 불에타지 않은 폐기물로 불연성종량제봉투(마대)로 배출하여야 합니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. · 인테리어 공사 등에서 발생한 폐기물은 공사장생활폐기물에 해당되며, 폐기물 특성에 따라 종량제봉투, 불연성 마대, 재활용품 또는 대형폐기물로 배출하여야 합니다. 공사장', '["수석은 불연성종량제봉투(마대)로 배출합니다.", "다량으로 배출할 때에는 지자체에 문의하여 공사장생활폐기물 전문 처리업체에 위탁하여 처리합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=759', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 수석은 재활용이 어렵고 불에타지 않은 폐기물로 불연성종량제봉투(마대)로 배출하여야 합니다. · 불연성폐기물은 불연성종량제 마대로 배출하며 수거 후 매립장으로 운반되어 매립하고 있습니다. · 인테리어 공사 등에서 발생한 폐기물은 공사장생활폐기물에 해당되며, 폐기물 특성에 따라 종량제봉투, 불연성 마대, 재활용품 또는 대형폐기물로 배출하여야 합니다. 공사장생활폐기물을 다량으로 배출할 시 지자...', '', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물", "공사장 생활폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('대리석 상판', '대리석 상판', 'general', '· 대리석 상판은 대리석 재질로 불에 타지 않은 재질이므로 불연성폐기물로 배출합니다. · 인테리어 공사 등에서 발생한 폐기물은 공사장생활폐기물에 해당되며, 폐기물 특성에 따라 종량제봉투, 불연성 마대, 재활용품 또는 대형폐기물로 배출하여야 합니다. 공사장생활폐기물을 다량으로 배출할 시 지자체에 문의하여 공사장생활폐기물 전문 수거업체에 연락하여 처리할 수 있', '["대리석 상판은 불연성종량제봉투(특수규격마대)에 배출합니다.", "다량으로 배출할 때에는 지자체에 문의하여 공사장생활폐기물 전문 처리업체에 위탁하여 처리합니다."]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=760', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 대리석 상판은 대리석 재질로 불에 타지 않은 재질이므로 불연성폐기물로 배출합니다. · 인테리어 공사 등에서 발생한 폐기물은 공사장생활폐기물에 해당되며, 폐기물 특성에 따라 종량제봉투, 불연성 마대, 재활용품 또는 대형폐기물로 배출하여야 합니다. 공사장생활폐기물을 다량으로 배출할 시 지자체에 문의하여 공사장생활폐기물 전문 수거업체에 연락하여 처리할 수 있습니다.', '· 리모델링, 인테리어 공사 등 일련의 공사 또는 작업 등으로 전체 기간 동안 발생하는 5톤 미만의 폐기물은 공사장생활폐기물에 해당되며, 올바른 배출방법은 해당 지자체에 문의', '2026-05-18', 0, '["일반폐기물", "불연성종량제폐기물", "공사장 생활폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('reusable_cup', '재사용 컵 (유리·머그·스테인리스)', 'reusable', '재사용 가능한 식기류는 분리배출 대상이 아닙니다.', '["세척 후 본인이 다시 사용", "버릴 때만 폐기 절차 (깨진 유리/도자기는 불연성 종량제봉투)"]', 'high', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL);
