INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('cosmetic_container', '화장품 용기', 'plastic', '비우고 헹궈서 플라스틱류. 작은 것은 일반쓰레기 가능', '["내용물 비우기", "헹구기", "라벨 제거", "플라스틱류 또는 일반쓰레기"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('small_metal_utensil', '수저/젓가락/포크 (금속)', 'can', '스테인리스/금속은 캔류와 함께. 작은 것은 일반쓰레기 가능', '["금속이면 캔류 배출함", "플라스틱이면 일반쓰레기"]', 'medium', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
