INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('reusable_kitchenware', '재사용 주방기구 (압력솥·냄비 등)', 'reusable', '고장 X 깨끗 = 계속 사용. 버릴 때만 폐기 절차.', '["세척 후 본인이 다시 사용", "고장난 경우 금속이면 캔류, 도자기면 일반쓰레기"]', 'high', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL);
