INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('bag_backpack', '가방/배낭/지갑', 'clothes', '재사용 가능하면 의류수거함, 훼손시 일반쓰레기', '["재사용 가능 → 의류수거함", "훼손 심함 → 일반쓰레기"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('택배_상자', '택배 상자', 'paper', '· 택배상자에 부착된 송장은 제거한 후 배출 · 상자에 부착된 테이프는 제거한 후 배출', '["택배 상자는 일반 종이와 구분하여 종이류수거함으로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=19', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 종이의 종류로는 골판지, 백판지, 백상지, 종이팩이 있습니다. · 종이를 배출할 때에는 골판지와 골판지 외 종이류(백판지, 백상지 등)으로 구분하여 배출합니다. · 골판지 상자는 별도의 분리배출함(또는 마대)에 배출하거나 끈 등으로 묶어서 배출합니다. · 상자 내 내용물을 보호하기 위하여 비닐, 알루미늄 박 등이 코팅된 경우도 있으나 배출할 때에는 최대한 제거한 후 접어서 배출합니다. ·...', '· 택배상자에 부착된 송장은 제거한 후 배출 · 상자에 부착된 테이프는 제거한 후 배출', NULL, 1, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('음수대용_종이컵', '음수대용 종이컵', 'paper', '· 음수대용 종이컵은 봉투형, 고깔형, 원기둥형 등이 있습니다. · 음수대용(정수기) 종이컵은 종류와 상관없이 압착하여 봉투에 넣거나 한데 묶어서 종이류 수거함으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수', '["음수대용 종이컵은 종이류수거함으로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=41', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음수대용 종이컵은 봉투형, 고깔형, 원기둥형 등이 있습니다. · 음수대용(정수기) 종이컵은 종류와 상관없이 압착하여 봉투에 넣거나 한데 묶어서 종이류 수거함으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다....', '', NULL, 1, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('책꽂이', '책꽂이', 'can', '· 재질에 맞게 배출', '["책꽂이는 재질에 맞게 고철수거함, 플라스틱 수거함 등으로 배출합니다", "목재제품이거나 복합재질인 경우에는 종량제봉투로 배출합니다", "크기가 커 수거함으로 배출하기 어려운 경우에는 대형폐기물로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=49', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 책상위에 책, 물건 등을 구분하기 위해 사용하는 책꽂이는 금속, 목재, 플라스틱 등 다양한 재질로 제작하고 있습니다. · 책꽂이를 배출하실 때에는 재질에 맞게 배출하며, 금속은 고철 수거함에 배출하고, 플라스틱은 재활용품으로, 목재는 일반쓰레기로 배출합니다. · 크기가 큰 경우에는 대형폐기물로 배출합니다.', '· 재질에 맞게 배출', NULL, 1, '["재활용폐기물", "금속류", "고철", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('세탁소_옷걸이', '세탁소 옷걸이', 'can', '· 세탁소에서 사용하는 철제 옷걸이는 대부분 금속으로 되어있으나 의류를 보호하기 위하여 곁면에 플라스틱을 감아 제작하고 있습니다. · 철제 옷걸이는 금속 단일재질은 아니나 겉면의 플라스틱을 녹이는 공정을 거쳐 재활용', '["세탁소 옷걸이는 고철수거함으로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=61', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 세탁소에서 사용하는 철제 옷걸이는 대부분 금속으로 되어있으나 의류를 보호하기 위하여 곁면에 플라스틱을 감아 제작하고 있습니다. · 철제 옷걸이는 금속 단일재질은 아니나 겉면의 플라스틱을 녹이는 공정을 거쳐 재활용이 가능하므로 고철로 배출하여 주시면 됩니다. · 사용하지 않는 옷걸이는 가까운 세탁소에서 반납하는 경우도 있습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치...', '', NULL, 1, '["재활용폐기물", "금속류", "고철"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('캔커피', '캔커피', 'can', '· 내용물을 비우고 물로 헹군 후 배출', '["캔커피는 금속캔 수거함으로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=86', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 캔커피는 몸체, 뚜껑이 금속(알루미늄) 재질로 금속캔으로 배출합니다. · 금속제품은 재활용 선별장에서 철캔, 알루미늄 캔, 생활철, 스테인리스 등으로 선별하여 제철소로 운반되며 이후 용융 과정을 거쳐 철판, 알루미늄 판 등으로 재활용하고 있습니다.', '· 내용물을 비우고 물로 헹군 후 배출', NULL, 1, '["재활용폐기물", "금속류", "금속캔"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('캔시머_용기', '캔시머 용기', 'plastic', '·캔시머 용기는 페트(PET) 몸체에 알루미늄 재질 마개가 결합되어 있습니다. ·캔시머 용기는 대부분 몸체와 마개를 분리하기 어렵고 대부분 페트로 제작되어 있어 플라스틱 수거함으로 배출합니다. ※ 배출방법은 지역별로', '["캔시머 용기는 플라스틱 수거함으로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=112', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·캔시머 용기는 페트(PET) 몸체에 알루미늄 재질 마개가 결합되어 있습니다. ·캔시머 용기는 대부분 몸체와 마개를 분리하기 어렵고 대부분 페트로 제작되어 있어 플라스틱 수거함으로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장...', '', NULL, 1, '["재활용폐기물", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('음료_페트병', '음료 페트병', 'plastic', '· 내용물을 비우고 물로 헹군 후 배출 · 용기 뒷면 분리배출 표시 확인 후 배출(플라스틱표시인 경우에는 플라스틱 수거함으로 배출)', '["음료 페트병은 무색페트병수거함으로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=123', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·음료 페트병은 대부분 무색페트 재질로 내용물을 깨끗이 비우고 부착상표(라벨) 등을 제거한 후 무색페트병수거함으로 배출합니다. ·용기에서 제거한 라벨은 비닐류수거함으로 배출합니다. ·별도 분리배출된 음료, 생수 투명페트병은 품질 좋은 재생원료로 재활용되어, 옷이나 신발, 새로운 페트병(식품용기) 등의 원료가 됩니다. ·유색페트병 또는 여러 재질이 혼합된 플라스틱 제품은 투명 페트병과 혼합 배...', '· 내용물을 비우고 물로 헹군 후 배출 · 용기 뒷면 분리배출 표시 확인 후 배출(플라스틱표시인 경우에는 플라스틱 수거함으로 배출)', NULL, 1, '["재활용폐기물", "무색페트병"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('전신거울', '전신거울', 'furniture', '· 유리, 거울이 부착된 가구류는 가능한 분리하지 않고 제품 그대로 배출', '["전신거울은 대형폐기물로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=195', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 거울과 같은 유리제품은 재활용이 어렵습니다. · 제품의 상태가 좋아 다른 사람이 사용할 수 있는 폐가구는 재활용센터에 판매할 수 있으며, 업체에 따라 무상으로 수거하는 경우도 있습니다. · 폐가구를 배출하시기 전 가까운 재활용센터에 문의하여 주시기 바랍니다.', '· 유리, 거울이 부착된 가구류는 가능한 분리하지 않고 제품 그대로 배출', NULL, 1, '["대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('칫솔살균기', '칫솔살균기', 'general', '· 칫솔살균기 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전', '["칫솔살균기는 소형전기전자제품 전용수거함으로 배출합니다", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=286', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 칫솔살균기 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출방법은 지역별로 차이가 있을 수 있...', '', NULL, 1, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('전동칫솔', '전동칫솔', 'general', '· 전동칫솔 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용', '["전동칫솔은 가까운 소형전기전자제품 전용수거함으로 배출합니다", "인근에 전용수거함이 없는 경우에는 지자체에 문의한 후 배출하여 주시기 바랍니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=301', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 전동칫솔 등 일부 소형가전제품은 환경성보장제도 대상품목에 해당되지 않습니다. · 환경성보장제도에 포함되지 않은 전기전자제품이어도 무상방문수거서비스를 이용할 때 함께 배출할 수 있으며, 가까운 소형전기전자제품 전용수거함으로 배출할 수도 있습니다. · 또한, 지자체에 따라 소형가전제품을 수거하는 경우도 있으니 확인하신 후 배출하시는 것이 좋습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으...', '', NULL, 1, '["재활용폐기물", "전기전자 제품류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('티백', '티백', 'general', '· 음식물류폐기물로 배출 불가능', '["티백은 종량제봉투로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=419', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 티백은 차, 커피 등 고유 성분이 물에 우러나올 수 있도록 미세한 다공질 포장재로 소포장한 것으로, 티백의 재질은 종이, PP, PET, PLA 등이 사용되고 있습니다. · 티백은 재활용이 어려우므로 일반쓰레기로 배출합니다.', '· 음식물류폐기물로 배출 불가능', NULL, 1, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('캔버스', '캔버스', 'furniture', '· 캔버스는 면, 아사 등의 천을 나무틀에 박아서 그림을 그릴수 있도록 한 제품으로 복합재질 재활용이 어려우므로 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는', '["캔버스는 종량제봉투로 배출합니다", "크기가 커 종량제봉투로 배출하기 어려운 경우에는 대형폐기물로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=433', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 캔버스는 면, 아사 등의 천을 나무틀에 박아서 그림을 그릴수 있도록 한 제품으로 복합재질 재활용이 어려우므로 일반쓰레기로 배출합니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위...', '', NULL, 1, '["일반폐기물", "일반종량제폐기물", "대형폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('종이', '종이', 'paper', '·양면이 코팅되어 찢어지지 않는 경우 일반종량제폐기물로 배출', '["종이는 골판지, 기타 종이로 구분하여 배출합니다", "물에 젖거나 이물질이 묻지 않도록 하고 끈으로 묶거나 마대 등에 담아 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=528', '분리배출.kr (한국폐기물협회·환경부)', 'A', '·종이의 종류로는 골판지와 기타 종이류 (신문지,백판지,책자,백상지,종이컵)이 있습니다. ·골판지는 테이프, 송장, 철핀, 알루미늄박을 제거하고 접어서 배출합니다. 테이프를 제거하기 곤란한 경우에는 칼이나 가위로 잘라서 배출합니다. ·기타 종이류는 비닐, 플라스틱, 코팅된 전단지, 노트·달력 스프링 등 제거하여 배출합니다. ·종이컵은 압착하여 봉투에 넣거나 묶어서 기타종이로 배출합니다. ·1...', '·양면이 코팅되어 찢어지지 않는 경우 일반종량제폐기물로 배출', NULL, 1, '["재활용폐기물", "종이"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('서랍_책꽂이', '서랍 책꽂이', 'can', '· 재질에 맞게 배출', '["서랍 책꽂이는 재질에 맞게 고철 수거함, 플라스틱 수거함 등으로 배출합니다", "목재제품이거나 복합재질인 경우에는 종량제봉투로 배출합니다", "크기가 커 수거함으로 배출하기 어려운 경우에는 대형폐기물로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=570', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 책, 물건 등을 구분하기 위해 사용하는 서랍 책꽂이는 금속, 목재, 플라스틱 등 다양한 재질로 제작하고 있습니다. · 서랍 책꽂이를 배출하실 때에는 재질에 맞게 배출하며, 금속은 고철 수거함에 배출하고, 플라스틱은 재활용품으로, 목재는 일반쓰레기로 배출합니다. · 크기가 큰 경우에는 대형폐기물로 배출합니다.', '· 재질에 맞게 배출', NULL, 1, '["재활용폐기물", "금속류", "고철", "합성수지 용기류"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('생선', '생선', 'food', '· 해당 지자체의 배출방법에 따라 배출', '["생선은 음식물류폐기물로 배출합니다", "음식물 전용 종량제봉투 또는 납부필증(스티커, 칩)을 부착하여 전용용기에 담아 배출하거나 RFID에 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=648', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 음식물류폐기물은 재활용과정을 거쳐 동물의 사료, 퇴비(비료), 바이오가스로 재활용하고 있습니다. 이 중 사료화는 동물이 직접 섭취하기 때문에 세밀한 기준이 요구되므로 음식물류폐기물의 배출기준은 사료화에 준하여 안내하고 있습니다. · 고등어, 우럭, 갈치 등과 같은 생선은 음식물류폐기물로 배출합니다.', '· 해당 지자체의 배출방법에 따라 배출', NULL, 1, '["음식물류폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('치간칫솔', '치간칫솔', 'general', '· 치간칫솔은 플라스틱, 솔, 금속 등이 혼합된 복합재질로, 재질별 분리가 어려워 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에', '["치간칫솔은 종량제봉투로 배출합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=724', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 치간칫솔은 플라스틱, 솔, 금속 등이 혼합된 복합재질로, 재질별 분리가 어려워 재활용이 어렵습니다. ※ 배출방법은 지역별로 차이가 있을 수 있으니, 해당 지방자치단체에서 정하는 방법이 있는 경우에는 해당 방법에 따라 배출하시기 바랍니다. 가까운 분리배출 장소를 확인해보세요. 현재 위치에 가까운 배출장소가 없습니다. 근처의 다른 지역을 검색해보세요. 현 위치 배출장소 전체보기 현 지도에서...', '', NULL, 1, '["일반폐기물", "일반종량제폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('책상유리', '책상유리', 'furniture', '· 유리 제품은 배출, 운반과정에서 깨질 우려가 있으므로 가능한 주의하여 배출 · 깨진 유리는 날카로워 외부로 누출될 시 사람이 다칠 우려가 있으므로 베이지 않도록 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출', '["책상유리는 불연성종량제봉투(마대)로 배출합니다", "크기가 크거나 무게가 무거운 제품은 대형폐기물로 배출합니다", "다량으로 배출할 때에는 지자체에 문의하여 공사장생활폐기물 전문 처리업체에 위탁하여 처리합니다"]', 'high', 'https://www.xn--oy2b29bd3a601b.kr/front/dischargeMethod/dictionaryView.do?niIdx=756', '분리배출.kr (한국폐기물협회·환경부)', 'A', '· 책상유리와 같은 유리제품은 재활용이 어렵습니다. · 재활용이 어렵고 불에 타지 않는 불연성폐기물은 수거 후 매립장으로 운반되어 매립하고 있습니다. · 인테리어 공사 등에서 발생한 폐기물은 공사장생활폐기물에 해당되며, 폐기물 특성에 따라 종량제봉투, 불연성 마대, 재활용품 또는 대형폐기물로 배출하여야 합니다. 공사장생활폐기물을 다량으로 배출할 시 지자체에 문의하여 공사장생활폐기물 전문 수거...', '· 유리 제품은 배출, 운반과정에서 깨질 우려가 있으므로 가능한 주의하여 배출 · 깨진 유리는 날카로워 외부로 누출될 시 사람이 다칠 우려가 있으므로 베이지 않도록 신문지, 테이프 등을 활용하여 충분히 감싼 후 배출 · 리모델링, 인테리어 공사 등 일련의 공사 또는 작...', NULL, 1, '["일반폐기물", "불연성종량제폐기물", "대형폐기물", "공사장 생활폐기물"]');
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('packaging_general', '포장재 (일반)', 'plastic', '재질 확인 후 분리. 플라스틱·비닐·종이·스티로폼 각각 해당 분리수거함에 배출.', '["재질 확인 (플라스틱/비닐/종이/스티로폼)", "각 분리수거함에 배출", "복합재질은 분리 어려우면 종량제봉투"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('packaging_styrofoam', '포장재 스티로폼', 'styrofoam', '흰색 깨끗 → 스티로폼류, 색상/오염 → 종량제봉투', '["테이프·운송장 완전 제거", "내용물·이물질 제거", "흰색만 분리배출", "색상/오염은 종량제봉투"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('aluminum_can', '알루미늄캔', 'can', '내용물 비우고 헹궈서 캔·금속류로 배출. 음료수캔·맥주캔 모두 포함.', '["내용물 비우기", "물로 헹구기", "압착하여 부피 줄이기", "캔/금속류 수거함에 배출"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('old_clothes', '헌 옷/의류', 'clothes', '재사용 가능 → 의류수거함, 오염·훼손 심함 → 종량제봉투', '["깨끗하게 세탁·건조", "의류수거함에 배출", "오염·훼손 심함 → 종량제봉투"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('disposable_paper_cup', '종이컵 (일회용)', 'general', '음료 묻은 종이컵은 종량제봉투. 깨끗하면 종이류 가능 (지역별 차이).', '["내용물 비우기", "오염된 종이컵 → 종량제봉투", "깨끗한 종이컵 → 종이류 (선택, 지역 확인)"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 1, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('dumbbell', '덤벨/아령', 'general', '소형 덤벨(2kg 미만)은 종량제봉투. 대형은 대형폐기물 신고.', '["소형(2kg 미만) → 종량제봉투", "대형 → 거주 지자체 대형폐기물 신고"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 1, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('vase', '꽃병/화병', 'general', '유리 꽃병은 깨지지 않은 채 유리병 수거함. 도자기는 일반쓰레기.', '["유리 → 유리병 수거함", "도자기 → 종량제봉투", "깨졌으면 신문지로 감싸 종량제봉투"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 1, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('toothpick', '이쑤시개', 'general', '녹말(전분) 이쑤시개는 음식물쓰레기, 나무 이쑤시개는 일반쓰레기', '["녹말(전분) 이쑤시개 → 음식물쓰레기", "나무 이쑤시개 → 종량제봉투"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('led_bulb', 'LED 전구', 'general', 'LED 전구는 형광등과 달리 수은이 없어 일반쓰레기. 깨지지 않게 종량제봉투에.', '["깨지지 않게 신문지로 감싸기", "종량제봉투에 배출", "(형광등은 별도 전용수거함)"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('face_mask', '마스크', 'general', '보건용·KF 마스크 모두 일반쓰레기. 사용한 마스크는 종량제봉투에.', '["끈 잘라서 분리", "종량제봉투에 담아 배출"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('thermometer', '체온계', 'hazardous', '수은 체온계는 유해폐기물 (전자식은 소형가전). 깨진 체온계는 동주민센터로.', '["수은 체온계 → 유해폐기물 또는 동주민센터", "전자 체온계 → 소형가전"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 1, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('diaper', '기저귀', 'general', '유아·성인용 기저귀 모두 일반쓰레기 (배설물 등 오염물 포함).', '["오염물 비우기 (가능한 경우)", "둘둘 말아서 종량제봉투에"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('gum', '껌', 'general', '씹은 껌은 일반쓰레기. 음식물쓰레기 아님 (재활용 불가).', '["껌은 종량제봉투에", "포장지(은박)는 비닐류 또는 종이류"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('takeout_cup', '테이크아웃 컵', 'general', 'PE코팅 종이컵·플라스틱 컵 모두 음료 묻으면 일반쓰레기. 깨끗하면 재질별 분리.', '["내용물 비우기", "오염 → 종량제봉투", "깨끗 종이컵 → 종이류 / 깨끗 플라스틱 → 플라스틱"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 1, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('treadmill', '런닝머신', 'furniture', '대형 운동기구는 대형폐기물 신고. 소형 (스텝퍼 등)은 종량제봉투.', '["거주 지자체 대형폐기물 신고", "수수료 납부 + 필증 부착", "지정 일자에 배출"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 1, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('ceramic_vase', '도자기 꽃병', 'general', '도자기는 재활용 불가 일반쓰레기. 깨지면 신문지에 감싸 종량제봉투.', '["깨지지 않게 신문지로 감싸기", "종량제봉투에 배출"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('glass_vase', '유리 꽃병', 'glass', '깨지지 않은 유리 꽃병은 유리병 수거함. 깨진 유리는 신문지에 싸서 종량제봉투.', '["깨끗이 헹구기", "유리병 수거함에 배출", "깨진 유리는 신문지로 감싸 종량제봉투"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('cotton_swab', '면봉', 'general', '면봉은 일반쓰레기. 사용한 것은 종량제봉투에.', '["종량제봉투에 배출"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('wet_tissue', '물티슈', 'general', '물티슈는 화학섬유 함유로 재활용 불가. 일반쓰레기.', '["종량제봉투에 배출", "(절대 변기에 버리지 말 것 — 막힘 원인)"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('tetra_pack', '테트라팩 (멸균팩)', 'paper_pack', '두유·주스 멸균팩. 내용물 비우고 헹궈서 종이팩 수거함.', '["내용물 비우기", "물로 헹구기", "펼쳐서 말리기", "종이팩 전용 수거함에 배출"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 0, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('pressure_cooker', '압력솥/압력밥솥', 'general', '버리려는 경우 종량제봉투. 깨끗·작동 → 본인이 계속 사용.', '["사용 가능 상태 → 본인이 계속 사용 (재사용 권장)", "버릴 때만 → 종량제봉투에 담아 배출", "대형이면 → 대형폐기물 신고"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 1, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('frying_pan', '프라이팬/후라이팬', 'general', '코팅 프라이팬은 코팅·금속·플라스틱 손잡이 복합재질로 재활용 불가. 종량제봉투 배출.', '["코팅 벗겨진·소형 → 종량제봉투", "큰 프라이팬 → 대형폐기물 신고", "스테인리스 단일 재질 → 캔/금속류 (재질 확실 시)"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 1, NULL);
INSERT OR REPLACE INTO items (id, name, category, note, steps, confidence, source_url, source_name, source_grade, feature, caution, last_verified, region_variation, official_classification) VALUES ('wok', '웍/중식 팬', 'general', '중식 웍·궁중팬. 종량제봉투 또는 대형폐기물 신고.', '["소형 → 종량제봉투", "대형 → 대형폐기물 신고"]', 'high', 'https://xn--oy2b29bd3a601b.kr/front/dischargeMethod/index.do', '분리배출.kr (한국폐기물협회·환경부)', 'A', NULL, NULL, NULL, 1, NULL);
