INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'instant_rice_bowl', 'general', '음식 묻은 즉석밥 용기는 일반쓰레기로 (오염 제거가 어려운 경우 종량제봉투에)', '["내용물 깨끗이 제거", "오염이 심하면 종량제봉투", "오염 없으면 헹궈서 플라스틱류"]', 'medium', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'broken_glass_bottle', 'general', '고양시는 깨진 유리·사기를 ''불연성 마대''에 담아 배출 (종량제봉투 X)', '["신문지로 감싸기", "''유리주의'' 표시", "불연성 마대(흰색이 아닌 청회색 마대)에 담아 배출"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'broken_ceramic', 'general', '고양시 — 깨진 도자기·사기그릇은 불연성 폐기물. 불연성 마대 사용', '["안전하게 포장(신문지 등)", "''사기/도자기 주의'' 표시", "불연성 마대에 담아 배출"]', 'high', 'https://ene.gys.or.kr/', 'B');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'ceramic_dish', 'general', '깨지지 않은 도자기/사기 그릇도 재활용 불가 — 고양시 불연성 마대 사용 권장', '["깨지지 않게 포장", "불연성 마대 또는 종량제봉투"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'mirror', 'general', '거울은 유리코팅이라 재활용 불가 — 고양시 불연성 마대', '["신문지로 감싸기", "''유리주의'' 표시", "불연성 마대 또는 종량제봉투"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'light_bulb', 'general', '백열/LED 전구는 수은 없어 일반쓰레기 (폐형광등과 다름). 깨지면 불연성 마대', '["깨지지 않게 포장", "종량제봉투에 배출", "깨졌으면 불연성 마대"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'milk_carton', 'paper', '고양시는 44개 동 행정복지센터에서 종이팩 1kg → 화장지 1롤 교환 사업 운영', '["내용물 비우기", "물로 헹구고 말리기", "납작하게 압착", "동주민센터 교환 또는 종이팩 전용함"]', 'high', 'https://www.kyeongin.com/article/1710566', 'B');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'juice_carton', 'paper', '멸균팩도 동 행정복지센터 종이팩 교환사업 대상 (일반 우유팩과 함께 가능)', '["내용물 비우기", "물로 헹구고 말리기", "납작하게 압착", "동주민센터 교환 또는 종이팩 전용함"]', 'high', 'http://www.vop.co.kr/A00000740247.html', 'B');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'paper_cup_coated', 'general', 'PE 코팅 일회용 종이컵·종이용기는 종량제봉투. 오염 없는 멸균팩(우유팩)은 동주민센터 교환사업으로', '["내용물 비우기", "PE 코팅이면 종량제봉투", "멸균팩(우유팩 형태)이면 헹궈 말려 종이팩 교환"]', 'medium', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'food_waste', 'food', '고양시는 RFID 종량기 또는 음식물 전용봉투 사용. 공동주택(60세대 이상)은 대부분 RFID', '["물기 꼭 짜기", "이물질(비닐·뼈·껍데기) 분리", "RFID 종량기 카드 인식 → 투입 → 닫힘 버튼", "또는 전용봉투에 담아 지정 수거함"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab3.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'fruit_peel', 'food', '사과·귤·바나나·딸기 꼭지 등은 음식물. 단단한 과일씨(복숭아·아보카도)는 일반쓰레기', '["물기 제거", "음식물 전용봉투/RFID 종량기"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab3.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'vegetable_scraps', 'general', '양파·마늘 껍질 외피, 옥수수대·옥수수 껍질, 대파 뿌리는 일반쓰레기. 부드러운 채소 자투리만 음식물', '["부드러운 자투리: 음식물", "단단한 껍질·줄기·뿌리: 종량제봉투"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab3.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'meat_bone', 'general', '소·돼지·닭 뼈, 비계, 내장은 모두 일반쓰레기', '["물기 제거 후 종량제봉투에 배출"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab3.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'fish_bone', 'general', '조개껍데기·게·새우 껍데기, 큰 생선뼈는 일반쓰레기 (분쇄 불가)', '["종량제봉투에 배출"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab3.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'tea_bag', 'general', '티백·한약재 찌꺼기·커피 찌꺼기는 일반쓰레기 (봉투째 종량제봉투)', '["종량제봉투에 배출"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab3.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'electronics', 'general', '고양시 — 폐가전 무상 방문수거 운영. 1599-0903 또는 15990903.or.kr', '["1599-0903 또는 15990903.or.kr에서 예약", "대형(냉장고·세탁기·TV·에어컨)은 1개부터 가능", "소형(청소기·선풍기·전기밥솥 등)은 5개 이상 모아서 신청", "예약일에 문 앞 배출"]', 'high', 'https://15990903.or.kr/', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'furniture', 'general', '고양시 대형폐기물 인터넷 신고센터에서 결제·필증 출력 후 부착하여 배출', '["clean.gys.or.kr 접속", "품목 선택 → 수수료 결제", "필증 출력(또는 신고번호 종이에 기재)", "지정 장소에 배출"]', 'high', 'https://clean.gys.or.kr/clean/waste_list', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'battery', 'battery', '동 행정복지센터·아파트 전용 수거함에 배출. 고양시 44개 동주민센터에서 폐건전지 수거', '["물기 제거, 분해 금지", "동주민센터/아파트 폐건전지 수거함"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'lithium_battery', 'battery', '보조배터리·노트북 배터리 — 부풀음 시 화재 위험. 비닐랩으로 감싸 동주민센터 환경녹지과로 직접 전달', '["부풀어 오른 경우 비닐랩으로 감싸기", "동주민센터 또는 일산동구청 환경녹지과(031-8075-6243)에 직접 전달"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'lamp', 'lamp', '수은 함유 폐형광등 — 동 행정복지센터·아파트 전용 수거함에 배출 (깨지지 않게 운반)', '["포장재 제거", "직관/환형/콤팩트 구분", "깨지지 않게 운반", "동주민센터/아파트 폐형광등 수거함"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'styrofoam_box', 'styrofoam', '고양시 — 흰색·깨끗한 스티로폼만 분리배출. 색상/오염/이물질 묻은 것은 종량제봉투', '["테이프·송장·라벨 완전 제거", "내용물 비우고 세척", "흰색 + 오염 없음 → 스티로폼류", "색깔 있거나 오염 → 종량제봉투"]', 'high', 'https://ene.gys.or.kr/', 'B');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'styrofoam_colored', 'general', '색깔 있는 스티로폼·컵라면 용기·오염 스티로폼은 종량제봉투', '["종량제봉투에 배출"]', 'high', 'https://ene.gys.or.kr/', 'B');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'cosmetics_bottle', 'glass', '화장품 유리병 — 펌프 분리 후 유리병류로. 펌프(스프링+플라스틱)는 일반쓰레기', '["내용물 비우기", "펌프·뚜껑 분리", "유리병류로 배출", "펌프는 종량제봉투"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'cosmetic_pump', 'general', '스프링(금속)+플라스틱 복합재질 — 일반쓰레기', '["종량제봉투에 배출"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'rubber_glove', 'general', '고양시 — 환경부 표준대로 고무장갑은 일반쓰레기 (강남구처럼 비닐 분류 X)', '["종량제봉투에 배출"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'hanger', 'general', '철제 옷걸이는 분리하여 캔/금속류, 플라스틱 옷걸이는 일반쓰레기', '["재질 확인", "철제: 금속류로 배출", "플라스틱: 종량제봉투"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'clothes', 'clothes', '재사용 가능한 의류·신발·가방은 의류수거함. 오염·훼손 심한 것은 종량제봉투', '["세탁·건조", "의류수거함 배출", "오염 심함 → 종량제봉투"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'paper_box', 'paper', '테이프·송장·철핀 반드시 제거. 비에 젖지 않게 보관 후 배출', '["테이프·송장·철핀 제거", "납작하게 펴기", "끈으로 묶어서 배출"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'vinyl_bag', 'vinyl', '검정 비닐 포함 — 내용물 비우고 이물질 제거 후 비닐류로 배출', '["내용물 비우기", "이물질·음식물 제거", "비닐류로 배출 (오염 심하면 종량제봉투)"]', 'high', 'https://www.goyang.go.kr/www/www03/www03_3/www03_3_3/www03_3_3_tab1.jsp', 'A');
INSERT OR REPLACE INTO region_exceptions (region_code, item_id, category, note, steps, confidence, source_url, source_grade) VALUES ('41285', 'medicine', 'general', '폐의약품은 약국·보건소 폐의약품 수거함에 배출 (변기·하수구·종량제봉투 절대 금지)', '["포장재(종이박스·설명서) 제거", "알약은 통째로, 시럽은 한 병에 모아", "관내 약국 또는 일산동구 보건소 수거함"]', 'high', 'https://www.goyang.go.kr/health/index.do', 'A');
